export const DEFAULT_GRAMMAR_TOPICS: GrammarTopic[] = [{"id":"akkusativ","level":"A1","category":"Cazuri","title_de":"Akkusativ","title_ro":"Cazul Acuzativ","summary":"Akkusativul indica obiectul direct (pe cine? ce?). Numai articolul masculin se schimba: der -> den.","theory":"\n<h3>Cand folosim Akkusativ?</h3>\n<p>Pentru <strong>obiectul direct</strong> al verbului -- cine sau ce primeste actiunea direct.</p>\n<p>Intrebari de control: <strong>Wen?</strong> (pe cine?) sau <strong>Was?</strong> (ce?)</p>\n<p class=\"gram-example\">Ich sehe <strong>den Mann</strong>. (Il vad pe barbat.)<br>\nVerbul \"sehen\" + cine? -> den Mann (Akkusativ).</p>\n\n<h3>Articolele la Akkusativ</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Gen</th><th>Nominativ</th><th>Akkusativ</th><th>Schimbare?</th></tr></thead>\n  <tbody>\n    <tr><td>masculin</td><td>der / ein / kein / mein</td><td><strong>den / einen / keinen / meinen</strong></td><td><strong>DA - adauga -en</strong></td></tr>\n    <tr><td>feminin</td><td>die / eine / keine / meine</td><td>die / eine / keine / meine</td><td>NU</td></tr>\n    <tr><td>neutru</td><td>das / ein / kein / mein</td><td>das / ein / kein / mein</td><td>NU</td></tr>\n    <tr><td>plural</td><td>die / -- / keine / meine</td><td>die / -- / keine / meine</td><td>NU</td></tr>\n  </tbody>\n</table>\n\n<h3>Vesti bune!</h3>\n<p>Numai <strong>masculinul</strong> se schimba. Femininul, neutrul si pluralul raman la fel ca la Nominativ.</p>\n\n<h3>Exemple pe genuri</h3>\n<ul>\n  <li><strong>m.:</strong> der Tisch -> Ich kaufe <strong>den</strong> Tisch. (Cumpar masa.)</li>\n  <li><strong>f.:</strong> die Lampe -> Ich kaufe <strong>die</strong> Lampe. (Cumpar lampa - fara schimbare!)</li>\n  <li><strong>n.:</strong> das Buch -> Ich kaufe <strong>das</strong> Buch. (Cumpar cartea - fara schimbare!)</li>\n  <li><strong>pl.:</strong> die Bücher -> Ich kaufe <strong>die</strong> Bücher. (Cumpar cartile.)</li>\n</ul>\n\n<h3>Verbe care cer Akkusativ (cele mai uzuale)</h3>\n<p>haben, kaufen, sehen, lesen, essen, trinken, brauchen, suchen, mögen, lieben, finden, fragen, besuchen, treffen, machen, schreiben.</p>\n\n<div class=\"gram-tip\">\n<strong>Truc de memorare:</strong> \"Akkusativ = den\". Daca trebuie sa zic \"Cumpar UN ____\", la masculin spun \"einen Tisch\", pentru altele \"eine Lampe / ein Buch\". Doar masculinul are 'n' in plus.\n</div>\n","exercises":[{"type":"fill","prompt":"Ich kaufe ___ Tisch. (un)","answer":"einen","hint":"der Tisch e masculin -> Akkusativ","explanation":"Tisch = masculin. La Akk masculin: ein -> einen."},{"type":"fill","prompt":"Ich sehe ___ Lampe. (lampa - articol definit)","answer":"die","hint":"Lampe = feminin","explanation":"Lampa e feminin. Femininul nu se schimba: die -> die."},{"type":"choice","prompt":"Wir essen ___ Apfel.","options":["der","den","die","das"],"answer":"den","explanation":"der Apfel = masculin. La Akk: der -> den."},{"type":"choice","prompt":"Sie hat ___ Bruder.","options":["ein","einen","eine","kein"],"answer":"einen","explanation":"der Bruder = masculin. ein -> einen la Akk."},{"type":"fill","prompt":"Ich liebe ___ Mutter. (mama mea)","answer":"meine","hint":"Mutter = feminin","explanation":"die Mutter = feminin. La Akk feminin: meine -> meine (fara schimbare)."},{"type":"fill","prompt":"Hast du ___ Stift? (un)","answer":"einen","hint":"der Stift = masculin","explanation":"der Stift e masculin. ein -> einen."},{"id":"ak-100","type":"Lückentext","difficulty":"Mediu","question":"Ich kaufe ___ Tisch. (un, m.)","options":null,"correctAnswer":"einen","explanationRomanian":"der Tisch (m.) la Akk: ein -> einen."},{"id":"ak-101","type":"Lückentext","difficulty":"Usor","question":"Wir lesen ___ Buch. (cartea, n.)","options":null,"correctAnswer":"das","explanationRomanian":"das Buch (n.) la Akk: das -> das (neschimbat)."},{"id":"ak-102","type":"Lückentext","difficulty":"Usor","question":"Sie sucht ___ Frau. (femeia, f.)","options":null,"correctAnswer":"die","explanationRomanian":"die Frau (f.) la Akk: die -> die (neschimbat)."},{"id":"ak-103","type":"Lückentext","difficulty":"Usor","question":"Er hat ___ Auto. (un, n.)","options":null,"correctAnswer":"ein","explanationRomanian":"das Auto (n.) la Akk: ein -> ein (neschimbat)."},{"id":"ak-104","type":"Lückentext","difficulty":"Mediu","question":"Ich brauche ___ Stift. (niciun, m.)","options":null,"correctAnswer":"keinen","explanationRomanian":"der Stift (m.) la Akk: kein -> keinen."},{"id":"ak-105","type":"Lückentext","difficulty":"Mediu","question":"Wir besuchen ___ Eltern. (parintii nostri, pl.)","options":null,"correctAnswer":"unsere","explanationRomanian":"die Eltern (pl.) la Akk: unsere -> unsere (neschimbat)."},{"id":"ak-106","type":"Lückentext","difficulty":"Mediu","question":"Maria kennt ___ Lehrer. (profesorul, m.)","options":null,"correctAnswer":"den","explanationRomanian":"der Lehrer (m.) la Akk: der -> den (singura schimbare!)."},{"id":"ak-107","type":"Lückentext","difficulty":"Usor","question":"Hast du ___ Bruder? (un, m.)","options":null,"correctAnswer":"einen","explanationRomanian":"der Bruder (m.) la Akk: ein -> einen."},{"id":"ak-108","type":"Multiple Choice","difficulty":"Greu","question":"Ich sehe ___ Hund. (cainele)","options":["der","den","die","das"],"correctAnswer":"den","explanationRomanian":"der Hund (m.). La Akk masculin: der -> den. CAPCANA: e usor sa lasi 'der'."},{"id":"ak-109","type":"Multiple Choice","difficulty":"Mediu","question":"Sie kauft ___ Lampe. (o lampa)","options":["ein","eine","einen","einem"],"correctAnswer":"eine","explanationRomanian":"die Lampe (f.). La Akk feminin: eine -> eine (neschimbat). 'einem' = Dat."},{"id":"ak-110","type":"Multiple Choice","difficulty":"Mediu","question":"Wir essen ___ Apfel. (un mar)","options":["ein","eine","einen","einem"],"correctAnswer":"einen","explanationRomanian":"der Apfel (m.). La Akk: ein -> einen. CAPCANA comuna: forma 'einen' uitata."},{"id":"ak-111","type":"Multiple Choice","difficulty":"Mediu","question":"Hast du ___ Kind? (un copil)","options":["ein","eine","einen","kein"],"correctAnswer":"ein","explanationRomanian":"das Kind (n.). La Akk: ein -> ein (neschimbat la neutru)."},{"id":"ak-112","type":"Multiple Choice","difficulty":"Mediu","question":"Ich liebe ___ Mutter. (mama mea)","options":["mein","meinen","meine","meinem"],"correctAnswer":"meine","explanationRomanian":"die Mutter (f.). La Akk: meine -> meine (feminin neschimbat)."},{"id":"ak-113","type":"Multiple Choice","difficulty":"Usor","question":"Er trinkt ___ Wasser. (apa)","options":["der","den","die","das"],"correctAnswer":"das","explanationRomanian":"das Wasser (n.). La Akk: das -> das (neutru neschimbat)."},{"id":"ak-114","type":"Multiple Choice","difficulty":"Mediu","question":"Ich frage ___ Lehrer. (profesorul)","options":["der","den","dem","des"],"correctAnswer":"den","explanationRomanian":"der Lehrer (m.). 'fragen' + Akk. der -> den. 'dem' ar fi Dativ."},{"id":"ak-115","type":"Multiple Choice","difficulty":"Mediu","question":"Wir treffen ___ Freunde. (prietenii)","options":["der","die","den","des"],"correctAnswer":"die","explanationRomanian":"die Freunde (pl.). La Akk plural: die -> die. 'den + n' ar fi Dat. plural."},{"id":"ak-116","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Buch","lese","ein","Ich"],"correctAnswer":"Ich lese ein Buch","explanationRomanian":"S + V + Akk (ein Buch n.)."},{"id":"ak-117","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["einen","Sie","schoenen","hat","Hund"],"correctAnswer":"Sie hat einen schoenen Hund","explanationRomanian":"Adjectiv 'schoenen' (-en pentru m. Akk dupa 'einen'). Ordinea: einen + adj + Hund."},{"id":"ak-118","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["meinen","ich","liebe","Bruder"],"correctAnswer":"Ich liebe meinen Bruder","explanationRomanian":"der Bruder (m.) -> meinen Bruder la Akk. mein -> meinen."},{"id":"ak-119","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["der","Mann","trinkt","den","Kaffee"],"correctAnswer":"Der Mann trinkt den Kaffee","explanationRomanian":"Subiect der Mann (Nom.) + verb + Akk (den Kaffee)."},{"id":"ak-120","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Apfel","moechte","Ich","einen"],"correctAnswer":"Ich moechte einen Apfel","explanationRomanian":"der Apfel -> einen Apfel la Akk."},{"id":"ak-121","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Kinder","die","sehen","wir"],"correctAnswer":"Wir sehen die Kinder","explanationRomanian":"die Kinder (pl.) la Akk = die Kinder (neschimbat)."},{"id":"ak-122","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Ich kaufe der Tisch.\"","options":null,"correctAnswer":"Ich kaufe den Tisch","explanationRomanian":"der Tisch (m.) ca obiect direct -> Akk. der -> den."},{"id":"ak-123","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Sie hat ein Bruder.\"","options":null,"correctAnswer":"Sie hat einen Bruder","explanationRomanian":"der Bruder (m.) ca obiect direct -> Akk. ein -> einen."},{"id":"ak-124","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Wir lesen der Buch.\"","options":null,"correctAnswer":"Wir lesen das Buch","explanationRomanian":"das Buch (n.). La Akk neutru: das (nu der). 'der' e masculin Nom."},{"id":"ak-125","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Ich liebe meiner Mutter.\"","options":null,"correctAnswer":"Ich liebe meine Mutter","explanationRomanian":"die Mutter (f.) la Akk = meine Mutter (neschimbat). 'meiner' e Dat."},{"id":"ak-126","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Er sucht einem Stift.\"","options":null,"correctAnswer":"Er sucht einen Stift","explanationRomanian":"der Stift (m.) la Akk: einen. 'einem' este Dativ."},{"id":"ak-127","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Wir sehen den Frau.\"","options":null,"correctAnswer":"Wir sehen die Frau","explanationRomanian":"die Frau (f.) la Akk = die Frau. 'den' e masculin Akk."},{"id":"ak-128","type":"Umformung","difficulty":"Mediu","question":"Pune cu articol nedefinit:\n\"Ich kaufe den Tisch.\"","options":null,"correctAnswer":"Ich kaufe einen Tisch","explanationRomanian":"der/den -> ein/einen. La Akk masculin nedefinit: einen."},{"id":"ak-129","type":"Umformung","difficulty":"Mediu","question":"Schimba la plural:\n\"Ich sehe den Mann.\"","options":null,"correctAnswer":"Ich sehe die Maenner","explanationRomanian":"der Mann -> die Maenner (umlaut + er). La Akk plural: die."},{"id":"ak-130","type":"Umformung","difficulty":"Mediu","question":"Negativeaza cu 'kein':\n\"Sie hat einen Bruder.\"","options":null,"correctAnswer":"Sie hat keinen Bruder","explanationRomanian":"ein -> kein la negatie. La Akk masculin: keinen."},{"id":"ak-131","type":"Umformung","difficulty":"Mediu","question":"Inlocuieste obiectul cu pronume:\n\"Ich kaufe den Apfel.\"","options":null,"correctAnswer":"Ich kaufe ihn","explanationRomanian":"der Apfel (m.) -> ihn (pronume Akk masculin)."},{"id":"ak-132","type":"Umformung","difficulty":"Mediu","question":"Inlocuieste cu pronume:\n\"Wir sehen die Kinder.\"","options":null,"correctAnswer":"Wir sehen sie","explanationRomanian":"die Kinder (pl.) -> sie (pronume Akk plural, neschimbat fata de Nom.)."},{"id":"ak-133","type":"Umformung","difficulty":"Greu","question":"Pune verbul la prezent (er):\n\"Ich liebe meinen Bruder.\"","options":null,"correctAnswer":"Er liebt seinen Bruder","explanationRomanian":"Pers. 3: liebt. Posesivul se schimba: meinen -> seinen (sau ihren) la masculin Akk."}]},{"id":"dativ","level":"A1","category":"Cazuri","title_de":"Dativ","title_ro":"Cazul Dativ","summary":"Dativul = obiectul indirect (cui?). Toate genurile se schimba (der/das/die -> dem/dem/der).","theory":"\n<h3>Cand folosim Dativ?</h3>\n<p>Pentru <strong>obiectul indirect</strong> -- cine primeste sau cui i se face ceva.</p>\n<p>Intrebare de control: <strong>Wem?</strong> (cui?)</p>\n<p class=\"gram-example\">Ich gebe <strong>dem Mann</strong> ein Buch.<br>\n(eu) (dau) (barbatului) (o carte) -- Cui dau cartea? -> dem Mann (Dativ).</p>\n\n<h3>Articolele la Dativ -- TOATE se schimba</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Gen</th><th>Nominativ</th><th>Dativ</th></tr></thead>\n  <tbody>\n    <tr><td>masculin</td><td>der / ein / kein</td><td><strong>dem / einem / keinem</strong></td></tr>\n    <tr><td>feminin</td><td>die / eine / keine</td><td><strong>der / einer / keiner</strong></td></tr>\n    <tr><td>neutru</td><td>das / ein / kein</td><td><strong>dem / einem / keinem</strong></td></tr>\n    <tr><td>plural</td><td>die / -- / keine</td><td><strong>den + n / -- / keinen</strong></td></tr>\n  </tbody>\n</table>\n\n<h3>Atentie la pluralul Dativ</h3>\n<p>La plural Dativ, substantivul primeste un <strong>-n in plus</strong> (daca nu il are deja):</p>\n<ul>\n  <li>die Kinder (Nom.) -> <strong>den Kindern</strong> (Dativ pl.)</li>\n  <li>die Männer (Nom.) -> <strong>den Männern</strong></li>\n  <li>die Frauen (Nom.) -> <strong>den Frauen</strong> (deja are -n)</li>\n</ul>\n\n<h3>Cand apare Dativul</h3>\n<ol>\n  <li><strong>Verbe specifice:</strong> helfen, danken, gehören, gefallen, antworten, glauben, gratulieren, schmecken.<br>\n    \"Ich helfe <strong>dem Bruder</strong>.\" (Il ajut pe frate. Atentie: in germana e Dativ!)</li>\n  <li><strong>Verbe cu 2 obiecte (dare/oferire):</strong> geben, schenken, zeigen, bringen, schicken, schreiben, kaufen.<br>\n    Persoana = Dativ, lucrul = Akkusativ.<br>\n    \"Ich gebe <strong>dem Mann</strong> (Dat.) <strong>ein Buch</strong> (Akk.).\"</li>\n  <li><strong>Prepozitii cu Dativ:</strong> aus, bei, mit, nach, seit, von, zu (urmatorul topic).</li>\n</ol>\n\n<div class=\"gram-tip\">\n<strong>Trucul: \"in 5 minute\"</strong> -- la Dativ, articolul are intotdeauna un 'm' (masculin/neutru) sau 'r' (feminin) sau 'n' (plural). Asta e diferit de Akk care are 'n' doar la masculin.\n</div>\n","exercises":[{"type":"fill","prompt":"Ich helfe ___ Mutter. (mama)","answer":"der","hint":"Mutter = feminin, helfen + Dativ","explanation":"die Mutter (Nom.) -> der Mutter (Dativ). 'helfen' cere Dativ in germana, desi in romana zicem 'o ajut'."},{"type":"fill","prompt":"Wir geben ___ Kind ein Geschenk. (copilului)","answer":"dem","hint":"das Kind = neutru -> Dativ","explanation":"das Kind (Nom.) -> dem Kind (Dativ neutru)."},{"type":"choice","prompt":"Das Buch gehört ___ Lehrer.","options":["der","den","dem","des"],"answer":"dem","explanation":"der Lehrer = masculin. La Dativ: der -> dem. 'gehören' cere Dativ."},{"type":"choice","prompt":"Ich danke ___ Freunden.","options":["der","den","die","dem"],"answer":"den","explanation":"die Freunde = plural. La Dativ pl.: die -> den + substantivul ia 'n' (Freunden)."},{"type":"fill","prompt":"Sie schreibt ___ Vater einen Brief. (tatalui)","answer":"dem","hint":"Vater = masculin, schreiben + Dat. (cui)","explanation":"der Vater -> dem Vater. Schimbarea de la 'der' la 'dem' la Dativ masculin."},{"type":"fill","prompt":"Das gefällt ___ Frau. (femeii)","answer":"der","hint":"Frau = feminin -> Dativ","explanation":"die Frau (Nom.) -> der Frau (Dativ feminin). 'gefallen' cere Dativ."},{"id":"dt-200","type":"Lückentext","difficulty":"Mediu","question":"Ich helfe ___ Mutter. (mamei)","options":null,"correctAnswer":"der","explanationRomanian":"die Mutter (f.) la Dat: der. helfen + Dat."},{"id":"dt-201","type":"Lückentext","difficulty":"Mediu","question":"Wir geben ___ Kind ein Buch. (copilului)","options":null,"correctAnswer":"dem","explanationRomanian":"das Kind (n.) la Dat: dem."},{"id":"dt-202","type":"Lückentext","difficulty":"Mediu","question":"Das gehoert ___ Lehrer. (profesorului, m.)","options":null,"correctAnswer":"dem","explanationRomanian":"der Lehrer (m.) la Dat: der -> dem."},{"id":"dt-203","type":"Lückentext","difficulty":"Mediu","question":"Ich danke ___ Freunden. (prietenilor)","options":null,"correctAnswer":"den","explanationRomanian":"die Freunde (pl.) la Dat: die -> den + Freunden (cu n)."},{"id":"dt-204","type":"Lückentext","difficulty":"Greu","question":"Sie spricht mit ___ Bruder. (cu fratele)","options":null,"correctAnswer":"ihrem","explanationRomanian":"der Bruder (m.) la Dat: ihr -> ihrem."},{"id":"dt-205","type":"Lückentext","difficulty":"Mediu","question":"Er antwortet ___ Frau. (femeii)","options":null,"correctAnswer":"der","explanationRomanian":"die Frau (f.) la Dat: die -> der."},{"id":"dt-206","type":"Lückentext","difficulty":"Mediu","question":"Das Geschenk ist von ___ Vater. (de la tatal meu)","options":null,"correctAnswer":"meinem","explanationRomanian":"der Vater (m.) la Dat: mein -> meinem."},{"id":"dt-207","type":"Lückentext","difficulty":"Greu","question":"Sie wohnt bei ___ Tante. (la matusa)","options":null,"correctAnswer":"ihrer","explanationRomanian":"die Tante (f.) la Dat: ihre -> ihrer."},{"id":"dt-208","type":"Multiple Choice","difficulty":"Mediu","question":"Ich helfe ___ Vater.","options":["der","den","dem","des"],"correctAnswer":"dem","explanationRomanian":"der Vater (m.) la Dat: dem. 'helfen' cere Dativ in germana."},{"id":"dt-209","type":"Multiple Choice","difficulty":"Mediu","question":"Das gehoert ___ Mutter.","options":["der","die","dem","den"],"correctAnswer":"der","explanationRomanian":"die Mutter (f.) la Dat: der. CAPCANA: 'der' la Dat = articolul feminin (ca 'die' la Nom)."},{"id":"dt-210","type":"Multiple Choice","difficulty":"Greu","question":"Sie schreibt ___ Kindern einen Brief.","options":["den","die","der","dem"],"correctAnswer":"den","explanationRomanian":"die Kinder (pl.) la Dat: den (cu Kindern primind 'n' suplimentar)."},{"id":"dt-211","type":"Multiple Choice","difficulty":"Mediu","question":"Wir antworten ___ Lehrer.","options":["der","den","dem","des"],"correctAnswer":"dem","explanationRomanian":"der Lehrer (m.) la Dat: dem. 'antworten' + Dativ (cuiva)."},{"id":"dt-212","type":"Multiple Choice","difficulty":"Mediu","question":"Das gefaellt ___ Frau.","options":["die","der","den","dem"],"correctAnswer":"der","explanationRomanian":"die Frau (f.) la Dat: der. 'gefallen' cere Dativ."},{"id":"dt-213","type":"Multiple Choice","difficulty":"Usor","question":"Mit ___ Auto fahren wir.","options":["der","dem","den","des"],"correctAnswer":"dem","explanationRomanian":"das Auto (n.) la Dat: dem. 'mit' + Dativ."},{"id":"dt-214","type":"Multiple Choice","difficulty":"Mediu","question":"Ich gratuliere ___ Bruder zum Geburtstag.","options":["der","den","dem","des"],"correctAnswer":"dem","explanationRomanian":"der Bruder (m.) la Dat: dem. 'gratulieren' + Dat."},{"id":"dt-215","type":"Multiple Choice","difficulty":"Mediu","question":"Sie kommt aus ___ Schule.","options":["die","der","den","dem"],"correctAnswer":"der","explanationRomanian":"die Schule (f.) la Dat: der. 'aus' + Dativ."},{"id":"dt-216","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["meinem","Bruder","helfe","Ich"],"correctAnswer":"Ich helfe meinem Bruder","explanationRomanian":"helfen + Dat. der Bruder -> meinem Bruder."},{"id":"dt-217","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["dem","Geschenk","Kind","Wir","ein","geben"],"correctAnswer":"Wir geben dem Kind ein Geschenk","explanationRomanian":"geben + Dat. (cui) + Akk. (ce). dem Kind = Dat., ein Geschenk = Akk."},{"id":"dt-218","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["mit","spricht","Sie","ihrem","Vater"],"correctAnswer":"Sie spricht mit ihrem Vater","explanationRomanian":"'mit' + Dat. ihr -> ihrem (m. Dat.)."},{"id":"dt-219","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["antwortet","der","Er","Lehrerin"],"correctAnswer":"Er antwortet der Lehrerin","explanationRomanian":"antworten + Dat. die Lehrerin -> der Lehrerin (f. Dat.)."},{"id":"dt-220","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["bei","Tante","wohne","ich","der"],"correctAnswer":"Ich wohne bei der Tante","explanationRomanian":"'bei' + Dat. die Tante -> der Tante."},{"id":"dt-221","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza cuvintele:","options":["den","Kindern","ich","Geschichte","erzaehle","eine"],"correctAnswer":"Ich erzaehle den Kindern eine Geschichte","explanationRomanian":"erzaehlen + Dat. (cui) + Akk. (ce). den Kindern (pl. Dat.) + eine Geschichte (f. Akk.)."},{"id":"dt-222","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich helfe der Bruder.\"","options":null,"correctAnswer":"Ich helfe dem Bruder","explanationRomanian":"der Bruder (m.) la Dat: dem. helfen + Dativ."},{"id":"dt-223","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Das gehoert die Frau.\"","options":null,"correctAnswer":"Das gehoert der Frau","explanationRomanian":"die Frau (f.) la Dat: der. gehoeren + Dativ."},{"id":"dt-224","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Scrie corect:\n\"Sie spricht mit ihren Vater.\"","options":null,"correctAnswer":"Sie spricht mit ihrem Vater","explanationRomanian":"der Vater (m.) la Dat: ihrem. 'mit' + Dativ. 'ihren' ar fi Akk."},{"id":"dt-225","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Wir antworten der Mann.\"","options":null,"correctAnswer":"Wir antworten dem Mann","explanationRomanian":"der Mann (m.) la Dat: dem. antworten + Dativ."},{"id":"dt-226","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Scrie corect:\n\"Ich danke meinen Eltern fuer das Geschenk.\"","options":null,"correctAnswer":"Ich danke meinen Eltern fuer das Geschenk","explanationRomanian":"ATENTIE: aceasta propozitie este DEJA CORECTA! 'meinen Eltern' = Dat. plural cu '-n' suplimentar."},{"id":"dt-227","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Das Auto gehoert mein Vater.\"","options":null,"correctAnswer":"Das Auto gehoert meinem Vater","explanationRomanian":"der Vater (m.) la Dat: meinem. gehoeren + Dat."},{"id":"dt-228","type":"Umformung","difficulty":"Greu","question":"Schimba la plural:\n\"Ich helfe dem Kind.\"","options":null,"correctAnswer":"Ich helfe den Kindern","explanationRomanian":"das Kind -> die Kinder (pl.). La Dat plural: den + substantivul ia '-n' = den Kindern."},{"id":"dt-229","type":"Umformung","difficulty":"Mediu","question":"Adauga 'mein/meine':\n\"Ich danke der Lehrerin.\"","options":null,"correctAnswer":"Ich danke meiner Lehrerin","explanationRomanian":"die Lehrerin (f.) la Dat: der -> meiner."},{"id":"dt-230","type":"Umformung","difficulty":"Mediu","question":"Pune cu pronume personal:\n\"Ich helfe dem Mann.\"","options":null,"correctAnswer":"Ich helfe ihm","explanationRomanian":"dem Mann (m. Dat.) -> ihm (pronume Dativ masculin)."},{"id":"dt-231","type":"Umformung","difficulty":"Mediu","question":"Pune cu pronume:\n\"Sie schreibt der Frau.\"","options":null,"correctAnswer":"Sie schreibt ihr","explanationRomanian":"der Frau (f. Dat.) -> ihr (pronume Dativ feminin)."},{"id":"dt-232","type":"Umformung","difficulty":"Mediu","question":"Cu 'mit' (instrument):\n\"Ich schreibe mit ein Stift.\"","options":null,"correctAnswer":"Ich schreibe mit einem Stift","explanationRomanian":"'mit' + Dat. der Stift (m.) -> einem Stift."},{"id":"dt-233","type":"Umformung","difficulty":"Greu","question":"Pune la prezent (3 sg.):\n\"Ich helfe dir.\"","options":null,"correctAnswer":"Er hilft dir","explanationRomanian":"helfen e neregulat: ich helfe -> er hilft (umlaut). 'dir' (Dat.) ramane."}]},{"id":"personalpronomen","level":"A1","category":"Pronume","title_de":"Personalpronomen","title_ro":"Pronumele personal","summary":"Pronumele care inlocuiesc o persoana sau un lucru: ich, du, er/sie/es, wir, ihr, sie, Sie.","theory":"\n<h3>Cele 7 pronume personale</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Persoana</th><th>Singular</th><th>Plural</th></tr></thead>\n  <tbody>\n    <tr><td>1</td><td><strong>ich</strong> (eu)</td><td><strong>wir</strong> (noi)</td></tr>\n    <tr><td>2 (informal)</td><td><strong>du</strong> (tu)</td><td><strong>ihr</strong> (voi)</td></tr>\n    <tr><td>2 (formal)</td><td><strong>Sie</strong> (dvs.)</td><td><strong>Sie</strong> (dvs.)</td></tr>\n    <tr><td>3</td><td><strong>er</strong> / <strong>sie</strong> / <strong>es</strong></td><td><strong>sie</strong> (ei/ele)</td></tr>\n  </tbody>\n</table>\n\n<h3>Atentie la cele 4 forme \"sie/Sie\"</h3>\n<ul>\n  <li><strong>sie</strong> (cu litera mica) = <em>ea</em> (singular feminin) -- \"Sie ist meine Mutter.\"</li>\n  <li><strong>sie</strong> (cu litera mica) = <em>ei/ele</em> (plural) -- \"Sie sind meine Eltern.\"</li>\n  <li><strong>Sie</strong> (cu litera MARE) = <em>dvs.</em> (forma formala) -- \"Wie heissen Sie?\"</li>\n</ul>\n<p>Diferenta intre singular si plural se vede din verb: <em>sie ist</em> (ea este) vs <em>sie sind</em> (ei sunt).</p>\n\n<h3>Pronume pentru lucruri</h3>\n<p>In germana, lucrurile au gen (m./f./n.) si pronumele se acorda cu genul:</p>\n<ul>\n  <li><strong>der Tisch</strong> (masa, masculin) -> <strong>er</strong> (literal \"el\"). \"Wo ist der Tisch? -- Er ist hier.\"</li>\n  <li><strong>die Lampe</strong> (lampa, feminin) -> <strong>sie</strong>. \"Wo ist die Lampe? -- Sie ist hier.\"</li>\n  <li><strong>das Buch</strong> (cartea, neutru) -> <strong>es</strong>. \"Wo ist das Buch? -- Es ist hier.\"</li>\n</ul>\n\n<div class=\"gram-tip\">\n<strong>Sfat:</strong> Romana foloseste \"el/ea\" doar pentru oameni, dar in germana si lucrurile sunt \"er/sie/es\" in functie de gen. Asta se invata cu fiecare cuvant nou, nu exista regula sigura.\n</div>\n","exercises":[{"type":"fill","prompt":"Complete: Das ist Maria. ___ kommt aus Berlin.","answer":"Sie","hint":"Maria = ea, deci pronume feminin","explanation":"Maria este o femeie (singular feminin) -> sie."},{"type":"fill","prompt":"Complete: Wo sind Anna und Tom? ___ sind im Park.","answer":"Sie","hint":"doi oameni = plural","explanation":"Doua persoane impreuna = plural -> sie (cu litera mica)."},{"type":"choice","prompt":"Wie heissen ___, Herr Schmidt?","options":["du","Sie","ihr","er"],"answer":"Sie","explanation":"Adresare formala (cu Herr) -> Sie cu litera mare. 'Du' ar fi prea familiar."},{"type":"choice","prompt":"Das Auto ist neu. ___ ist rot.","options":["Er","Sie","Es","Ihr"],"answer":"Es","explanation":"das Auto este neutru -> pronumele este 'es'."},{"type":"choice","prompt":"Marie und ich gehen ins Kino. ___ haben Zeit.","options":["Sie","Wir","Ihr","Ich"],"answer":"Wir","explanation":"Marie + ich = noi (persoana 1 plural) -> wir."},{"type":"fill","prompt":"Complete: Die Lampe ist neu. ___ ist sehr schon.","answer":"Sie","hint":"die Lampe = feminin","explanation":"die Lampe e feminin -> pronumele este 'sie' (literal 'ea')."},{"id":"pp-100","type":"Lückentext","difficulty":"Usor","question":"Das ist Maria. ___ kommt aus Berlin.","options":null,"correctAnswer":"Sie","explanationRomanian":"Maria = ea (sg. f.) -> sie."},{"id":"pp-101","type":"Lückentext","difficulty":"Mediu","question":"Wo ist der Tisch? - ___ ist hier.","options":null,"correctAnswer":"Er","explanationRomanian":"der Tisch (m.) -> er ('el' pentru lucru masculin)."},{"id":"pp-102","type":"Lückentext","difficulty":"Mediu","question":"Wo ist das Buch? - ___ liegt da.","options":null,"correctAnswer":"Es","explanationRomanian":"das Buch (n.) -> es."},{"id":"pp-103","type":"Lückentext","difficulty":"Usor","question":"Wo sind die Kinder? - ___ spielen draussen.","options":null,"correctAnswer":"Sie","explanationRomanian":"die Kinder (pl.) -> sie (plural)."},{"id":"pp-104","type":"Lückentext","difficulty":"Usor","question":"Anna und ich gehen ins Kino. ___ haben Zeit.","options":null,"correctAnswer":"Wir","explanationRomanian":"Anna+ich = noi -> wir."},{"id":"pp-105","type":"Lückentext","difficulty":"Usor","question":"Wie heisst du? - ___ heisse Marius.","options":null,"correctAnswer":"Ich","explanationRomanian":"Eu insumi -> ich."},{"id":"pp-106","type":"Lückentext","difficulty":"Greu","question":"Hallo Tom und Lisa! Wie geht ___ ?","options":null,"correctAnswer":"es euch","explanationRomanian":"'wie geht es' + cui (Dativ pl.) -> euch (vouă)."},{"id":"pp-107","type":"Lückentext","difficulty":"Mediu","question":"Kennen Sie die Frau? - Ja, ich kenne ___ .","options":null,"correctAnswer":"sie","explanationRomanian":"die Frau (Akk.) -> sie (pronume Akk f. = neschimbat)."},{"id":"pp-108","type":"Multiple Choice","difficulty":"Usor","question":"Wie heissen ___, Herr Schmidt?","options":["du","Sie","ihr","er"],"correctAnswer":"Sie","explanationRomanian":"Adresare formala (Herr) -> Sie cu majuscula (forma de politete)."},{"id":"pp-109","type":"Multiple Choice","difficulty":"Usor","question":"Marc und Anna, wo wohnt ___ ?","options":["du","Sie","ihr","er"],"correctAnswer":"ihr","explanationRomanian":"Adresare informala la 2+ persoane -> ihr (voi)."},{"id":"pp-110","type":"Multiple Choice","difficulty":"Mediu","question":"Ich helfe ___ . (mama mea = ei)","options":["sie","ihr","ihm","es"],"correctAnswer":"ihr","explanationRomanian":"helfen + Dat. ea -> ihr (pron. Dativ feminin)."},{"id":"pp-111","type":"Multiple Choice","difficulty":"Mediu","question":"Wir sehen ___ . (pe el)","options":["er","ihn","ihm","es"],"correctAnswer":"ihn","explanationRomanian":"sehen + Akk. el -> ihn (pron. Akk masculin)."},{"id":"pp-112","type":"Multiple Choice","difficulty":"Mediu","question":"Das Geschenk ist von ___ . (de la mine)","options":["ich","mich","mir","meinem"],"correctAnswer":"mir","explanationRomanian":"von + Dat. eu -> mir (pron. Dativ pers. 1 sg)."},{"id":"pp-113","type":"Multiple Choice","difficulty":"Mediu","question":"Sie liebt ___ . (pe noi)","options":["wir","uns","ihr","sie"],"correctAnswer":"uns","explanationRomanian":"lieben + Akk. noi -> uns (Akk pl. 1)."},{"id":"pp-114","type":"Multiple Choice","difficulty":"Usor","question":"Wer hat das gesehen? ___ habe es gesehen.","options":["Du","Mir","Ich","Mein"],"correctAnswer":"Ich","explanationRomanian":"Subiect (Nom.) -> ich. 'mir' e Dativ, 'mein' e adjectiv posesiv."},{"id":"pp-115","type":"Multiple Choice","difficulty":"Mediu","question":"Cum se zice 'cu el' (mit el)?","options":["mit er","mit ihm","mit ihn","mit ihnen"],"correctAnswer":"mit ihm","explanationRomanian":"mit + Dat. el -> ihm (pron. Dativ masculin)."},{"id":"pp-116","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["bin","Lehrer","Ich"],"correctAnswer":"Ich bin Lehrer","explanationRomanian":"S + V + complement."},{"id":"pp-117","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["uns","sie","sieht"],"correctAnswer":"Sie sieht uns","explanationRomanian":"S (sie) + V (sieht) + Akk (uns = pe noi)."},{"id":"pp-118","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["mir","Buch","ein","Er","gibt"],"correctAnswer":"Er gibt mir ein Buch","explanationRomanian":"geben + Dat. (mir) + Akk. (ein Buch). Dativul inainte de Akk daca pronume."},{"id":"pp-119","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["dir","ich","helfe"],"correctAnswer":"Ich helfe dir","explanationRomanian":"helfen + Dat. (dir = tie)."},{"id":"pp-120","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["dich","Wir","lieben"],"correctAnswer":"Wir lieben dich","explanationRomanian":"S + V + Akk (dich)."},{"id":"pp-121","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["euch","wir","danken"],"correctAnswer":"Wir danken euch","explanationRomanian":"danken + Dat. (euch = vouă)."},{"id":"pp-122","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich helfe ihn.\"","options":null,"correctAnswer":"Ich helfe ihm","explanationRomanian":"helfen + Dat. el -> ihm (nu ihn = Akk)."},{"id":"pp-123","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Sie liebt mir.\"","options":null,"correctAnswer":"Sie liebt mich","explanationRomanian":"lieben + Akk. eu -> mich (nu mir = Dat)."},{"id":"pp-124","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Wir sehen wir.\"","options":null,"correctAnswer":"Wir sehen uns","explanationRomanian":"wir e Nom. La Akk: uns. Reflexiv: 'wir sehen uns' = ne vedem."},{"id":"pp-125","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Sie wohnt mit mein Bruder.\"","options":null,"correctAnswer":"Sie wohnt mit meinem Bruder","explanationRomanian":"mit + Dat. mein -> meinem (m. Dat)."},{"id":"pp-126","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Scrie corect:\n\"Du hilfst mein.\"","options":null,"correctAnswer":"Du hilfst mir","explanationRomanian":"helfen + Dat. eu -> mir (pronume, nu adj. posesiv)."},{"id":"pp-127","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Scrie corect:\n\"Es geht gut mir.\"","options":null,"correctAnswer":"Es geht mir gut","explanationRomanian":"Topica fixa: 'es geht + Dat + adj/adverb'. mir vine inainte de gut."},{"id":"pp-128","type":"Umformung","difficulty":"Usor","question":"Inlocuieste cu pronume:\n\"Ich sehe Maria.\"","options":null,"correctAnswer":"Ich sehe sie","explanationRomanian":"Maria (f. sg. Akk) -> sie."},{"id":"pp-129","type":"Umformung","difficulty":"Mediu","question":"Inlocuieste cu pronume:\n\"Ich helfe dem Bruder.\"","options":null,"correctAnswer":"Ich helfe ihm","explanationRomanian":"dem Bruder (m. Dat.) -> ihm."},{"id":"pp-130","type":"Umformung","difficulty":"Mediu","question":"Inlocuieste cu pronume:\n\"Wir lieben die Eltern.\"","options":null,"correctAnswer":"Wir lieben sie","explanationRomanian":"die Eltern (pl. Akk.) -> sie."},{"id":"pp-131","type":"Umformung","difficulty":"Usor","question":"Pune la formal (Sie):\n\"Wie heisst du?\"","options":null,"correctAnswer":"Wie heissen Sie","explanationRomanian":"du -> Sie (formal). Verbul la pers. 3 pl: heissen Sie."},{"id":"pp-132","type":"Umformung","difficulty":"Mediu","question":"Pune la informal (du):\n\"Helfen Sie mir bitte.\"","options":null,"correctAnswer":"Hilfst du mir bitte","explanationRomanian":"Sie -> du. helfen e neregulat: du hilfst (umlaut)."},{"id":"pp-133","type":"Umformung","difficulty":"Usor","question":"Schimba la pers. 1 plural:\n\"Ich gehe ins Kino.\"","options":null,"correctAnswer":"Wir gehen ins Kino","explanationRomanian":"ich -> wir. Verbul: gehe -> gehen."}]},{"id":"modalverben","level":"A1","category":"Verbe","title_de":"Modalverben","title_ro":"Verbele modale","summary":"können, müssen, wollen, sollen, dürfen, mögen/möchten -- 6 verbe care exprima posibilitate, obligatie, dorinta. Verbul principal merge la INFINITIV la sfarsit.","theory":"\n<h3>Cele 6 verbe modale + traducerea</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Verb</th><th>Sens</th><th>Exemplu</th></tr></thead>\n  <tbody>\n    <tr><td><strong>können</strong></td><td>a putea, a sti</td><td>Ich kann schwimmen. (Pot/stiu sa inot.)</td></tr>\n    <tr><td><strong>müssen</strong></td><td>a trebui (obligatie)</td><td>Ich muss arbeiten. (Trebuie sa lucrez.)</td></tr>\n    <tr><td><strong>wollen</strong></td><td>a vrea (puternic)</td><td>Ich will lernen. (Vreau sa invat.)</td></tr>\n    <tr><td><strong>sollen</strong></td><td>a trebui (recomandare)</td><td>Du sollst schlafen. (Ar trebui sa dormi.)</td></tr>\n    <tr><td><strong>dürfen</strong></td><td>a avea voie</td><td>Ich darf rauchen. (Am voie sa fumez.)</td></tr>\n    <tr><td><strong>möchten</strong></td><td>as dori (politicos)</td><td>Ich möchte Kaffee. (As dori cafea.)</td></tr>\n  </tbody>\n</table>\n\n<h3>Conjugare la prezent -- regula speciala</h3>\n<p>Verbele modale au 2 trasaturi unice:</p>\n<ol>\n  <li><strong>Schimbare de vocala in singular</strong> (cu exceptia 'sollen').</li>\n  <li><strong>Persoana 1 si 3 singular sunt IDENTICE</strong> (fara terminatie).</li>\n</ol>\n\n<table class=\"gram-table\">\n  <thead><tr><th></th><th>können</th><th>müssen</th><th>wollen</th><th>möchten</th></tr></thead>\n  <tbody>\n    <tr><td>ich</td><td>k<strong>a</strong>nn</td><td>m<strong>u</strong>ss</td><td>w<strong>i</strong>ll</td><td>möchte</td></tr>\n    <tr><td>du</td><td>k<strong>a</strong>nnst</td><td>m<strong>u</strong>sst</td><td>w<strong>i</strong>llst</td><td>möchtest</td></tr>\n    <tr><td>er/sie/es</td><td>k<strong>a</strong>nn</td><td>m<strong>u</strong>ss</td><td>w<strong>i</strong>ll</td><td>möchte</td></tr>\n    <tr><td>wir</td><td>können</td><td>müssen</td><td>wollen</td><td>möchten</td></tr>\n    <tr><td>ihr</td><td>könnt</td><td>müsst</td><td>wollt</td><td>möchtet</td></tr>\n    <tr><td>sie/Sie</td><td>können</td><td>müssen</td><td>wollen</td><td>möchten</td></tr>\n  </tbody>\n</table>\n\n<h3>Pozitia in propozitie</h3>\n<p>Verbul modal este pe pozitia 2 (al doilea), iar verbul principal merge la <strong>INFINITIV la sfarsit</strong>:</p>\n<p class=\"gram-example\">Ich <strong>muss</strong> heute viel <strong>arbeiten</strong>.<br>\n(eu) (trebuie) (azi) (mult) (a lucra) -- Trebuie sa lucrez mult azi.</p>\n<p class=\"gram-example\">Wir <strong>wollen</strong> nach Berlin <strong>fahren</strong>.<br>\nVrem sa mergem la Berlin.</p>\n\n<div class=\"gram-tip\">\n<strong>möchten vs wollen:</strong> ambele = \"a vrea\". \"möchten\" e mult mai politicos (ca un conditional). La restaurant zici intotdeauna \"Ich möchte...\" nu \"Ich will...\".\n</div>\n","exercises":[{"type":"fill","prompt":"Ich ___ heute nicht arbeiten. (a putea)","answer":"kann","hint":"ich + können -> ?","explanation":"Ich kann = pot. Vocala se schimba: kann (nu könne)."},{"type":"fill","prompt":"Du ___ jetzt schlafen. (a trebui - obligatie)","answer":"musst","hint":"du + müssen -> ?","explanation":"du musst (cu 2 'ss')."},{"type":"choice","prompt":"Wir ___ ins Kino gehen. (a vrea - puternic)","options":["wollt","wollen","willst","will"],"answer":"wollen","explanation":"wir wollen = vrem. La plural fara schimbare de vocala."},{"type":"choice","prompt":"Cum se zice politicos 'Vreau o cafea, va rog' la cafenea?","options":["Ich will Kaffee","Ich möchte Kaffee","Ich kann Kaffee","Ich darf Kaffee"],"answer":"Ich möchte Kaffee","explanation":"möchte = as dori (politicos). 'Ich will' suna brutal."},{"type":"order","prompt":"Ordoneaza: lernen / heute / muss / Ich / Deutsch","answer":"Ich muss heute Deutsch lernen","hint":"Modal pe pozitia 2, infinitiv la sfarsit","explanation":"Schema: Subiect + Modal + complement + INFINITIV. Trebuie sa invat germana azi."},{"type":"fill","prompt":"Ihr ___ rauchen? (a avea voie)","answer":"dürft","hint":"ihr + dürfen","explanation":"ihr dürft = voi aveti voie."},{"id":"mv-300","type":"Lückentext","difficulty":"Usor","question":"Ich ___ Deutsch sprechen. (a putea)","options":null,"correctAnswer":"kann","explanationRomanian":"können -> ich kann (1 sg fara terminatie, vocala schimbata: ö->a)."},{"id":"mv-301","type":"Lückentext","difficulty":"Usor","question":"Du ___ heute kommen? (a vrea)","options":null,"correctAnswer":"willst","explanationRomanian":"wollen -> du willst (vocala o->i, terminatie -st)."},{"id":"mv-302","type":"Lückentext","difficulty":"Usor","question":"Wir ___ jetzt gehen. (a trebui)","options":null,"correctAnswer":"muessen","explanationRomanian":"muessen -> wir muessen (plural fara schimbare)."},{"id":"mv-303","type":"Lückentext","difficulty":"Mediu","question":"Er ___ rauchen. (a avea voie)","options":null,"correctAnswer":"darf","explanationRomanian":"duerfen -> er darf (umlaut pierdut, fara terminatie pers. 3)."},{"id":"mv-304","type":"Lückentext","difficulty":"Mediu","question":"Ihr ___ leiser sein. (ar trebui)","options":null,"correctAnswer":"sollt","explanationRomanian":"sollen -> ihr sollt (terminatie -t pentru voi)."},{"id":"mv-305","type":"Lückentext","difficulty":"Usor","question":"Ich ___ einen Kaffee, bitte. (politicos: as dori)","options":null,"correctAnswer":"moechte","explanationRomanian":"moechte = forma de politete pentru 'wollen'."},{"id":"mv-306","type":"Lückentext","difficulty":"Usor","question":"Sie (ea) ___ schwimmen. (a sti/putea)","options":null,"correctAnswer":"kann","explanationRomanian":"können -> sie kann (3 sg = 1 sg)."},{"id":"mv-307","type":"Lückentext","difficulty":"Usor","question":"Du ___ jetzt schlafen. (a trebui-obligatie)","options":null,"correctAnswer":"musst","explanationRomanian":"muessen -> du musst (cu 2 's', vocala neschimbata)."},{"id":"mv-308","type":"Lückentext","difficulty":"Usor","question":"Wir ___ ins Kino gehen. (vrem)","options":null,"correctAnswer":"wollen","explanationRomanian":"wollen -> wir wollen (plural fara schimbare)."},{"id":"mv-309","type":"Lückentext","difficulty":"Mediu","question":"Sie (dvs.) ___ hier nicht parken. (nu aveti voie)","options":null,"correctAnswer":"duerfen","explanationRomanian":"duerfen -> Sie duerfen (formal = pers. 3 pl.)."},{"id":"mv-310","type":"Multiple Choice","difficulty":"Usor","question":"Cum se zice politicos 'Vreau apa' la restaurant?","options":["Ich will Wasser","Ich moechte Wasser","Ich kann Wasser","Ich muss Wasser"],"correctAnswer":"Ich moechte Wasser","explanationRomanian":"moechte = forma politicoasa. 'Ich will' suna brutal in restaurant."},{"id":"mv-311","type":"Multiple Choice","difficulty":"Usor","question":"Care arata o OBLIGATIE puternica?","options":["koennen","duerfen","moegen","muessen"],"correctAnswer":"muessen","explanationRomanian":"muessen = a trebui (obligatie). Celelalte au alte sensuri."},{"id":"mv-312","type":"Multiple Choice","difficulty":"Mediu","question":"Care arata PERMISIUNE (a avea voie)?","options":["sollen","duerfen","wollen","muessen"],"correctAnswer":"duerfen","explanationRomanian":"duerfen = a avea voie. sollen = a trebui (recomandare); wollen = a vrea."},{"id":"mv-313","type":"Multiple Choice","difficulty":"Mediu","question":"Wir ___ heute lange schlafen. (avem voie - e weekend)","options":["muessen","duerfen","sollen","wollen"],"correctAnswer":"duerfen","explanationRomanian":"Pe weekend nu e obligatie ci permisiune -> duerfen."},{"id":"mv-314","type":"Multiple Choice","difficulty":"Mediu","question":"Du ___ mehr Sport machen. (recomandare medic)","options":["musst","darfst","sollst","willst"],"correctAnswer":"sollst","explanationRomanian":"Recomandare/sfat -> sollen. 'musst' ar fi obligatie stricta."},{"id":"mv-315","type":"Multiple Choice","difficulty":"Mediu","question":"Ich ___ heute nicht arbeiten, ich bin krank.","options":["kann","muss","darf","soll"],"correctAnswer":"kann","explanationRomanian":"'nu pot' din cauza bolii -> kann (capacitate fizica)."},{"id":"mv-316","type":"Multiple Choice","difficulty":"Mediu","question":"Cu modal, verbul principal merge:","options":["la inceput","imediat dupa modal","la sfarsit ca infinitiv","la sfarsit ca Partizip"],"correctAnswer":"la sfarsit ca infinitiv","explanationRomanian":"Modal pe poz. 2 + INFINITIV la sfarsitul propozitiei."},{"id":"mv-317","type":"Multiple Choice","difficulty":"Usor","question":"Care e forma corecta: 'tu poti'?","options":["du kann","du kannst","du kanst","du können"],"correctAnswer":"du kannst","explanationRomanian":"kann + st = kannst (vocala schimbata + terminatie pers. 2)."},{"id":"mv-318","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele:","options":["lernen","muss","Ich","Deutsch"],"correctAnswer":"Ich muss Deutsch lernen","explanationRomanian":"S + Modal poz.2 + complement + INFINITIV (lernen) la sfarsit."},{"id":"mv-319","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele:","options":["wir","ins","wollen","Kino","gehen"],"correctAnswer":"Wir wollen ins Kino gehen","explanationRomanian":"S + wollen + complement + gehen (inf.) la sfarsit."},{"id":"mv-320","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele:","options":["Kaffee","moechte","ich","einen"],"correctAnswer":"Ich moechte einen Kaffee","explanationRomanian":"Politete: moechte. NU necesita infinitiv aici (moechte e singur)."},{"id":"mv-321","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["fruh","morgen","musst","aufstehen","du"],"correctAnswer":"Du musst morgen fruh aufstehen","explanationRomanian":"Modal + verbul SEPARABIL ramane intreg ca infinitiv (aufstehen) la sfarsit."},{"id":"mv-322","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["nicht","rauchen","ihr","duerft","hier"],"correctAnswer":"Ihr duerft hier nicht rauchen","explanationRomanian":"S + duerfen + complement + nicht + INFINITIV. 'nicht' inainte de infinitiv."},{"id":"mv-323","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["Sie","Italienisch","spricht","kann"],"correctAnswer":"Sie kann Italienisch sprechen","explanationRomanian":"Modal kann + obiect + INFINITIV (sprechen)."},{"id":"mv-324","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich kann sprechen Deutsch.\"","options":null,"correctAnswer":"Ich kann Deutsch sprechen","explanationRomanian":"Cu modal: complementul (Deutsch) merge inainte de INFINITIV (sprechen) la sfarsit."},{"id":"mv-325","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Scrie corect:\n\"Du musst gehen jetzt.\"","options":null,"correctAnswer":"Du musst jetzt gehen","explanationRomanian":"Adverbele temporale (jetzt) inainte de infinitiv. INFINITIV mereu la sfarsit."},{"id":"mv-326","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Wir wollen ein Kaffee trinken.\"","options":null,"correctAnswer":"Wir wollen einen Kaffee trinken","explanationRomanian":"der Kaffee la Akk: einen (nu ein). Apoi infinitivul trinken."},{"id":"mv-327","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Scrie corect:\n\"Ich muess heute arbeiten.\"","options":null,"correctAnswer":"Ich muss heute arbeiten","explanationRomanian":"muessen pers. 1 sg = muss (cu 2 's'). 'muess' nu exista."},{"id":"mv-328","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Sie kannst gut singen.\"","options":null,"correctAnswer":"Sie kann gut singen","explanationRomanian":"Pers. 3 sg (sie) -> kann (fara -st). 'kannst' e pentru du."},{"id":"mv-329","type":"Umformung","difficulty":"Usor","question":"Adauga modal 'muessen':\n\"Ich gehe jetzt.\"","options":null,"correctAnswer":"Ich muss jetzt gehen","explanationRomanian":"Modal pe poz. 2 + verbul ('gehen') ramane infinitiv la sfarsit."},{"id":"mv-330","type":"Umformung","difficulty":"Mediu","question":"Adauga 'koennen':\n\"Sie spricht Italienisch.\"","options":null,"correctAnswer":"Sie kann Italienisch sprechen","explanationRomanian":"Verb 'spricht' devine infinitiv 'sprechen' la sfarsit. Modal kann pe poz. 2."},{"id":"mv-331","type":"Umformung","difficulty":"Usor","question":"Negativeaza:\n\"Ich darf rauchen.\"","options":null,"correctAnswer":"Ich darf nicht rauchen","explanationRomanian":"'nicht' inainte de infinitiv. Cu modal: modal + ... + nicht + infinitiv."},{"id":"mv-332","type":"Umformung","difficulty":"Usor","question":"Pune politicos:\n\"Ich will einen Kaffee.\"","options":null,"correctAnswer":"Ich moechte einen Kaffee","explanationRomanian":"wollen -> moechte pentru politete (la cumparaturi/restaurant)."},{"id":"mv-333","type":"Umformung","difficulty":"Mediu","question":"Pune la pers. 2 sg.:\n\"Ich kann gut tanzen.\"","options":null,"correctAnswer":"Du kannst gut tanzen","explanationRomanian":"kann + st = kannst pentru du (pers. 2 sg.)."}]},{"id":"sein-haben","level":"A1","category":"Verbe","title_de":"Sein und haben (Präsens)","title_ro":"A fi si a avea (prezent)","summary":"Verbele 'sein' (a fi) si 'haben' (a avea) -- cele mai importante verbe din germana, ambele neregulate.","theory":"\n<h3>SEIN (a fi) -- complet neregulat</h3>\n<table class=\"gram-table\">\n  <tbody>\n    <tr><td>ich</td><td><strong>bin</strong></td><td>eu sunt</td></tr>\n    <tr><td>du</td><td><strong>bist</strong></td><td>tu esti</td></tr>\n    <tr><td>er/sie/es</td><td><strong>ist</strong></td><td>el/ea este</td></tr>\n    <tr><td>wir</td><td><strong>sind</strong></td><td>noi suntem</td></tr>\n    <tr><td>ihr</td><td><strong>seid</strong></td><td>voi sunteti</td></tr>\n    <tr><td>sie/Sie</td><td><strong>sind</strong></td><td>ei sunt / dvs. sunteti</td></tr>\n  </tbody>\n</table>\n\n<h3>HABEN (a avea) -- aproape regulat</h3>\n<table class=\"gram-table\">\n  <tbody>\n    <tr><td>ich</td><td><strong>habe</strong></td><td>eu am</td></tr>\n    <tr><td>du</td><td><strong>hast</strong></td><td>tu ai (pierde 'b')</td></tr>\n    <tr><td>er/sie/es</td><td><strong>hat</strong></td><td>el are (pierde 'b')</td></tr>\n    <tr><td>wir</td><td><strong>haben</strong></td><td>noi avem</td></tr>\n    <tr><td>ihr</td><td><strong>habt</strong></td><td>voi aveti (pierde 'e')</td></tr>\n    <tr><td>sie/Sie</td><td><strong>haben</strong></td><td>ei au</td></tr>\n  </tbody>\n</table>\n\n<h3>Cand folosim sein vs haben</h3>\n<ul>\n  <li><strong>sein</strong> = pentru identitate, locatie, stare: \"Ich bin Marius. Ich bin in Berlin. Ich bin mude.\"</li>\n  <li><strong>haben</strong> = pentru posesie, varsta, foame/sete: \"Ich habe ein Auto. Ich habe 30 Jahre. Ich habe Hunger.\"</li>\n</ul>\n\n<div class=\"gram-tip\">\n<strong>Diferenta importanta vs romana:</strong> in germana <em>\"am 30 de ani\"</em> = <em>\"ich bin 30 Jahre alt\"</em> (literal: \"sunt 30 de ani batran\"). NU se zice \"ich habe 30 Jahre\".\nDar pentru foame/sete: <em>\"mi-e foame\"</em> = <em>\"ich habe Hunger\"</em> (literal: \"am foame\").\n</div>\n","exercises":[{"type":"fill","prompt":"Ich ___ Lehrer.","answer":"bin","hint":"ich + sein","explanation":"ich bin = eu sunt."},{"type":"fill","prompt":"Wir ___ aus Rumanien.","answer":"sind","hint":"wir + sein","explanation":"wir sind = noi suntem."},{"type":"fill","prompt":"Du ___ einen Bruder?","answer":"hast","hint":"du + haben","explanation":"du hast = tu ai (forma neregulata, pierde 'b')."},{"type":"choice","prompt":"Sie ___ 25 Jahre alt. (ea)","options":["bin","bist","ist","sind"],"answer":"ist","explanation":"In germana, varsta se exprima cu 'sein' nu 'haben'. sie ist = ea este."},{"type":"choice","prompt":"Ich ___ Hunger.","options":["bin","habe","hat","haben"],"answer":"habe","explanation":"Foame se exprima cu 'haben' (a avea) -> ich habe Hunger = mi-e foame."},{"type":"fill","prompt":"Ihr ___ Studenten?","answer":"seid","hint":"ihr + sein (e dificil!)","explanation":"ihr seid = voi sunteti. Forma 'seid' este unica, doar pentru ihr+sein."},{"id":"sh-200","type":"Lückentext","difficulty":"Usor","question":"Ich ___ Lehrer. (sein)","options":null,"correctAnswer":"bin","explanationRomanian":"ich + sein -> bin."},{"id":"sh-201","type":"Lückentext","difficulty":"Usor","question":"Du ___ einen Bruder? (haben)","options":null,"correctAnswer":"hast","explanationRomanian":"du + haben -> hast (pierde 'b')."},{"id":"sh-202","type":"Lückentext","difficulty":"Usor","question":"Wir ___ aus Rumaenien. (sein)","options":null,"correctAnswer":"sind","explanationRomanian":"wir + sein -> sind."},{"id":"sh-203","type":"Lückentext","difficulty":"Mediu","question":"Er ___ 30 Jahre alt. (sein - varsta)","options":null,"correctAnswer":"ist","explanationRomanian":"Varsta in germana cu 'sein': er ist 30 Jahre alt (literal: el este 30 ani batran)."},{"id":"sh-204","type":"Lückentext","difficulty":"Mediu","question":"Ich ___ Hunger. (haben)","options":null,"correctAnswer":"habe","explanationRomanian":"Foame in germana cu 'haben': ich habe Hunger."},{"id":"sh-205","type":"Lückentext","difficulty":"Usor","question":"Sie ___ keine Zeit. (haben - ea nu are)","options":null,"correctAnswer":"hat","explanationRomanian":"sie/er/es + haben -> hat."},{"id":"sh-206","type":"Lückentext","difficulty":"Mediu","question":"Ihr ___ Studenten. (sein)","options":null,"correctAnswer":"seid","explanationRomanian":"ihr + sein -> seid (forma unica, doar pentru ihr)."},{"id":"sh-207","type":"Lückentext","difficulty":"Usor","question":"Sie ___ zwei Kinder. (haben - ei au)","options":null,"correctAnswer":"haben","explanationRomanian":"sie (pl.) + haben -> haben."},{"id":"sh-208","type":"Multiple Choice","difficulty":"Mediu","question":"Cum se zice 'mi-e foame'?","options":["Ich bin Hunger","Ich habe Hunger","Ich bin hungrig","Ich habe hungrig"],"correctAnswer":"Ich habe Hunger","explanationRomanian":"In germana 'foame' = haben + Hunger (substantiv). 'Ich bin hungrig' (sunt flamand) cu adj. e si corect dar mai rar."},{"id":"sh-209","type":"Multiple Choice","difficulty":"Mediu","question":"Cum se zice 'am 25 ani'?","options":["Ich habe 25 Jahre","Ich bin 25 Jahre alt","Ich bin 25","Mir sind 25 Jahre"],"correctAnswer":"Ich bin 25 Jahre alt","explanationRomanian":"Varsta = sein + Jahre alt. NU 'haben'."},{"id":"sh-210","type":"Multiple Choice","difficulty":"Usor","question":"Wir ___ in Berlin. (suntem in Berlin)","options":["sind","haben","ist","seid"],"correctAnswer":"sind","explanationRomanian":"wir + sein -> sind."},{"id":"sh-211","type":"Multiple Choice","difficulty":"Usor","question":"Care e CORECT?","options":["du bist","du bin","du sein","du sind"],"correctAnswer":"du bist","explanationRomanian":"du + sein -> bist."},{"id":"sh-212","type":"Multiple Choice","difficulty":"Usor","question":"___ du Geschwister? (ai frati?)","options":["Bist","Hast","Habst","Sein"],"correctAnswer":"Hast","explanationRomanian":"du + haben -> hast (forma neregulata, fara 'b')."},{"id":"sh-213","type":"Multiple Choice","difficulty":"Mediu","question":"Ihr ___ glücklich. (sunteti)","options":["seid","sind","habt","bist"],"correctAnswer":"seid","explanationRomanian":"ihr + sein -> seid (forma unica si dificila!)."},{"id":"sh-214","type":"Multiple Choice","difficulty":"Mediu","question":"Sie (forma de politete) ___ Lehrer? (sunteti?)","options":["bist","ist","sind","seid"],"correctAnswer":"sind","explanationRomanian":"Sie (formal) + sein -> sind (la fel ca pers. 3 pl)."},{"id":"sh-215","type":"Multiple Choice","difficulty":"Mediu","question":"Care propozitie e GRESITA?","options":["Ich bin Hunger","Ich habe Hunger","Mir ist warm","Ich bin müde"],"correctAnswer":"Ich bin Hunger","explanationRomanian":"Hunger cere haben, nu sein. 'Mir ist warm' (mi-e cald) e corect cu Dat."},{"id":"sh-216","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["bin","Ich","Lehrer"],"correctAnswer":"Ich bin Lehrer","explanationRomanian":"S + V + complement."},{"id":"sh-217","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["habe","Ich","Hund","einen"],"correctAnswer":"Ich habe einen Hund","explanationRomanian":"haben + Akk: einen Hund (m.)."},{"id":"sh-218","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["aus","wir","Rumaenien","sind"],"correctAnswer":"Wir sind aus Rumaenien","explanationRomanian":"wir sind = noi suntem; aus + Dat (locul de origine)."},{"id":"sh-219","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["alt","Sie","ist","Jahre","30"],"correctAnswer":"Sie ist 30 Jahre alt","explanationRomanian":"Varsta cu 'sein': S + ist + N Jahre alt."},{"id":"sh-220","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["seid","muede","Ihr"],"correctAnswer":"Ihr seid muede","explanationRomanian":"ihr seid (sunteti) + adj."},{"id":"sh-221","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["habt","ihr","Zeit"],"correctAnswer":"Habt ihr Zeit","explanationRomanian":"Intrebare (V poz.1): habt + ihr + obiect."},{"id":"sh-222","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich bin Hunger.\"","options":null,"correctAnswer":"Ich habe Hunger","explanationRomanian":"Foame se exprima cu 'haben'."},{"id":"sh-223","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich habe 25 Jahre.\"","options":null,"correctAnswer":"Ich bin 25 Jahre alt","explanationRomanian":"Varsta se exprima cu 'sein' + Jahre alt."},{"id":"sh-224","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Corect:\n\"Du bin Lehrer.\"","options":null,"correctAnswer":"Du bist Lehrer","explanationRomanian":"du + sein -> bist."},{"id":"sh-225","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Corect:\n\"Wir bin glücklich.\"","options":null,"correctAnswer":"Wir sind glücklich","explanationRomanian":"wir + sein -> sind."},{"id":"sh-226","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Corect:\n\"Sie habt zwei Kinder.\"","options":null,"correctAnswer":"Sie haben zwei Kinder","explanationRomanian":"sie (pl.) + haben -> haben."},{"id":"sh-227","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Corect:\n\"Ihr bist Studenten.\"","options":null,"correctAnswer":"Ihr seid Studenten","explanationRomanian":"ihr + sein -> seid."},{"id":"sh-228","type":"Umformung","difficulty":"Usor","question":"Schimba subiectul la pers. 2 sg.:\n\"Ich bin müde.\"","options":null,"correctAnswer":"Du bist müde","explanationRomanian":"ich -> du; bin -> bist."},{"id":"sh-229","type":"Umformung","difficulty":"Usor","question":"Schimba la plural (wir):\n\"Ich habe einen Bruder.\"","options":null,"correctAnswer":"Wir haben einen Bruder","explanationRomanian":"ich -> wir; habe -> haben."},{"id":"sh-230","type":"Umformung","difficulty":"Mediu","question":"Pune la formal:\n\"Du bist Lehrer.\"","options":null,"correctAnswer":"Sie sind Lehrer","explanationRomanian":"du -> Sie (formal); bist -> sind."},{"id":"sh-231","type":"Umformung","difficulty":"Mediu","question":"Negativeaza:\n\"Ich habe Zeit.\"","options":null,"correctAnswer":"Ich habe keine Zeit","explanationRomanian":"Pentru substantive cu articol nedef./fara articol: 'kein/keine'."},{"id":"sh-232","type":"Umformung","difficulty":"Mediu","question":"Trecut (Praeteritum):\n\"Ich bin in Berlin.\"","options":null,"correctAnswer":"Ich war in Berlin","explanationRomanian":"sein -> war (eram/am fost)."},{"id":"sh-233","type":"Umformung","difficulty":"Mediu","question":"Trecut (Praeteritum):\n\"Sie hat einen Bruder.\"","options":null,"correctAnswer":"Sie hatte einen Bruder","explanationRomanian":"haben -> hatte (avea/avea/a avut)."}]},{"id":"adjective-deklination","level":"A2","category":"Adjective","title_de":"Adjektivdeklination (Nominativ + Akkusativ)","title_ro":"Declinarea adjectivelor","summary":"Cand adjectivul sta INAINTEA substantivului, primeste o terminatie. Trei tipuri de declinare in functie de articol.","theory":"\n<h3>Cand declinam adjectivul?</h3>\n<p>Numai cand vine <strong>inaintea</strong> substantivului. Cand este predicat (dupa \"ist\", \"wird\"), NU se declina:</p>\n<ul>\n  <li>Predicat: \"Das Auto ist <strong>neu</strong>.\" (Masina e noua. -- fara terminatie)</li>\n  <li>Atribut: \"Das ist ein <strong>neues</strong> Auto.\" (Este o masina noua. -- cu terminatie)</li>\n</ul>\n\n<h3>Cele 3 tipuri de declinare</h3>\n<p>Terminatia depinde de ce articol e in fata:</p>\n<ol>\n  <li><strong>Cu articol definit (der/die/das)</strong> -- declinare slaba</li>\n  <li><strong>Cu articol nedefinit (ein/eine/kein/mein)</strong> -- declinare mixta</li>\n  <li><strong>Fara articol</strong> -- declinare tare (nu o tratam acum)</li>\n</ol>\n\n<h3>1. Cu articol definit (der/die/das/die)</h3>\n<table class=\"gram-table\">\n  <thead><tr><th></th><th>Nominativ</th><th>Akkusativ</th></tr></thead>\n  <tbody>\n    <tr><td>m.</td><td>der nett<strong>e</strong> Mann</td><td>den nett<strong>en</strong> Mann</td></tr>\n    <tr><td>f.</td><td>die nett<strong>e</strong> Frau</td><td>die nett<strong>e</strong> Frau</td></tr>\n    <tr><td>n.</td><td>das nett<strong>e</strong> Kind</td><td>das nett<strong>e</strong> Kind</td></tr>\n    <tr><td>pl.</td><td>die nett<strong>en</strong> Leute</td><td>die nett<strong>en</strong> Leute</td></tr>\n  </tbody>\n</table>\n<p><strong>Pattern simplu:</strong> majoritatea sunt -e. Doar masculin Akkusativ si pluralul = -en.</p>\n\n<h3>2. Cu articol nedefinit (ein/eine + kein/mein)</h3>\n<table class=\"gram-table\">\n  <thead><tr><th></th><th>Nominativ</th><th>Akkusativ</th></tr></thead>\n  <tbody>\n    <tr><td>m.</td><td>ein nett<strong>er</strong> Mann</td><td>einen nett<strong>en</strong> Mann</td></tr>\n    <tr><td>f.</td><td>eine nett<strong>e</strong> Frau</td><td>eine nett<strong>e</strong> Frau</td></tr>\n    <tr><td>n.</td><td>ein nett<strong>es</strong> Kind</td><td>ein nett<strong>es</strong> Kind</td></tr>\n    <tr><td>pl.</td><td>-- nett<strong>e</strong> Leute</td><td>-- nett<strong>e</strong> Leute</td></tr>\n  </tbody>\n</table>\n<p><strong>Pattern:</strong> adjectivul \"imprumuta\" terminatia care lipseste de la articol (ein nu are terminatie clara, deci adjectivul ia -er pentru masculin etc.).</p>\n\n<h3>Logica simplificata</h3>\n<p>Daca articolul iti spune CLAR genul (der, die, das), atunci adjectivul are doar -e sau -en (slab).</p>\n<p>Daca articolul NU iti spune clar (ein), adjectivul preia \"munca\" si arata genul prin terminatie (-er, -e, -es).</p>\n\n<h3>Exemple practice</h3>\n<ul>\n  <li>Nom. m.: <em>Der <strong>kleine</strong> Hund / Ein <strong>kleiner</strong> Hund</em> bellt. (Cainele mic latra.)</li>\n  <li>Akk. m.: Ich sehe <em>den <strong>kleinen</strong> Hund / einen <strong>kleinen</strong> Hund</em>.</li>\n  <li>Nom. f.: <em>Die <strong>schöne</strong> Frau / Eine <strong>schöne</strong> Frau</em> singt.</li>\n  <li>Akk. f.: Ich sehe <em>die <strong>schöne</strong> Frau / eine <strong>schöne</strong> Frau</em>.</li>\n  <li>Nom. n.: <em>Das <strong>neue</strong> Auto / Ein <strong>neues</strong> Auto</em> ist rot.</li>\n</ul>\n\n<div class=\"gram-tip\">\n<strong>Sfat:</strong> Cu articol definit, regula este \"-e majoritar, -en doar la m.Akk si plural\". Cu articol nedefinit, gandeste-te ce litera lipseste de la 'der/die/das' si pune ea pe adjectiv.\n</div>\n","exercises":[{"type":"fill","prompt":"Das ist ein ___ Mann. (nett, m. Nom.)","answer":"netter","hint":"ein + adjectiv -> -er la m. Nom.","explanation":"ein nu arata genul, adjectivul preia -er (de la 'der')."},{"type":"fill","prompt":"Ich sehe den ___ Mann. (nett, m. Akk.)","answer":"netten","hint":"den arata clar Akk -> -en","explanation":"Cu articol definit, m. Akk = -en."},{"type":"choice","prompt":"Das ist ein ___ Kind. (klein)","options":["klein","kleines","kleiner","kleinen"],"answer":"kleines","explanation":"ein la neutru -> adjectivul ia -es (de la 'das')."},{"type":"choice","prompt":"Wir haben einen ___ Hund. (gross)","options":["gross","grosse","grossen","grosser"],"answer":"grossen","explanation":"einen = m. Akk + adjectiv -en (declinare mixta, m. Akk)."},{"type":"fill","prompt":"Die ___ Lampe ist neu. (alt, f. Nom.)","answer":"alte","hint":"die + adjectiv -> -e","explanation":"Cu articol definit, f. Nom = -e."},{"type":"fill","prompt":"Ich kaufe eine ___ Tasche. (rot, f. Akk.)","answer":"rote","hint":"eine + adjectiv -> -e","explanation":"Cu articol nedefinit, f. Akk = -e (acelasi ca Nom.)."},{"id":"ad-600","type":"Lückentext","difficulty":"Mediu","question":"Das ist ein ___ Mann. (nett, m. Nom.)","options":null,"correctAnswer":"netter","explanationRomanian":"ein + adj. m. Nom -> -er (preia 'r' de la 'der')."},{"id":"ad-601","type":"Lückentext","difficulty":"Mediu","question":"Ich sehe den ___ Mann. (nett, m. Akk.)","options":null,"correctAnswer":"netten","explanationRomanian":"den + adj. m. Akk -> -en (declinare slaba)."},{"id":"ad-602","type":"Lückentext","difficulty":"Usor","question":"Das ist eine ___ Frau. (schön, f. Nom.)","options":null,"correctAnswer":"schöne","explanationRomanian":"eine + adj. f. Nom -> -e."},{"id":"ad-603","type":"Lückentext","difficulty":"Mediu","question":"Ich kaufe ein ___ Auto. (neu, n. Akk.)","options":null,"correctAnswer":"neues","explanationRomanian":"ein + adj. n. Akk -> -es (preia 's' de la 'das')."},{"id":"ad-604","type":"Lückentext","difficulty":"Usor","question":"Die ___ Lampe ist neu. (alt, f. Nom.)","options":null,"correctAnswer":"alte","explanationRomanian":"die + adj. f. Nom -> -e (slab)."},{"id":"ad-605","type":"Lückentext","difficulty":"Mediu","question":"Wir haben einen ___ Hund. (gross, m. Akk.)","options":null,"correctAnswer":"grossen","explanationRomanian":"einen + adj. m. Akk -> -en (declinare mixta)."},{"id":"ad-606","type":"Lückentext","difficulty":"Mediu","question":"Das ___ Kind spielt. (klein, n. Nom., articol definit)","options":null,"correctAnswer":"kleine","explanationRomanian":"das + adj. n. Nom -> -e."},{"id":"ad-607","type":"Lückentext","difficulty":"Usor","question":"Ich kaufe eine ___ Tasche. (rot, f. Akk.)","options":null,"correctAnswer":"rote","explanationRomanian":"eine + adj. f. Akk -> -e."},{"id":"ad-608","type":"Multiple Choice","difficulty":"Mediu","question":"Cu articol definit (der/die/das), majoritatea adj. au:","options":["-er","-e","-en","-es"],"correctAnswer":"-e","explanationRomanian":"Cu articol definit, majoritatea = -e. Doar m.Akk si plural = -en."},{"id":"ad-609","type":"Multiple Choice","difficulty":"Mediu","question":"Cu articol nedefinit (ein) la m. Nom., adj. ia:","options":["-er","-en","-e","-es"],"correctAnswer":"-er","explanationRomanian":"ein nu arata genul, adj. preia 'r' de la 'der' -> ein netter Mann."},{"id":"ad-610","type":"Multiple Choice","difficulty":"Mediu","question":"'un copil mic' (n. Nom.) =","options":["ein klein Kind","ein kleines Kind","ein kleiner Kind","ein kleinen Kind"],"correctAnswer":"ein kleines Kind","explanationRomanian":"ein + adj. n. Nom -> -es (preia 's' de la 'das')."},{"id":"ad-611","type":"Multiple Choice","difficulty":"Greu","question":"'masina noua' (f. Nom., articol definit) =","options":["die neue Auto","die neu Auto","die neue Auto","das neue Auto"],"correctAnswer":"das neue Auto","explanationRomanian":"Auto e NEUTRU (das Auto), nu feminin. Adj: das neue Auto."},{"id":"ad-612","type":"Multiple Choice","difficulty":"Greu","question":"'un baiat inalt' (m. Akk.) =","options":["einen grossen Junge","einen grossen Jungen","ein grossen Jungen","einen grosser Junge"],"correctAnswer":"einen grossen Jungen","explanationRomanian":"der Junge e n-deklinatie -> Akk: den Jungen / einen Jungen. Adj: grossen (m. Akk)."},{"id":"ad-613","type":"Multiple Choice","difficulty":"Mediu","question":"Cand adjectivul NU se declina?","options":["niciodata, mereu","cand e dupa 'sein' (predicat)","cand e inainte de substantiv","cand e dupa 'haben'"],"correctAnswer":"cand e dupa 'sein' (predicat)","explanationRomanian":"Predicat: 'Das Auto IST neu' (fara terminatie). Atribut: 'das neue Auto' (cu terminatie)."},{"id":"ad-614","type":"Multiple Choice","difficulty":"Mediu","question":"'Mancarea calda' (n. Nom., articol definit) =","options":["das warmes Essen","der warme Essen","das warme Essen","die warme Essen"],"correctAnswer":"das warme Essen","explanationRomanian":"das Essen (n.). das + adj. n. Nom -> -e."},{"id":"ad-615","type":"Multiple Choice","difficulty":"Mediu","question":"Pluralul 'oameni mici' (Nom., articol definit) =","options":["die kleine Leute","die kleines Leute","die kleinen Leute","die klein Leute"],"correctAnswer":"die kleinen Leute","explanationRomanian":"die + plural -> adj. -en (slab plural mereu -en)."},{"id":"ad-616","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["ein","Mann","Das","ist","netter"],"correctAnswer":"Das ist ein netter Mann","explanationRomanian":"ein + adj-er + Subst (m. Nom)."},{"id":"ad-617","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["sehe","den","Hund","Ich","grossen"],"correctAnswer":"Ich sehe den grossen Hund","explanationRomanian":"den + adj-en + Subst (m. Akk)."},{"id":"ad-618","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["neue","Das","Auto","ist","rot"],"correctAnswer":"Das neue Auto ist rot","explanationRomanian":"das + adj-e + Subst (predicat 'rot' fara declinare)."},{"id":"ad-619","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["eine","Maria","hat","Tasche","rote"],"correctAnswer":"Maria hat eine rote Tasche","explanationRomanian":"eine + adj-e + Subst (f. Akk)."},{"id":"ad-620","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["altes","Wir","Haus","kaufen","ein"],"correctAnswer":"Wir kaufen ein altes Haus","explanationRomanian":"ein + adj-es + Subst (n. Akk)."},{"id":"ad-621","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["kleinen","die","spielen","Kinder"],"correctAnswer":"Die kleinen Kinder spielen","explanationRomanian":"die + adj-en + Subst (pl. Nom)."},{"id":"ad-622","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Das ist ein nett Mann.\"","options":null,"correctAnswer":"Das ist ein netter Mann","explanationRomanian":"Adj inainte de substantiv MEREU primeste terminatie. m. Nom + ein -> -er."},{"id":"ad-623","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich sehe den nette Hund.\"","options":null,"correctAnswer":"Ich sehe den netten Hund","explanationRomanian":"den (m. Akk) + adj -> -en. 'nette' ar fi pentru 'der nette Hund' (Nom.)."},{"id":"ad-624","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Das ist ein klein Kind.\"","options":null,"correctAnswer":"Das ist ein kleines Kind","explanationRomanian":"ein + adj. n. Nom -> -es (de la 'das')."},{"id":"ad-625","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Wir kaufen ein neuen Auto.\"","options":null,"correctAnswer":"Wir kaufen ein neues Auto","explanationRomanian":"ein + adj. n. Akk -> -es. 'neuen' ar fi pentru masculin Akk."},{"id":"ad-626","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Die kleine Kinder spielen.\"","options":null,"correctAnswer":"Die kleinen Kinder spielen","explanationRomanian":"Plural definit -> adj. mereu -en, nu -e."},{"id":"ad-627","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Sie hat einen rote Tasche.\"","options":null,"correctAnswer":"Sie hat eine rote Tasche","explanationRomanian":"die Tasche e f. La Akk: eine (nu einen). Adj. -e."},{"id":"ad-628","type":"Umformung","difficulty":"Mediu","question":"Schimba la articol definit:\n\"Das ist ein netter Mann.\"","options":null,"correctAnswer":"Das ist der nette Mann","explanationRomanian":"ein netter -> der nette (cu articol definit, adj. preia -e slab)."},{"id":"ad-629","type":"Umformung","difficulty":"Mediu","question":"Schimba la articol nedefinit:\n\"Die schöne Frau singt.\"","options":null,"correctAnswer":"Eine schöne Frau singt","explanationRomanian":"die schöne -> eine schöne (la f., adj. ramane -e)."},{"id":"ad-630","type":"Umformung","difficulty":"Mediu","question":"Pune la plural:\n\"Das ist ein nettes Kind.\"","options":null,"correctAnswer":"Das sind nette Kinder","explanationRomanian":"Plural fara articol nedefinit (ein -> nimic). Adj. -e (declinare tare/mixta plural)."},{"id":"ad-631","type":"Umformung","difficulty":"Greu","question":"Schimba la Akkusativ:\n\"Der nette Mann steht da.\"","options":null,"correctAnswer":"Ich sehe den netten Mann","explanationRomanian":"der nette -> den netten la m. Akk."},{"id":"ad-632","type":"Umformung","difficulty":"Mediu","question":"Adauga adjectivul 'gross':\n\"Wir haben einen Hund.\"","options":null,"correctAnswer":"Wir haben einen grossen Hund","explanationRomanian":"einen + adj. m. Akk -> -en (mixt)."},{"id":"ad-633","type":"Umformung","difficulty":"Mediu","question":"Schimba la negativ cu kein:\n\"Ich kaufe ein neues Auto.\"","options":null,"correctAnswer":"Ich kaufe kein neues Auto","explanationRomanian":"ein -> kein. Adj. n. Akk dupa kein la fel: kein neues Auto."}]},{"id":"wechselpraepositionen","level":"A2","category":"Prepozitii","title_de":"Wechselpräpositionen","title_ro":"Prepozitii care 'isi schimba' cazul","summary":"9 prepozitii care iau Akkusativ pentru directie (wohin?) si Dativ pentru loc (wo?).","theory":"\n<h3>Cele 9 prepozitii Wechsel</h3>\n<p><strong>an, auf, hinter, in, neben, über, unter, vor, zwischen</strong></p>\n<p>Aceste prepozitii pot lua DOUA cazuri, in functie de inteles.</p>\n\n<h3>Regula de aur</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Caz</th><th>Intrebare</th><th>Sens</th></tr></thead>\n  <tbody>\n    <tr>\n      <td><strong>Akkusativ</strong></td>\n      <td><strong>Wohin?</strong> (incotro?)</td>\n      <td>directia, miscarea catre un loc</td>\n    </tr>\n    <tr>\n      <td><strong>Dativ</strong></td>\n      <td><strong>Wo?</strong> (unde?)</td>\n      <td>locul, pozitia statica</td>\n    </tr>\n  </tbody>\n</table>\n\n<h3>Comparatia clasica</h3>\n<p class=\"gram-example\"><strong>Directie (Akk):</strong> Ich gehe <strong>in die Schule</strong>. (Merg la scoala.)<br>\n<strong>Loc (Dat):</strong> Ich bin <strong>in der Schule</strong>. (Sunt la scoala.)</p>\n\n<p class=\"gram-example\"><strong>Directie (Akk):</strong> Ich lege das Buch <strong>auf den Tisch</strong>. (Pun cartea pe masa.)<br>\n<strong>Loc (Dat):</strong> Das Buch liegt <strong>auf dem Tisch</strong>. (Cartea sta pe masa.)</p>\n\n<h3>Verbe-cheie pentru fiecare grup</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Cu Akkusativ (directie)</th><th>Cu Dativ (loc)</th></tr></thead>\n  <tbody>\n    <tr>\n      <td>gehen, fahren, fliegen, kommen<br>legen (a aseza orizontal)<br>stellen (a aseza vertical)<br>setzen (a aseza, a pune jos)<br>hängen (a atarna, a agata)</td>\n      <td>sein, bleiben<br>liegen (a sta culcat)<br>stehen (a sta in picioare)<br>sitzen (a sta jezand)<br>hängen (a atarna pasiv)<br>wohnen, leben</td>\n    </tr>\n  </tbody>\n</table>\n\n<h3>Articolele schimbate</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Gen</th><th>Akkusativ (wohin)</th><th>Dativ (wo)</th></tr></thead>\n  <tbody>\n    <tr><td>m.</td><td>auf <strong>den</strong> Tisch</td><td>auf <strong>dem</strong> Tisch</td></tr>\n    <tr><td>f.</td><td>in <strong>die</strong> Stadt</td><td>in <strong>der</strong> Stadt</td></tr>\n    <tr><td>n.</td><td>in <strong>das/ins</strong> Kino</td><td>in <strong>dem/im</strong> Kino</td></tr>\n    <tr><td>pl.</td><td>auf <strong>die</strong> Berge</td><td>auf <strong>den</strong> Bergen</td></tr>\n  </tbody>\n</table>\n\n<h3>Contractii frecvente</h3>\n<ul>\n  <li>in dem -> <strong>im</strong> (im Kino, im Park)</li>\n  <li>in das -> <strong>ins</strong> (ins Kino, ins Bett)</li>\n  <li>an dem -> <strong>am</strong> (am Strand, am Sonntag)</li>\n  <li>an das -> <strong>ans</strong> (ans Meer)</li>\n</ul>\n\n<div class=\"gram-tip\">\n<strong>Truc sigur:</strong> intreaba-te \"Cum ar suna intrebarea: WO sau WOHIN?\" -- Wo? -> Dativ. Wohin? -> Akkusativ. Daca ai indoieli, gandeste-te daca subiectul se misca (Akk) sau e static (Dat).\n</div>\n","exercises":[{"type":"fill","prompt":"Wohin gehst du? -- Ich gehe in ___ Park. (m. directie)","answer":"den","hint":"wohin = Akkusativ","explanation":"wohin = directie = Akk. der Park -> in den Park."},{"type":"fill","prompt":"Wo bist du? -- Ich bin in ___ Park. (m. loc)","answer":"dem","hint":"wo = Dativ","explanation":"wo = loc = Dat. der Park -> in dem Park (sau im Park, contractie)."},{"type":"choice","prompt":"Das Buch liegt auf ___ Tisch.","options":["den","dem","der","die"],"answer":"dem","explanation":"liegen (a sta culcat) = static = Dat. der Tisch -> auf dem Tisch."},{"type":"choice","prompt":"Ich lege das Buch auf ___ Tisch.","options":["den","dem","der","die"],"answer":"den","explanation":"legen (a pune) = miscare/directie = Akk. der Tisch -> auf den Tisch."},{"type":"fill","prompt":"Wir fahren in ___ Stadt. (f.)","answer":"die","hint":"fahren = miscare = Akk","explanation":"fahren in + Akk. die Stadt -> in die Stadt."},{"type":"fill","prompt":"Maria wohnt in ___ Stadt. (f.)","answer":"der","hint":"wohnen = static = Dat","explanation":"wohnen = a locui (static) = Dat. die Stadt -> in der Stadt."},{"id":"wp-400","type":"Lückentext","difficulty":"Usor","question":"Wo bist du? - Ich bin in ___ Park. (m. loc)","options":null,"correctAnswer":"dem","explanationRomanian":"wo? = Dat. der Park (m.) -> dem Park (sau im)."},{"id":"wp-401","type":"Lückentext","difficulty":"Usor","question":"Wohin gehst du? - In ___ Park. (m. directie)","options":null,"correctAnswer":"den","explanationRomanian":"wohin? = Akk. der Park -> den Park."},{"id":"wp-402","type":"Lückentext","difficulty":"Mediu","question":"Wohin legst du das Buch? - Auf ___ Tisch. (m. directie)","options":null,"correctAnswer":"den","explanationRomanian":"legen + directie = Akk. der Tisch -> den Tisch."},{"id":"wp-403","type":"Lückentext","difficulty":"Mediu","question":"Wo liegt das Buch? - Auf ___ Tisch. (m. loc)","options":null,"correctAnswer":"dem","explanationRomanian":"liegen + loc = Dat. der Tisch -> dem Tisch."},{"id":"wp-404","type":"Lückentext","difficulty":"Mediu","question":"Ich gehe in ___ Stadt. (f. directie)","options":null,"correctAnswer":"die","explanationRomanian":"wohin? = Akk. die Stadt (f.) -> die Stadt (neschimbat la f.)."},{"id":"wp-405","type":"Lückentext","difficulty":"Mediu","question":"Ich wohne in ___ Stadt. (f. loc)","options":null,"correctAnswer":"der","explanationRomanian":"wo? = Dat. die Stadt (f.) -> der Stadt."},{"id":"wp-406","type":"Lückentext","difficulty":"Mediu","question":"Wir gehen ins Kino. (Kino, n.) -> Care e contractia?","options":null,"correctAnswer":"ins","explanationRomanian":"in + das = ins (contractie). Pentru directie cu neutru."},{"id":"wp-407","type":"Lückentext","difficulty":"Mediu","question":"Wir sind im Kino. -> Forma necontractata?","options":null,"correctAnswer":"in dem","explanationRomanian":"im = in dem (Dat. neutru, loc)."},{"id":"wp-408","type":"Lückentext","difficulty":"Greu","question":"Hang das Bild an ___ Wand. (f. directie)","options":null,"correctAnswer":"die","explanationRomanian":"haengen (a agata, directie) -> Akk. die Wand -> die Wand."},{"id":"wp-409","type":"Lückentext","difficulty":"Greu","question":"Das Bild haengt an ___ Wand. (f. loc)","options":null,"correctAnswer":"der","explanationRomanian":"haengen (a atarna pasiv, loc) -> Dat. die Wand -> der Wand."},{"id":"wp-410","type":"Multiple Choice","difficulty":"Mediu","question":"Wo? Das Auto steht vor ___ Haus.","options":["das","dem","den","der"],"correctAnswer":"dem","explanationRomanian":"wo? = Dat. das Haus (n.) -> dem Haus."},{"id":"wp-411","type":"Multiple Choice","difficulty":"Mediu","question":"Wohin? Ich fahre vor ___ Haus.","options":["das","dem","den","der"],"correctAnswer":"das","explanationRomanian":"wohin? = Akk. das Haus (n.) -> das Haus (neutru neschimbat)."},{"id":"wp-412","type":"Multiple Choice","difficulty":"Mediu","question":"Die Katze sitzt unter ___ Tisch. (Tisch, m.)","options":["der","den","dem","des"],"correctAnswer":"dem","explanationRomanian":"sitzen = static, wo? = Dat. der Tisch -> dem Tisch."},{"id":"wp-413","type":"Multiple Choice","difficulty":"Greu","question":"Ich setze das Kind auf ___ Stuhl. (Stuhl, m.)","options":["der","den","dem","des"],"correctAnswer":"den","explanationRomanian":"setzen (a aseza, directie) -> Akk. der Stuhl -> den Stuhl."},{"id":"wp-414","type":"Multiple Choice","difficulty":"Usor","question":"Wo wohnst du? - Ich wohne ___ Berlin.","options":["in","an","auf","nach"],"correctAnswer":"in","explanationRomanian":"Pentru orase folosim 'in' + Dat. (in Berlin)."},{"id":"wp-415","type":"Multiple Choice","difficulty":"Mediu","question":"Wohin fahrst du? - ___ Berlin.","options":["In","Nach","Zu","An"],"correctAnswer":"Nach","explanationRomanian":"Pentru directie spre orase/tari fara articol: 'nach' (nach Berlin, nach Deutschland)."},{"id":"wp-416","type":"Multiple Choice","difficulty":"Greu","question":"Care e CORECT pentru 'la doctor' (mergi)?","options":["zur Aerztin","in die Aerztin","auf die Aerztin","an die Aerztin"],"correctAnswer":"zur Aerztin","explanationRomanian":"La persoane: 'zu' + Dat. zu der = zur. zur Aerztin = la doctorita."},{"id":"wp-417","type":"Multiple Choice","difficulty":"Greu","question":"Care e CORECT pentru 'la mare' (mergi in vacanta)?","options":["ins Meer","im Meer","ans Meer","am Meer"],"correctAnswer":"ans Meer","explanationRomanian":"'an + das = ans' pentru mare (Akk. directie). 'an' pentru margine de apa."},{"id":"wp-418","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele:","options":["Park","ich","gehe","in","den"],"correctAnswer":"Ich gehe in den Park","explanationRomanian":"wohin? Akk: in den Park."},{"id":"wp-419","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele:","options":["Park","im","ich","bin"],"correctAnswer":"Ich bin im Park","explanationRomanian":"wo? Dat: im Park (im = in dem)."},{"id":"wp-420","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["dem","Buch","auf","Tisch","liegt","das"],"correctAnswer":"Das Buch liegt auf dem Tisch","explanationRomanian":"liegen = static. auf + Dat. (dem Tisch)."},{"id":"wp-421","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza cuvintele:","options":["Mauer","Bild","die","an","haengen","wir","das"],"correctAnswer":"Wir haengen das Bild an die Mauer","explanationRomanian":"haengen (a agata) = directie. an + Akk. (die Mauer, f.)."},{"id":"wp-422","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["Schule","die","Kinder","gehen","in"],"correctAnswer":"Die Kinder gehen in die Schule","explanationRomanian":"wohin? Akk. die Schule (f.) -> in die Schule."},{"id":"wp-423","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["sitzt","Stuhl","auf","dem","die","Katze"],"correctAnswer":"Die Katze sitzt auf dem Stuhl","explanationRomanian":"sitzen = static. auf + Dat. (dem Stuhl)."},{"id":"wp-424","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich gehe in dem Park.\"","options":null,"correctAnswer":"Ich gehe in den Park","explanationRomanian":"wohin? = Akk. der Park -> den Park (nu dem)."},{"id":"wp-425","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Das Buch liegt auf den Tisch.\"","options":null,"correctAnswer":"Das Buch liegt auf dem Tisch","explanationRomanian":"wo? liegen = static = Dat. dem Tisch (nu den)."},{"id":"wp-426","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich fahre in Berlin.\"","options":null,"correctAnswer":"Ich fahre nach Berlin","explanationRomanian":"Directie spre oras fara articol = 'nach', nu 'in'."},{"id":"wp-427","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Scrie corect:\n\"Das Bild haengt an die Wand.\"","options":null,"correctAnswer":"Das Bild haengt an der Wand","explanationRomanian":"haengen (a atarna pasiv) = static = Dat. die Wand -> der Wand."},{"id":"wp-428","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Wir gehen in die Kino.\"","options":null,"correctAnswer":"Wir gehen ins Kino","explanationRomanian":"das Kino (n.) directie. in + das = ins (contractie obligatorie). 'in die' nu se foloseste cu neutru."},{"id":"wp-429","type":"Umformung","difficulty":"Greu","question":"Schimba din loc in directie:\n\"Das Buch liegt auf dem Tisch.\"","options":null,"correctAnswer":"Ich lege das Buch auf den Tisch","explanationRomanian":"liegen (Dat.) -> legen (Akk.). Acum 'pun' cartea pe masa (directie)."},{"id":"wp-430","type":"Umformung","difficulty":"Mediu","question":"Schimba din directie in loc:\n\"Ich gehe in die Schule.\"","options":null,"correctAnswer":"Ich bin in der Schule","explanationRomanian":"gehen (Akk.) -> sein (Dat.). Acum 'sunt' la scoala (loc static)."},{"id":"wp-431","type":"Umformung","difficulty":"Mediu","question":"Foloseste contractie:\n\"Ich gehe in das Kino.\"","options":null,"correctAnswer":"Ich gehe ins Kino","explanationRomanian":"in + das = ins (contractie obligatorie cu neutru directie)."},{"id":"wp-432","type":"Umformung","difficulty":"Mediu","question":"Foloseste contractie:\n\"Wir sind in dem Park.\"","options":null,"correctAnswer":"Wir sind im Park","explanationRomanian":"in + dem = im (contractie cu masculin/neutru loc)."},{"id":"wp-433","type":"Umformung","difficulty":"Greu","question":"Pune cu prepozitia 'auf':\n\"Das Auto faehrt zur Strasse.\"","options":null,"correctAnswer":"Das Auto faehrt auf die Strasse","explanationRomanian":"Schimbare de prepozitie. 'auf + Akk' pentru directie pe suprafata."}]},{"id":"nebensaetze","level":"A2","category":"Propozitii","title_de":"Nebensätze (weil, dass, wenn, obwohl)","title_ro":"Propozitii subordonate","summary":"Conjuctii care introduc o propozitie secundara unde verbul merge la SFARSIT.","theory":"\n<h3>Cele 4 conjuctii principale la A2</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Conjuctie</th><th>Sens</th><th>Tip</th></tr></thead>\n  <tbody>\n    <tr><td><strong>weil</strong></td><td>deoarece, pentru ca</td><td>cauza</td></tr>\n    <tr><td><strong>dass</strong></td><td>ca, faptul ca</td><td>completiva</td></tr>\n    <tr><td><strong>wenn</strong></td><td>daca, atunci cand</td><td>conditie/timp</td></tr>\n    <tr><td><strong>obwohl</strong></td><td>desi</td><td>concesie</td></tr>\n  </tbody>\n</table>\n\n<h3>Regula de aur: VERBUL LA SFARSIT</h3>\n<p>In propozitia secundara introdusa de aceste conjuctii, <strong>verbul conjugat merge la sfarsitul absolut</strong>:</p>\n\n<p class=\"gram-example\">Ich bleibe zu Hause, <strong>weil</strong> ich krank <strong>bin</strong>.<br>\n(Stau acasa pentru ca sunt bolnav.) -- 'bin' la sfarsit.</p>\n\n<p class=\"gram-example\">Ich glaube, <strong>dass</strong> er morgen <strong>kommt</strong>.<br>\n(Cred ca el vine maine.) -- 'kommt' la sfarsit.</p>\n\n<p class=\"gram-example\">Ich rufe dich an, <strong>wenn</strong> ich Zeit <strong>habe</strong>.<br>\n(Te sun daca am timp.) -- 'habe' la sfarsit.</p>\n\n<p class=\"gram-example\">Sie kommt, <strong>obwohl</strong> sie müde <strong>ist</strong>.<br>\n(Vine, desi e obosita.) -- 'ist' la sfarsit.</p>\n\n<h3>Cu verbe modale</h3>\n<p>Modal + infinitiv = modalul (conjugat) merge la sfarsit, dupa infinitiv:</p>\n<p class=\"gram-example\">Ich lerne, <strong>weil</strong> ich die Prüfung <em>bestehen</em> <strong>will</strong>.<br>\n(Invat pentru ca vreau sa trec examenul.)</p>\n\n<h3>Cu Perfekt</h3>\n<p>Auxiliarul (haben/sein) merge la sfarsit, DUPA Partizip:</p>\n<p class=\"gram-example\">Ich bin müde, <strong>weil</strong> ich gestern viel <em>gearbeitet</em> <strong>habe</strong>.<br>\n(Sunt obosit pentru ca am muncit mult ieri.)</p>\n\n<h3>Cu verbe separabile</h3>\n<p>Verbul separabil ramane intreg (nedespartit) la sfarsit:</p>\n<p class=\"gram-example\">Ich kann nicht, <strong>weil</strong> ich um 6 <strong>aufstehe</strong>.<br>\n(Nu pot pentru ca ma scol la 6.) -- aufstehen ramane intreg, nu se desparte.</p>\n\n<h3>Inversiune cand subordonata vine prima</h3>\n<p>Daca subordonata e prima, verbul principal vine imediat dupa virgula:</p>\n<p class=\"gram-example\"><strong>Wenn</strong> es regnet, <strong>bleibe</strong> ich zu Hause.<br>\n(Daca ploua, raman acasa.)<br>\nNU: \"Wenn es regnet, ich bleibe zu Hause.\"</p>\n\n<div class=\"gram-tip\">\n<strong>Diferenta wenn vs als:</strong><br>\n<strong>als</strong> = O DATA in trecut: \"Als ich ein Kind war...\" (Cand eram copil).<br>\n<strong>wenn</strong> = repetat sau viitor: \"Wenn ich Zeit habe...\" (Cand am timp).\n</div>\n","exercises":[{"type":"fill","prompt":"Ich bleibe zu Hause, weil ich krank ___.","answer":"bin","hint":"verb la sfarsit dupa weil","explanation":"weil + verb la sfarsit. ich bin = sunt."},{"type":"transform","prompt":"Combina cu 'weil': Ich lerne. Ich will gut sprechen.","answer":"Ich lerne, weil ich gut sprechen will.","hint":"modal la sfarsit dupa infinitiv","explanation":"Cu modal: ... infinitiv + modal la sfarsit."},{"type":"transform","prompt":"Combina cu 'dass': Sie sagt: Ich komme morgen.","answer":"Sie sagt, dass sie morgen kommt.","hint":"verb la sfarsit","explanation":"dass + verb la sfarsit. 'kommt' la final."},{"type":"order","prompt":"Ordoneaza: bin / weil / muede / ich / Ich gehe schlafen,","answer":"Ich gehe schlafen, weil ich muede bin","hint":"verb la sfarsit","explanation":"Subordonata cu weil: weil + subiect + ... + verb."},{"type":"fill","prompt":"Wenn es ___, gehe ich nicht aus. (a ploua = regnen, prezent)","answer":"regnet","hint":"wenn + verb la sfarsit","explanation":"wenn + es + verb la sfarsit. regnen -> regnet."},{"type":"transform","prompt":"Combina cu 'obwohl': Sie kommt. Sie ist krank.","answer":"Sie kommt, obwohl sie krank ist.","hint":"verb la sfarsit","explanation":"obwohl + ... + ist la final."},{"id":"nb-500","type":"Lückentext","difficulty":"Usor","question":"Ich bleibe zu Hause, ___ ich krank bin. (deoarece)","options":null,"correctAnswer":"weil","explanationRomanian":"weil = deoarece. Verbul 'bin' la sfarsit."},{"id":"nb-501","type":"Lückentext","difficulty":"Usor","question":"Ich rufe dich an, ___ ich Zeit habe. (cand)","options":null,"correctAnswer":"wenn","explanationRomanian":"wenn = cand/daca. Verbul 'habe' la sfarsit."},{"id":"nb-502","type":"Lückentext","difficulty":"Usor","question":"Ich glaube, ___ er morgen kommt. (ca)","options":null,"correctAnswer":"dass","explanationRomanian":"dass = ca (faptul ca). Verbul 'kommt' la sfarsit."},{"id":"nb-503","type":"Lückentext","difficulty":"Mediu","question":"Sie kommt, ___ sie muede ist. (desi)","options":null,"correctAnswer":"obwohl","explanationRomanian":"obwohl = desi (concesiv). Verbul 'ist' la sfarsit."},{"id":"nb-504","type":"Lückentext","difficulty":"Mediu","question":"Wir lernen, ___ wir die Pruefung bestehen wollen. (pentru ca = scop)","options":null,"correctAnswer":"damit","explanationRomanian":"damit = ca sa (scop). Modal 'wollen' la sfarsitul absolut."},{"id":"nb-505","type":"Lückentext","difficulty":"Usor","question":"Ich weiss, ___ er Deutsch spricht. (ca)","options":null,"correctAnswer":"dass","explanationRomanian":"dass + verb la sfarsit. Diferit de 'das' (articol)!"},{"id":"nb-506","type":"Lückentext","difficulty":"Mediu","question":"___ es regnet, gehe ich nicht aus. (daca)","options":null,"correctAnswer":"Wenn","explanationRomanian":"Subordonata prima cu 'wenn' + verb la sfarsit. Apoi V principal imediat dupa virgula."},{"id":"nb-507","type":"Lückentext","difficulty":"Greu","question":"Er ist mude, ___ er gut geschlafen hat. (desi)","options":null,"correctAnswer":"obwohl","explanationRomanian":"obwohl + ... + auxiliar 'hat' la sfarsit (Perfekt: gut geschlafen hat)."},{"id":"nb-508","type":"Multiple Choice","difficulty":"Usor","question":"Care arata o CAUZA?","options":["weil","dass","wenn","obwohl"],"correctAnswer":"weil","explanationRomanian":"weil = deoarece (cauza). dass = ca; wenn = cand; obwohl = desi."},{"id":"nb-509","type":"Multiple Choice","difficulty":"Mediu","question":"Care arata UN SCOP (ca sa)?","options":["weil","damit","wenn","obwohl"],"correctAnswer":"damit","explanationRomanian":"damit = ca sa (scop). Cere subiecte diferite sau modal."},{"id":"nb-510","type":"Multiple Choice","difficulty":"Usor","question":"In subordonata, verbul conjugat merge:","options":["pe pozitia 1","pe pozitia 2","imediat dupa subiect","la sfarsit"],"correctAnswer":"la sfarsit","explanationRomanian":"REGULA DE AUR: in TOATE subordonatele verbul conjugat la SFARSIT."},{"id":"nb-511","type":"Multiple Choice","difficulty":"Mediu","question":"Care e CORECT? 'Stau acasa pentru ca sunt bolnav.'","options":["Ich bleibe, weil ich krank bin","Ich bleibe, weil bin ich krank","Ich bleibe, weil ich bin krank","Ich bleibe, denn ich bin krank"],"correctAnswer":"Ich bleibe, weil ich krank bin","explanationRomanian":"weil + S + V la sfarsit. NOTA: 'denn' (caci) NU e subordonata, are alta topica."},{"id":"nb-512","type":"Multiple Choice","difficulty":"Greu","question":"Care e diferenta wenn vs als?","options":["nu exista diferenta","wenn = repetat/viitor, als = o data in trecut","wenn = trecut, als = viitor","wenn = formal, als = informal"],"correctAnswer":"wenn = repetat/viitor, als = o data in trecut","explanationRomanian":"'als ich Kind war' (cand eram copil - o singura data). 'wenn ich Zeit habe' (cand am timp - posibil repetat)."},{"id":"nb-513","type":"Multiple Choice","difficulty":"Greu","question":"Cu Perfekt, auxiliarul merge:","options":["pe poz. 2","inainte de Partizip","la sfarsit dupa Partizip","in mijloc"],"correctAnswer":"la sfarsit dupa Partizip","explanationRomanian":"Ex: 'weil ich gestern gearbeitet habe' - habe la sfarsit absolut."},{"id":"nb-514","type":"Multiple Choice","difficulty":"Mediu","question":"Subordonata prima -> verbul principal vine:","options":["la sfarsit","imediat dupa virgula","pe poz. 3","dupa subiect"],"correctAnswer":"imediat dupa virgula","explanationRomanian":"Wenn es regnet, BLEIBE ich. - V principal imediat dupa virgula (inversiune)."},{"id":"nb-515","type":"Multiple Choice","difficulty":"Mediu","question":"Care e GRESIT?","options":["Ich denke, dass er kommt","Ich denke, dass kommt er","Ich denke, dass er morgen kommt","Ich denke, dass er gut spricht"],"correctAnswer":"Ich denke, dass kommt er","explanationRomanian":"Verbul 'kommt' trebuie la SFARSIT, nu imediat dupa 'dass'."},{"id":"nb-516","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["weil","Ich bleibe zu Hause,","ich","bin","krank"],"correctAnswer":"Ich bleibe zu Hause, weil ich krank bin","explanationRomanian":"weil + S + adj/complement + V la sfarsit (bin). Topica: weil ich krank bin."},{"id":"nb-517","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["Zeit","Ich rufe dich an,","wenn","ich","habe"],"correctAnswer":"Ich rufe dich an, wenn ich Zeit habe","explanationRomanian":"wenn + S + obiect + V la sfarsit (habe). 'Zeit haben' = a avea timp."},{"id":"nb-518","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["er","dass","kommt","Ich glaube,","morgen"],"correctAnswer":"Ich glaube, dass er morgen kommt","explanationRomanian":"dass + S + adverb temporal + V la sfarsit (kommt)."},{"id":"nb-519","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["sie","obwohl","Sie kommt,","muede","ist"],"correctAnswer":"Sie kommt, obwohl sie muede ist","explanationRomanian":"obwohl + S + adj + V la sfarsit (ist)."},{"id":"nb-520","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza cuvintele:","options":["regnet,","ich","es","Wenn","bleibe","zu","Hause"],"correctAnswer":"Wenn es regnet, bleibe ich zu Hause","explanationRomanian":"Subordonata prima: Wenn + S + V (regnet) la sfarsit + virgula. Apoi V principal (bleibe) imediat dupa virgula. Inversiune: bleibe ich (V-S)."},{"id":"nb-521","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza cuvintele:","options":["habe,","viel","ich","muede","weil","Ich bin","gearbeitet"],"correctAnswer":"Ich bin muede, weil ich viel gearbeitet habe","explanationRomanian":"Cu Perfekt in subordonata: weil + S + complement + Partizip + auxiliar (habe) la SFARSIT absolut."},{"id":"nb-522","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich bleibe zu Hause, weil bin ich krank.\"","options":null,"correctAnswer":"Ich bleibe zu Hause, weil ich krank bin","explanationRomanian":"weil cere V la sfarsit. Forma corecta: weil + S + ... + V (bin) la final."},{"id":"nb-523","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich denke, dass er kommt morgen.\"","options":null,"correctAnswer":"Ich denke, dass er morgen kommt","explanationRomanian":"dass + V la SFARSIT. Adverbul 'morgen' inainte de verb."},{"id":"nb-524","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Scrie corect:\n\"Wenn ich Zeit habe, ich rufe dich an.\"","options":null,"correctAnswer":"Wenn ich Zeit habe, rufe ich dich an","explanationRomanian":"Subordonata prima -> inversiune in principala: V (rufe) + S (ich), nu S + V."},{"id":"nb-525","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Sie kommt, obwohl sie ist krank.\"","options":null,"correctAnswer":"Sie kommt, obwohl sie krank ist","explanationRomanian":"obwohl + S + complement + V la final (ist). Nu 'sie ist krank'."},{"id":"nb-526","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Scrie corect:\n\"Ich lerne, weil ich gut sprechen will Deutsch.\"","options":null,"correctAnswer":"Ich lerne, weil ich gut Deutsch sprechen will","explanationRomanian":"Cu modal in subordonata: complement + INFINITIV + MODAL la sfarsit absolut. 'sprechen will' la final."},{"id":"nb-527","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich bin muede, weil habe ich gearbeitet.\"","options":null,"correctAnswer":"Ich bin muede, weil ich gearbeitet habe","explanationRomanian":"Cu Perfekt in subordonata: S + Partizip + auxiliar (habe) la sfarsit absolut."},{"id":"nb-528","type":"Umformung","difficulty":"Mediu","question":"Combina cu 'weil':\n\"Ich gehe nicht aus. Es regnet.\"","options":null,"correctAnswer":"Ich gehe nicht aus, weil es regnet","explanationRomanian":"weil = a doua propozitie cu V la sfarsit. 'Es regnet' deja are V la sfarsit caci e scurt."},{"id":"nb-529","type":"Umformung","difficulty":"Mediu","question":"Combina cu 'dass':\n\"Sie sagt: Ich komme morgen.\"","options":null,"correctAnswer":"Sie sagt, dass sie morgen kommt","explanationRomanian":"dass + S (sie) + adverb (morgen) + V la sfarsit (kommt)."},{"id":"nb-530","type":"Umformung","difficulty":"Mediu","question":"Combina cu 'wenn':\n\"Ich rufe dich an. Ich habe Zeit.\"","options":null,"correctAnswer":"Ich rufe dich an, wenn ich Zeit habe","explanationRomanian":"wenn + S + obiect + V la final."},{"id":"nb-531","type":"Umformung","difficulty":"Greu","question":"Inverseaza ordinea (subordonata prima):\n\"Ich bleibe zu Hause, weil ich krank bin.\"","options":null,"correctAnswer":"Weil ich krank bin, bleibe ich zu Hause","explanationRomanian":"Subordonata prima -> V principal (bleibe) imediat dupa virgula + S (ich)."},{"id":"nb-532","type":"Umformung","difficulty":"Mediu","question":"Combina cu 'obwohl':\n\"Sie kommt. Sie ist muede.\"","options":null,"correctAnswer":"Sie kommt, obwohl sie muede ist","explanationRomanian":"obwohl + S + adj + V la final (ist)."},{"id":"nb-533","type":"Umformung","difficulty":"Greu","question":"Combina cu 'damit':\n\"Ich lerne. Ich will gut sprechen.\"","options":null,"correctAnswer":"Ich lerne, damit ich gut sprechen will","explanationRomanian":"damit + S + complement + INFINITIV + MODAL la final (sprechen will)."}]},{"id":"perfekt","level":"A2","category":"Verbe","title_de":"Perfekt (haben/sein + Partizip II)","title_ro":"Timpul Perfect","summary":"Timpul trecut cel mai folosit in germana vorbita. Format din auxiliar (haben/sein) + participiu trecut.","theory":"\n<h3>Formula generala</h3>\n<p class=\"gram-example\"><strong>Subiect + haben/sein (poz. 2) + ... + Partizip II (la sfarsit)</strong></p>\n<p>Exemplu: <em>Ich <strong>habe</strong> gestern Pizza <strong>gegessen</strong>.</em> (Am mancat pizza ieri.)</p>\n\n<h3>haben sau sein? -- regula simpla</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Folosesti SEIN cand...</th><th>Folosesti HABEN in rest</th></tr></thead>\n  <tbody>\n    <tr>\n      <td>\n        <ul>\n          <li>verb de <strong>miscare</strong> (gehen, fahren, kommen, fliegen, laufen, schwimmen)</li>\n          <li>verb de <strong>schimbare de stare</strong> (aufstehen, einschlafen, sterben, werden, aufwachen)</li>\n          <li><strong>sein</strong> insusi (ich bin gewesen)</li>\n          <li><strong>bleiben</strong> (a ramane), <strong>passieren</strong> (a se intampla)</li>\n        </ul>\n      </td>\n      <td>\n        Aproape toate celelalte verbe.<br>\n        Verbe tranzitive (cu obiect direct): essen, trinken, kaufen, sehen, lesen.<br>\n        Verbe modale: ich habe gemusst.<br>\n        Verbe reflexive: ich habe mich gefreut.\n      </td>\n    </tr>\n  </tbody>\n</table>\n\n<h3>Cum formez Partizip II?</h3>\n<h4>Verbe regulate (slabe): ge- + radacina + -t</h4>\n<ul>\n  <li>spielen -> <strong>gespielt</strong>: Ich habe Fussball gespielt.</li>\n  <li>kaufen -> <strong>gekauft</strong>: Ich habe Brot gekauft.</li>\n  <li>arbeiten -> <strong>gearbeitet</strong>: Ich habe gearbeitet.</li>\n</ul>\n\n<h4>Verbe neregulate (tari): ge- + radacina (modificata) + -en</h4>\n<p>Trebuie invatate pe de rost! Cele mai frecvente:</p>\n<table class=\"gram-table\">\n  <thead><tr><th>Infinitiv</th><th>Partizip II</th><th>Auxiliar</th></tr></thead>\n  <tbody>\n    <tr><td>gehen (a merge)</td><td>gegangen</td><td><strong>sein</strong></td></tr>\n    <tr><td>fahren (a calatori)</td><td>gefahren</td><td><strong>sein</strong></td></tr>\n    <tr><td>kommen (a veni)</td><td>gekommen</td><td><strong>sein</strong></td></tr>\n    <tr><td>essen (a manca)</td><td>gegessen</td><td>haben</td></tr>\n    <tr><td>trinken (a bea)</td><td>getrunken</td><td>haben</td></tr>\n    <tr><td>sehen (a vedea)</td><td>gesehen</td><td>haben</td></tr>\n    <tr><td>lesen (a citi)</td><td>gelesen</td><td>haben</td></tr>\n    <tr><td>sein (a fi)</td><td>gewesen</td><td><strong>sein</strong></td></tr>\n    <tr><td>haben (a avea)</td><td>gehabt</td><td>haben</td></tr>\n    <tr><td>schreiben</td><td>geschrieben</td><td>haben</td></tr>\n  </tbody>\n</table>\n\n<h4>Verbe cu prefixe inseparabile (be-, er-, ver-, ge-, ent-, emp-, zer-, miss-)</h4>\n<p>NU primesc \"ge-\": besuchen -> <strong>besucht</strong>, verstehen -> <strong>verstanden</strong>, bekommen -> <strong>bekommen</strong>.</p>\n\n<h4>Verbe terminate in -ieren</h4>\n<p>NU primesc \"ge-\": studieren -> <strong>studiert</strong>, telefonieren -> <strong>telefoniert</strong>.</p>\n\n<h3>Verbe separabile la Perfect</h3>\n<p>Prefixul ramane lipit de Partizip, iar \"ge-\" se baga intre prefix si radacina:</p>\n<ul>\n  <li>einkaufen -> <strong>eingekauft</strong>: Ich habe eingekauft.</li>\n  <li>aufstehen -> <strong>aufgestanden</strong>: Ich bin aufgestanden.</li>\n</ul>\n\n<div class=\"gram-tip\">\n<strong>Sfat:</strong> In germana vorbita, oamenii folosesc Perfekt pentru aproape orice trecut, chiar pentru \"yesterday I had breakfast\". Präteritum (ich ass = am mancat) e folosit mai mult la sein/haben/modale si in scris.\n</div>\n","exercises":[{"type":"fill","prompt":"Gestern ___ ich Pizza gegessen.","answer":"habe","hint":"essen = verb cu obiect = haben","explanation":"Pizza este obiect direct -> haben. Forma: ich habe gegessen."},{"type":"fill","prompt":"Ich ___ nach Berlin gefahren.","answer":"bin","hint":"fahren = miscare = sein","explanation":"fahren e verb de miscare -> sein. Forma: ich bin gefahren."},{"type":"transform","prompt":"Trecut: Ich kaufe Brot.","answer":"Ich habe Brot gekauft.","hint":"kaufen + haben + Partizip","explanation":"kaufen (regulat) -> gekauft. Cu haben."},{"type":"transform","prompt":"Trecut: Wir gehen ins Kino.","answer":"Wir sind ins Kino gegangen.","hint":"gehen = miscare = sein, neregulat","explanation":"gehen e neregulat -> gegangen. Cu sein (miscare)."},{"type":"choice","prompt":"Maria ___ gestern in Italien gewesen.","options":["hat","ist","war","hatte"],"answer":"ist","explanation":"Verbul 'sein' la Perfect ia tot 'sein' ca auxiliar: sie ist gewesen."},{"type":"fill","prompt":"Wir ___ einen Film gesehen.","answer":"haben","hint":"sehen + obiect direct = haben","explanation":"sehen + einen Film (Akk) -> haben. Forma: wir haben gesehen."},{"id":"pf-500","type":"Lückentext","difficulty":"Usor","question":"Gestern ___ ich Pizza gegessen.","options":null,"correctAnswer":"habe","explanationRomanian":"essen + haben. ich habe gegessen."},{"id":"pf-501","type":"Lückentext","difficulty":"Usor","question":"Wir ___ ins Kino gegangen.","options":null,"correctAnswer":"sind","explanationRomanian":"gehen = miscare -> sein. wir sind gegangen."},{"id":"pf-502","type":"Lückentext","difficulty":"Mediu","question":"Sie ___ ein Buch gelesen. (ea)","options":null,"correctAnswer":"hat","explanationRomanian":"lesen + haben (obiect direct). sie hat gelesen."},{"id":"pf-503","type":"Lückentext","difficulty":"Mediu","question":"Ich ___ in Italien gewesen.","options":null,"correctAnswer":"bin","explanationRomanian":"sein cu sein!: ich bin gewesen."},{"id":"pf-504","type":"Lückentext","difficulty":"Mediu","question":"Du ___ heute spät aufgestanden.","options":null,"correctAnswer":"bist","explanationRomanian":"aufstehen = schimbare stare -> sein."},{"id":"pf-505","type":"Lückentext","difficulty":"Mediu","question":"Ihr ___ den Film gesehen?","options":null,"correctAnswer":"habt","explanationRomanian":"sehen + haben (obiect direct)."},{"id":"pf-506","type":"Lückentext","difficulty":"Mediu","question":"Maria ___ nach Berlin gefahren.","options":null,"correctAnswer":"ist","explanationRomanian":"fahren = miscare -> sein."},{"id":"pf-507","type":"Lückentext","difficulty":"Greu","question":"Wir ___ uns gut amüsiert.","options":null,"correctAnswer":"haben","explanationRomanian":"Reflexive iau mereu haben (sich amüsieren)."},{"id":"pf-508","type":"Multiple Choice","difficulty":"Usor","question":"Care verb foloseste 'sein' la Perfekt?","options":["essen","kaufen","gehen","lesen"],"correctAnswer":"gehen","explanationRomanian":"gehen = miscare -> sein. Celelalte cu obiect direct -> haben."},{"id":"pf-509","type":"Multiple Choice","difficulty":"Usor","question":"Care verb foloseste 'haben' la Perfekt?","options":["fahren","kommen","trinken","aufstehen"],"correctAnswer":"trinken","explanationRomanian":"trinken cu obiect direct -> haben. Celelalte sunt miscare/schimbare stare -> sein."},{"id":"pf-510","type":"Multiple Choice","difficulty":"Mediu","question":"Partizip de la 'gehen':","options":["gehte","gegehen","gegangen","gegehnt"],"correctAnswer":"gegangen","explanationRomanian":"gehen e neregulat -> gegangen."},{"id":"pf-511","type":"Multiple Choice","difficulty":"Usor","question":"Partizip de la 'spielen':","options":["spielte","gespielt","gespielen","spiel"],"correctAnswer":"gespielt","explanationRomanian":"spielen e regulat -> ge + spiel + t = gespielt."},{"id":"pf-512","type":"Multiple Choice","difficulty":"Mediu","question":"Partizip de la 'studieren':","options":["gestudiert","studiert","studierte","gestuden"],"correctAnswer":"studiert","explanationRomanian":"Verbele in -ieren NU primesc 'ge-': studieren -> studiert."},{"id":"pf-513","type":"Multiple Choice","difficulty":"Mediu","question":"Partizip de la 'besuchen':","options":["gebesucht","besucht","besuchte","besucht-ge"],"correctAnswer":"besucht","explanationRomanian":"Prefixul inseparabil 'be-' nu permite 'ge-': besuchen -> besucht."},{"id":"pf-514","type":"Multiple Choice","difficulty":"Mediu","question":"'Maria a venit ieri' =","options":["Maria hat gestern gekommen","Maria ist gestern gekommen","Maria kommt gestern","Maria kam gestern"],"correctAnswer":"Maria ist gestern gekommen","explanationRomanian":"kommen = miscare -> sein."},{"id":"pf-515","type":"Multiple Choice","difficulty":"Usor","question":"La Perfekt, auxiliarul (haben/sein) merge:","options":["la sfarsit","pe poz. 1","pe poz. 2","imediat dupa Partizip"],"correctAnswer":"pe poz. 2","explanationRomanian":"Auxiliar pe poz. 2 + Partizip la SFARSITUL absolut."},{"id":"pf-516","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["habe","Pizza","gegessen","Ich"],"correctAnswer":"Ich habe Pizza gegessen","explanationRomanian":"Aux + obiect + Partizip."},{"id":"pf-517","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["bin","ich","Gestern","Berlin","gefahren","nach"],"correctAnswer":"Gestern bin ich nach Berlin gefahren","explanationRomanian":"Inversiune cu adverb temporal: adv + aux + S + complement + Partizip."},{"id":"pf-518","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["habt","Film","den","Ihr","gesehen","?"],"correctAnswer":"Habt ihr den Film gesehen","explanationRomanian":"Intrebare: aux + S + Akk + Partizip."},{"id":"pf-519","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["hat","ein","geschrieben","Sie","Buch"],"correctAnswer":"Sie hat ein Buch geschrieben","explanationRomanian":"S + aux + Akk + Partizip."},{"id":"pf-520","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["sind","in","gewesen","Wir","Italien"],"correctAnswer":"Wir sind in Italien gewesen","explanationRomanian":"sein cu sein! aux 'sind' + complement + 'gewesen'."},{"id":"pf-521","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["habe","uns","gut","wir","amüsiert"],"correctAnswer":"Wir haben uns gut amüsiert","explanationRomanian":"Reflexive: aux 'haben' + reflexiv + adv + Partizip."},{"id":"pf-522","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich habe nach Berlin gefahren.\"","options":null,"correctAnswer":"Ich bin nach Berlin gefahren","explanationRomanian":"fahren = miscare -> sein, nu haben."},{"id":"pf-523","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Wir sind Pizza gegessen.\"","options":null,"correctAnswer":"Wir haben Pizza gegessen","explanationRomanian":"essen + obiect direct -> haben."},{"id":"pf-524","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Sie ist ein Buch gelesen.\"","options":null,"correctAnswer":"Sie hat ein Buch gelesen","explanationRomanian":"lesen + obiect direct -> haben."},{"id":"pf-525","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich habe gestudiert.\"","options":null,"correctAnswer":"Ich habe studiert","explanationRomanian":"Verbe in -ieren nu primesc 'ge-': studiert (fara ge)."},{"id":"pf-526","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Maria hat aufgestanden.\"","options":null,"correctAnswer":"Maria ist aufgestanden","explanationRomanian":"aufstehen = schimbare stare -> sein."},{"id":"pf-527","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Ich habe gegegangen.\"","options":null,"correctAnswer":"Ich bin gegangen","explanationRomanian":"Partizip de la gehen e 'gegangen' (nu 'gegegangen'). Si miscare = sein."},{"id":"pf-528","type":"Umformung","difficulty":"Usor","question":"Pune la Perfekt:\n\"Ich kaufe Brot.\"","options":null,"correctAnswer":"Ich habe Brot gekauft","explanationRomanian":"kaufen + haben. Partizip: gekauft."},{"id":"pf-529","type":"Umformung","difficulty":"Mediu","question":"Pune la Perfekt:\n\"Wir gehen ins Kino.\"","options":null,"correctAnswer":"Wir sind ins Kino gegangen","explanationRomanian":"gehen + sein. Partizip: gegangen."},{"id":"pf-530","type":"Umformung","difficulty":"Mediu","question":"Pune la Perfekt:\n\"Sie liest ein Buch.\"","options":null,"correctAnswer":"Sie hat ein Buch gelesen","explanationRomanian":"lesen e neregulat -> gelesen + haben."},{"id":"pf-531","type":"Umformung","difficulty":"Greu","question":"Pune la Perfekt:\n\"Ich stehe um 7 auf.\"","options":null,"correctAnswer":"Ich bin um 7 aufgestanden","explanationRomanian":"aufstehen + sein. Partizip: aufgestanden."},{"id":"pf-532","type":"Umformung","difficulty":"Mediu","question":"Pune la Perfekt:\n\"Sie reist nach Italien.\"","options":null,"correctAnswer":"Sie ist nach Italien gereist","explanationRomanian":"reisen e regulat dar miscare -> sein. Partizip: gereist."},{"id":"pf-533","type":"Umformung","difficulty":"Mediu","question":"Pune la Perfekt:\n\"Wir besuchen die Oma.\"","options":null,"correctAnswer":"Wir haben die Oma besucht","explanationRomanian":"besuchen + haben. Partizip: besucht (be- nu primeste ge-)."}]},{"id":"reflexive","level":"A2","category":"Verbe","title_de":"Reflexive Verben","title_ro":"Verbe reflexive (sich)","summary":"Verbe care au pronume reflexiv 'sich' (= pe sine, isi). Pronumele se schimba cu fiecare persoana.","theory":"\n<h3>Ce sunt verbele reflexive?</h3>\n<p>Verbe care exprima ca actiunea se intoarce catre subiect. In dictionar apar cu <strong>sich</strong>:</p>\n<ul>\n  <li><strong>sich freuen</strong> = a se bucura</li>\n  <li><strong>sich waschen</strong> = a se spala</li>\n  <li><strong>sich anziehen</strong> = a se imbraca</li>\n  <li><strong>sich treffen</strong> = a se intalni</li>\n  <li><strong>sich erinnern</strong> = a-si aminti</li>\n  <li><strong>sich beeilen</strong> = a se grabi</li>\n</ul>\n\n<h3>Pronumele reflexiv -- la Akkusativ</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Persoana</th><th>Pronume reflexiv</th></tr></thead>\n  <tbody>\n    <tr><td>ich</td><td><strong>mich</strong></td></tr>\n    <tr><td>du</td><td><strong>dich</strong></td></tr>\n    <tr><td>er/sie/es</td><td><strong>sich</strong></td></tr>\n    <tr><td>wir</td><td><strong>uns</strong></td></tr>\n    <tr><td>ihr</td><td><strong>euch</strong></td></tr>\n    <tr><td>sie/Sie</td><td><strong>sich</strong></td></tr>\n  </tbody>\n</table>\n\n<h3>Pozitia in propozitie</h3>\n<p>Pronumele reflexiv vine <strong>imediat dupa verbul conjugat</strong>:</p>\n<p class=\"gram-example\">Ich freue <strong>mich</strong> sehr.<br>(Ma bucur foarte mult.)</p>\n<p class=\"gram-example\">Wir treffen <strong>uns</strong> um 19 Uhr.<br>(Ne intalnim la ora 19.)</p>\n\n<h3>Conjugare completa: sich freuen</h3>\n<table class=\"gram-table\">\n  <tbody>\n    <tr><td>ich freue mich</td><td>ma bucur</td></tr>\n    <tr><td>du freust dich</td><td>te bucuri</td></tr>\n    <tr><td>er/sie/es freut sich</td><td>se bucura</td></tr>\n    <tr><td>wir freuen uns</td><td>ne bucuram</td></tr>\n    <tr><td>ihr freut euch</td><td>va bucurati</td></tr>\n    <tr><td>sie/Sie freuen sich</td><td>se bucura</td></tr>\n  </tbody>\n</table>\n\n<h3>La Perfekt</h3>\n<p>Verbele reflexive folosesc <strong>haben</strong> ca auxiliar, iar pronumele reflexiv vine inainte:</p>\n<p class=\"gram-example\">Ich <strong>habe mich</strong> gefreut. (M-am bucurat.)<br>\nDu <strong>hast dich</strong> gewaschen. (Te-ai spalat.)</p>\n\n<h3>Reflexiv la Dativ -- partile corpului</h3>\n<p>Cand spalam o parte din corp (\"imi spal mainile\"), folosim Dativ + obiect direct la Akk:</p>\n<p class=\"gram-example\">Ich wasche <strong>mir</strong> (Dat.) <strong>die Hände</strong> (Akk.).<br>(Imi spal mainile.)</p>\n<p>Pronumele reflexiv la Dativ: mir, dir, sich, uns, euch, sich.</p>\n\n<div class=\"gram-tip\">\n<strong>Sfat:</strong> in romana spunem \"ma bucur\" cu un cuvant + pronume. In germana e identic ca structura, doar ca scrii \"ich freue mich\" -- gandeste-te ca \"mich\" inseamna \"(pe) mine\".\n</div>\n","exercises":[{"type":"fill","prompt":"Ich freue ___ auf das Wochenende.","answer":"mich","hint":"ich + reflexiv Akk","explanation":"ich -> mich. (Ma bucur de weekend.)"},{"type":"fill","prompt":"Wir treffen ___ um 18 Uhr.","answer":"uns","hint":"wir + reflexiv","explanation":"wir -> uns. (Ne intalnim la 18.)"},{"type":"choice","prompt":"Er erinnert ___ an die Reise.","options":["mich","dich","sich","uns"],"answer":"sich","explanation":"er/sie/es -> sich. (El isi aminteste de calatorie.)"},{"type":"fill","prompt":"Ihr beeilt ___, der Bus kommt!","answer":"euch","hint":"ihr + reflexiv","explanation":"ihr -> euch. (Va grabiti, vine autobuzul!)"},{"type":"transform","prompt":"Trecut (Perfekt): Ich freue mich.","answer":"Ich habe mich gefreut.","hint":"haben + mich + gefreut","explanation":"Reflexive iau 'haben'. Forma: subiect + haben + reflexiv + Partizip."},{"type":"fill","prompt":"Du wäschst ___ die Hände.","answer":"dir","hint":"Dativ! pentru ca die Hände e obiect direct","explanation":"Cand obiectul direct (Hände) e prezent, reflexivul merge la Dativ: du -> dir."},{"id":"re-300","type":"Lückentext","difficulty":"Usor","question":"Ich freue ___ auf das Wochenende.","options":null,"correctAnswer":"mich","explanationRomanian":"ich + reflexiv Akk -> mich."},{"id":"re-301","type":"Lückentext","difficulty":"Usor","question":"Wir treffen ___ um 18 Uhr.","options":null,"correctAnswer":"uns","explanationRomanian":"wir + reflexiv -> uns."},{"id":"re-302","type":"Lückentext","difficulty":"Mediu","question":"Er erinnert ___ an die Reise.","options":null,"correctAnswer":"sich","explanationRomanian":"er/sie/es -> sich."},{"id":"re-303","type":"Lückentext","difficulty":"Usor","question":"Ihr beeilt ___ , der Bus kommt!","options":null,"correctAnswer":"euch","explanationRomanian":"ihr -> euch."},{"id":"re-304","type":"Lückentext","difficulty":"Mediu","question":"Du wäschst ___ jeden Morgen.","options":null,"correctAnswer":"dich","explanationRomanian":"du + reflexiv Akk -> dich."},{"id":"re-305","type":"Lückentext","difficulty":"Greu","question":"Du wäschst ___ die Hände. (parti din corp)","options":null,"correctAnswer":"dir","explanationRomanian":"Cu obiect direct (Hände): reflexiv Dat -> dir."},{"id":"re-306","type":"Lückentext","difficulty":"Mediu","question":"Sie kümmert ___ um ihre Kinder.","options":null,"correctAnswer":"sich","explanationRomanian":"ea + reflexiv -> sich."},{"id":"re-307","type":"Lückentext","difficulty":"Greu","question":"Ich putze ___ die Zähne. (imi periez dintii)","options":null,"correctAnswer":"mir","explanationRomanian":"Parti din corp + obiect Akk: reflexiv Dat -> mir."},{"id":"re-308","type":"Multiple Choice","difficulty":"Usor","question":"Care e reflexiv pentru 'ei se bucura'?","options":["sich freuen","mich freuen","ihn freuen","sie freuen"],"correctAnswer":"sich freuen","explanationRomanian":"ei (sie pl.) -> sich (la fel ca pers. 3 sg)."},{"id":"re-309","type":"Multiple Choice","difficulty":"Mediu","question":"Wir ___ um 19 Uhr. (a se intalni)","options":["sehen","treffen uns","treffen","treffen sich"],"correctAnswer":"treffen uns","explanationRomanian":"wir + reflexiv = treffen uns. 'sich treffen' = a se intalni."},{"id":"re-310","type":"Multiple Choice","difficulty":"Greu","question":"Cand pronumele reflexiv merge la Dativ?","options":["niciodata","cand verbul cere Dativ","cand exista obiect direct cu Akk","doar la pers. 1"],"correctAnswer":"cand exista obiect direct cu Akk","explanationRomanian":"Ex: 'ich wasche mich' (Akk) vs 'ich wasche mir die Hände' (Dat + Akk obiect)."},{"id":"re-311","type":"Multiple Choice","difficulty":"Usor","question":"Care e reflexiv corect pentru ihr (voi)?","options":["uns","euch","sich","dich"],"correctAnswer":"euch","explanationRomanian":"ihr -> euch (atat la Akk cat si la Dat)."},{"id":"re-312","type":"Multiple Choice","difficulty":"Mediu","question":"Cum se zice 'eu ma bucur' la Perfekt?","options":["Ich bin gefreut","Ich habe gefreut","Ich habe mich gefreut","Ich bin mich gefreut"],"correctAnswer":"Ich habe mich gefreut","explanationRomanian":"Reflexive iau auxiliarul 'haben'. Schema: ich habe + reflexiv + Partizip."},{"id":"re-313","type":"Multiple Choice","difficulty":"Mediu","question":"Pozitia reflexivului in propozitie:","options":["la inceput","imediat dupa verbul conjugat","la sfarsit","in fata verbului"],"correctAnswer":"imediat dupa verbul conjugat","explanationRomanian":"Pronumele reflexiv vine imediat dupa verbul conjugat."},{"id":"re-314","type":"Multiple Choice","difficulty":"Usor","question":"Care verb NU e reflexiv?","options":["sich freuen","sich erinnern","gehen","sich treffen"],"correctAnswer":"gehen","explanationRomanian":"gehen = a merge (nereflexiv). Celelalte au 'sich' obligatoriu."},{"id":"re-315","type":"Multiple Choice","difficulty":"Greu","question":"Hör ___ , der Lehrer spricht!","options":["zu","auf","dich zu","dir zu"],"correctAnswer":"auf","explanationRomanian":"'aufhören' = a inceta. Aici: 'hör auf' = inceteaza (imperativ). NOTA: nu e reflexiv aici."},{"id":"re-316","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["mich","Ich","freue"],"correctAnswer":"Ich freue mich","explanationRomanian":"S + V + reflexiv (mich)."},{"id":"re-317","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["uns","treffen","wir","morgen"],"correctAnswer":"Wir treffen uns morgen","explanationRomanian":"S + V + reflexiv + adverb."},{"id":"re-318","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["dich","Du","im","duschst","Bad"],"correctAnswer":"Du duschst dich im Bad","explanationRomanian":"S + V + reflexiv + complement loc."},{"id":"re-319","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["sich","Sie","Reise","an","die","erinnert"],"correctAnswer":"Sie erinnert sich an die Reise","explanationRomanian":"S + V + reflexiv (sich) + an + Akk."},{"id":"re-320","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["mir","die","wasche","Hände","Ich"],"correctAnswer":"Ich wasche mir die Hände","explanationRomanian":"S + V + reflexiv Dat (mir) + obiect Akk (die Hände)."},{"id":"re-321","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["euch","Beeilt","!"],"correctAnswer":"Beeilt euch","explanationRomanian":"Imperativ: V + reflexiv (euch pentru ihr)."},{"id":"re-322","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich freue mir auf das Wochenende.\"","options":null,"correctAnswer":"Ich freue mich auf das Wochenende","explanationRomanian":"ich + reflexiv Akk = mich (nu mir). 'sich freuen' cere Akk."},{"id":"re-323","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Wir treffen sich um 19 Uhr.\"","options":null,"correctAnswer":"Wir treffen uns um 19 Uhr","explanationRomanian":"wir + reflexiv = uns (nu sich)."},{"id":"re-324","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Er ist sich gefreut.\"","options":null,"correctAnswer":"Er hat sich gefreut","explanationRomanian":"Reflexive iau 'haben', nu 'sein'."},{"id":"re-325","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Ich wasche mich die Hände.\"","options":null,"correctAnswer":"Ich wasche mir die Hände","explanationRomanian":"Cu obiect direct (Hände) -> reflexiv la Dativ (mir)."},{"id":"re-326","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Sie kümmert ihre Kinder.\"","options":null,"correctAnswer":"Sie kümmert sich um ihre Kinder","explanationRomanian":"'kümmern' e mereu reflexiv. Lipseste 'sich um'."},{"id":"re-327","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ihr beeilt sich!\"","options":null,"correctAnswer":"Ihr beeilt euch","explanationRomanian":"ihr + reflexiv = euch (nu sich)."},{"id":"re-328","type":"Umformung","difficulty":"Mediu","question":"Pune la Perfekt:\n\"Ich freue mich.\"","options":null,"correctAnswer":"Ich habe mich gefreut","explanationRomanian":"Reflexive: haben + reflexiv + Partizip la sfarsit."},{"id":"re-329","type":"Umformung","difficulty":"Mediu","question":"Pune la Perfekt:\n\"Wir treffen uns.\"","options":null,"correctAnswer":"Wir haben uns getroffen","explanationRomanian":"treffen e neregulat -> Partizip 'getroffen'."},{"id":"re-330","type":"Umformung","difficulty":"Mediu","question":"Schimba la pers. 3 sg.:\n\"Ich erinnere mich an die Schule.\"","options":null,"correctAnswer":"Sie erinnert sich an die Schule","explanationRomanian":"ich -> sie; mich -> sich."},{"id":"re-331","type":"Umformung","difficulty":"Mediu","question":"Schimba la imperativ (du):\n\"Du beeilst dich.\"","options":null,"correctAnswer":"Beeil dich","explanationRomanian":"Imperativ du: forma fara terminatie. dich ramane."},{"id":"re-332","type":"Umformung","difficulty":"Mediu","question":"Schimba la formal (Sie):\n\"Setz dich!\"","options":null,"correctAnswer":"Setzen Sie sich","explanationRomanian":"Imperativ formal: V infinitiv + Sie + reflexiv (sich)."},{"id":"re-333","type":"Umformung","difficulty":"Mediu","question":"Adauga reflexivul:\n\"Ich wasche jeden Morgen.\"","options":null,"correctAnswer":"Ich wasche mich jeden Morgen","explanationRomanian":"'sich waschen' = a se spala. reflexiv 'mich' dupa V."}]},{"id":"trennbare","level":"A2","category":"Verbe","title_de":"Trennbare Verben","title_ro":"Verbe separabile","summary":"Verbe cu prefix care 'se desprinde' la prezent si Imperfekt, dar revine la sfarsitul propozitiei.","theory":"\n<h3>Ce sunt verbele separabile?</h3>\n<p>Verbe germane formate dintr-un prefix + verb baza. La prezent, prefixul se DESPRINDE si zboara la sfarsit:</p>\n<p class=\"gram-example\">Infinitiv: <strong>ein</strong>kaufen (a face cumparaturi)<br>\nConjugat: Ich <strong>kaufe</strong> jeden Tag <strong>ein</strong>. (Fac cumparaturi in fiecare zi.)</p>\n\n<h3>Cele mai frecvente prefixe separabile</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Prefix</th><th>Sens</th><th>Exemplu</th></tr></thead>\n  <tbody>\n    <tr><td><strong>an-</strong></td><td>spre, la</td><td>anrufen (a suna), ankommen (a sosi)</td></tr>\n    <tr><td><strong>auf-</strong></td><td>sus, deschis</td><td>aufstehen (a se ridica), aufmachen (a deschide)</td></tr>\n    <tr><td><strong>aus-</strong></td><td>din, afara</td><td>ausgehen (a iesi), ausziehen (a se dezbraca)</td></tr>\n    <tr><td><strong>ein-</strong></td><td>in, inauntru</td><td>einkaufen, einsteigen (a urca in)</td></tr>\n    <tr><td><strong>mit-</strong></td><td>impreuna</td><td>mitkommen (a veni cu), mitnehmen (a lua cu)</td></tr>\n    <tr><td><strong>weg-</strong></td><td>departe</td><td>weggehen (a pleca), wegfahren</td></tr>\n    <tr><td><strong>zurück-</strong></td><td>inapoi</td><td>zurückkommen (a se intoarce)</td></tr>\n    <tr><td><strong>fern-</strong></td><td>departe</td><td>fernsehen (a se uita la TV)</td></tr>\n  </tbody>\n</table>\n\n<h3>Cum stiu ca un prefix e separabil?</h3>\n<p>Regula: <strong>daca accentul cade pe prefix, e separabil</strong>. <em>'AN</em>rufen, <em>'EIN</em>kaufen, <em>'AUF</em>stehen.</p>\n<p>Inseparabile (NU se separa): be-, er-, ver-, ge-, ent-, emp-, zer-, miss-. Aici accentul cade pe radacina: be<em>'SU</em>chen.</p>\n\n<h3>Cele 4 contexte cu schimbari diferite</h3>\n\n<h4>1. Prezent (separat)</h4>\n<p class=\"gram-example\">Ich <strong>rufe</strong> dich morgen <strong>an</strong>. (Te sun maine.)</p>\n\n<h4>2. Cu verb modal (NEseparat, la sfarsit)</h4>\n<p class=\"gram-example\">Ich muss morgen früh <strong>aufstehen</strong>. (Trebuie sa ma scol devreme maine.)</p>\n<p>Cu modal, infinitivul ramane intreg la sfarsit.</p>\n\n<h4>3. Perfekt (Partizip II are 'ge' la mijloc)</h4>\n<p class=\"gram-example\">Ich habe gestern <strong>eingekauft</strong>. (Am facut cumparaturi ieri.)</p>\n<p>einkaufen -> ein + ge + kauf + t = eingekauft.</p>\n\n<h4>4. Subordonata (NEseparat la sfarsit)</h4>\n<p class=\"gram-example\">Ich glaube, dass er morgen <strong>ankommt</strong>.<br>(Cred ca soseste maine.)</p>\n\n<div class=\"gram-tip\">\n<strong>Mnemonic:</strong> \"ein-kauf-ein\" -- prefixul ein se desparte si zboara la sfarsit ca un boomerang. La Perfekt se reuneste in 'eingekauft'.\n</div>\n","exercises":[{"type":"transform","prompt":"Conjuga la prezent: anrufen / ich / dich","answer":"Ich rufe dich an","hint":"prefixul 'an' la sfarsit","explanation":"anrufen -> ich rufe ... an. Prefixul zboara la final."},{"type":"fill","prompt":"Ich ___ jeden Morgen um 7 Uhr ___ . (aufstehen)","answer":"stehe ... auf","hint":"doua parti","explanation":"aufstehen -> ich stehe auf. Verbul se desparte la prezent."},{"type":"transform","prompt":"Perfekt: Ich kaufe ein.","answer":"Ich habe eingekauft.","hint":"ein + ge + kauft","explanation":"Verb separabil la Perfekt: prefixul + ge + radacina + t = eingekauft."},{"type":"fill","prompt":"Wann ___ der Zug ___? (ankommen - sosi)","answer":"kommt ... an","hint":"intrebare cu prefix la sfarsit","explanation":"Wann kommt der Zug an? La intrebare verbul e pe pozitia 1, prefixul la sfarsit."},{"type":"choice","prompt":"Ich muss morgen früh ___.","options":["stehe auf","aufstehen","stand auf","aufgestanden"],"answer":"aufstehen","explanation":"Cu verb modal (muss), verbul principal ramane infinitiv intreg la sfarsit."},{"type":"order","prompt":"Ordoneaza: an / die / Tür / mache / ich","answer":"Ich mache die Tür an","hint":"prefixul la sfarsit","explanation":"Subiect + verb + obiect + prefix. Note: aufmachen e mai natural pentru deschis usa, aici e doar exercitiu."},{"id":"tr-400","type":"Lückentext","difficulty":"Usor","question":"Ich ___ jeden Morgen um 7 Uhr ___ . (aufstehen)","options":null,"correctAnswer":"stehe ... auf","explanationRomanian":"aufstehen -> ich stehe ... auf. Prefixul la sfarsit la prezent."},{"id":"tr-401","type":"Lückentext","difficulty":"Usor","question":"Ich ___ heute ___ . (einkaufen)","options":null,"correctAnswer":"kaufe ... ein","explanationRomanian":"einkaufen -> kaufe ... ein."},{"id":"tr-402","type":"Lückentext","difficulty":"Mediu","question":"Wann ___ der Zug ___ ? (ankommen)","options":null,"correctAnswer":"kommt ... an","explanationRomanian":"ankommen -> kommt ... an. Intrebare cu prefix la sfarsit."},{"id":"tr-403","type":"Lückentext","difficulty":"Usor","question":"Ich ___ dich morgen ___ . (anrufen)","options":null,"correctAnswer":"rufe ... an","explanationRomanian":"anrufen -> rufe ... an."},{"id":"tr-404","type":"Lückentext","difficulty":"Mediu","question":"Wir ___ um 22 Uhr ___ . (fernsehen)","options":null,"correctAnswer":"sehen ... fern","explanationRomanian":"fernsehen (a se uita la TV) -> sehen ... fern."},{"id":"tr-405","type":"Lückentext","difficulty":"Usor","question":"Mach bitte die Tür ___ ! (auf)","options":null,"correctAnswer":"auf","explanationRomanian":"aufmachen -> mach ... auf (imperativ)."},{"id":"tr-406","type":"Lückentext","difficulty":"Mediu","question":"Er ___ um 6 Uhr ___ . (aufwachen)","options":null,"correctAnswer":"wacht ... auf","explanationRomanian":"aufwachen -> wacht ... auf."},{"id":"tr-407","type":"Lückentext","difficulty":"Mediu","question":"Steigen wir hier ___ ? (einsteigen)","options":null,"correctAnswer":"ein","explanationRomanian":"einsteigen -> steigen ... ein. Aici e intrebare."},{"id":"tr-408","type":"Multiple Choice","difficulty":"Usor","question":"Care e prefix SEPARABIL?","options":["be-","an-","ver-","ge-"],"correctAnswer":"an-","explanationRomanian":"Separabile: an, auf, aus, ein, mit, vor, zu... Inseparabile: be, er, ver, ge, ent."},{"id":"tr-409","type":"Multiple Choice","difficulty":"Mediu","question":"Cu modal verb, prefixul:","options":["se desparte","ramane lipit (verbul stă infinitiv)","dispare","se dubleaza"],"correctAnswer":"ramane lipit (verbul stă infinitiv)","explanationRomanian":"Ex: 'Ich muss aufstehen' - infinitiv intreg la sfarsit."},{"id":"tr-410","type":"Multiple Choice","difficulty":"Mediu","question":"La Perfekt, 'einkaufen' devine:","options":["geeinkauft","eingekauft","kaufte ein","einekauft"],"correctAnswer":"eingekauft","explanationRomanian":"Pattern Perfekt separabil: prefix + ge + radacina + t = eingekauft."},{"id":"tr-411","type":"Multiple Choice","difficulty":"Usor","question":"Care e CORECT (prezent)?","options":["Ich aufrufe dich","Ich rufe dich an","Ich an rufe dich","Ich rufen an dich"],"correctAnswer":"Ich rufe dich an","explanationRomanian":"anrufen -> rufe ... an. Prefixul la sfarsit."},{"id":"tr-412","type":"Multiple Choice","difficulty":"Mediu","question":"Cu modal: 'trebuie sa ma scol' =","options":["Ich aufstehe muss","Ich muss aufstehen","Ich muss stehe auf","Ich stehe auf muss"],"correctAnswer":"Ich muss aufstehen","explanationRomanian":"Modal pe poz.2 + INFINITIV intreg la sfarsit (aufstehen, NU separat)."},{"id":"tr-413","type":"Multiple Choice","difficulty":"Mediu","question":"In subordonata, verbul separabil:","options":["se desparte","ramane intreg la sfarsit","vine pe poz. 2","dispare"],"correctAnswer":"ramane intreg la sfarsit","explanationRomanian":"Ex: 'weil ich aufstehe' - aufstehen ramane intreg la sfarsit."},{"id":"tr-414","type":"Multiple Choice","difficulty":"Mediu","question":"Care prefix arata 'inapoi'?","options":["an-","auf-","zurück-","ein-"],"correctAnswer":"zurück-","explanationRomanian":"zurück = inapoi (zurückkommen, zurückfahren)."},{"id":"tr-415","type":"Multiple Choice","difficulty":"Mediu","question":"Imperativ 'deschide usa!' =","options":["Mach die Tür auf!","Aufmach die Tür!","Auf mach die Tür!","Mach auf die Tür!"],"correctAnswer":"Mach die Tür auf!","explanationRomanian":"Imperativ separabil: V + obiect + prefix la sfarsit."},{"id":"tr-416","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["um","Ich","stehe","7","auf"],"correctAnswer":"Ich stehe um 7 auf","explanationRomanian":"S + V + adv + prefix (auf) la sfarsit."},{"id":"tr-417","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["dich","rufe","morgen","Ich","an"],"correctAnswer":"Ich rufe dich morgen an","explanationRomanian":"S + V + Akk + adv + prefix la sfarsit."},{"id":"tr-418","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["aufstehen","muss","ich","morgen","fruh"],"correctAnswer":"Ich muss morgen fruh aufstehen","explanationRomanian":"Cu modal: V infinitiv intreg la sfarsit."},{"id":"tr-419","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["weil","Ich kann nicht,","fruh","ich","aufstehe"],"correctAnswer":"Ich kann nicht, weil ich fruh aufstehe","explanationRomanian":"Subordonata cu weil: V separabil ramane intreg la sfarsit."},{"id":"tr-420","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["habe","ich","Gestern","eingekauft"],"correctAnswer":"Gestern habe ich eingekauft","explanationRomanian":"Inversiune: adv + V + S + Partizip (eingekauft) la sfarsit."},{"id":"tr-421","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["aufgemacht","Sie","die","Tür","hat"],"correctAnswer":"Sie hat die Tür aufgemacht","explanationRomanian":"Perfekt separabil: hat + Akk + Partizip (aufgemacht) la sfarsit. ge intre prefix si radacina."},{"id":"tr-422","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich aufstehe um 7 Uhr.\"","options":null,"correctAnswer":"Ich stehe um 7 Uhr auf","explanationRomanian":"Verbul se desparte la prezent: stehe ... auf."},{"id":"tr-423","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Corect:\n\"Ich muss aufstehen morgen.\"","options":null,"correctAnswer":"Ich muss morgen aufstehen","explanationRomanian":"Cu modal, infinitivul (aufstehen) la SFARSIT absolut. Adverbul 'morgen' inainte."},{"id":"tr-424","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich habe geeinkauft.\"","options":null,"correctAnswer":"Ich habe eingekauft","explanationRomanian":"Perfekt separabil: ein-ge-kauf-t = eingekauft (nu 'geeinkauft')."},{"id":"tr-425","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich an dich rufe morgen.\"","options":null,"correctAnswer":"Ich rufe dich morgen an","explanationRomanian":"Pe pozitia 2 = verbul. Prefixul 'an' merge la SFARSIT."},{"id":"tr-426","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Wir fernsehen jetzt.\"","options":null,"correctAnswer":"Wir sehen jetzt fern","explanationRomanian":"fernsehen separat: sehen ... fern."},{"id":"tr-427","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Mach auf die Tür!\"","options":null,"correctAnswer":"Mach die Tür auf","explanationRomanian":"Imperativ: V + obiect + prefix la sfarsit. NU 'mach auf' (asta e cand obiectul lipseste)."},{"id":"tr-428","type":"Umformung","difficulty":"Usor","question":"Conjuga la prezent:\n\"einkaufen / wir / heute\"","options":null,"correctAnswer":"Wir kaufen heute ein","explanationRomanian":"wir kaufen ... ein."},{"id":"tr-429","type":"Umformung","difficulty":"Greu","question":"Pune la Perfekt:\n\"Ich stehe um 7 Uhr auf.\"","options":null,"correctAnswer":"Ich bin um 7 Uhr aufgestanden","explanationRomanian":"aufstehen e miscare/schimbare stare -> sein. Partizip: aufgestanden."},{"id":"tr-430","type":"Umformung","difficulty":"Mediu","question":"Pune la Perfekt:\n\"Ich kaufe heute ein.\"","options":null,"correctAnswer":"Ich habe heute eingekauft","explanationRomanian":"einkaufen + haben. Partizip: eingekauft."},{"id":"tr-431","type":"Umformung","difficulty":"Mediu","question":"Adauga modal 'muessen':\n\"Ich stehe fruh auf.\"","options":null,"correctAnswer":"Ich muss fruh aufstehen","explanationRomanian":"Cu modal: infinitivul intreg (aufstehen) la sfarsit. Prefixul reuneste."},{"id":"tr-432","type":"Umformung","difficulty":"Greu","question":"Pune in subordonata cu 'weil':\n\"Ich kann nicht. Ich rufe dich an.\"","options":null,"correctAnswer":"Ich kann nicht, weil ich dich anrufe","explanationRomanian":"weil + V separabil intreg la sfarsit (anrufe)."},{"id":"tr-433","type":"Umformung","difficulty":"Mediu","question":"Pune la imperativ (du):\n\"Du machst die Tür auf.\"","options":null,"correctAnswer":"Mach die Tür auf","explanationRomanian":"Imperativ: V (mach) + Akk + prefix (auf) la sfarsit."}]},{"id":"verben-praepositionen","level":"A2","category":"Verbe","title_de":"Verben mit Präpositionen","title_ro":"Verbe cu prepozitii fixe","summary":"75+ verbe care vin cu o prepozitie obligatorie (ex. denken AN, warten AUF, sich freuen ÜBER). Se invata ca unitati fixe.","theory":"\n<h3>Ce sunt verbele cu prepozitii fixe?</h3>\n<p>In germana, multe verbe vin cu o <strong>prepozitie obligatorie</strong> care nu se schimba. Aceasta combinatie verb + prepozitie functioneaza ca o unitate fixa si trebuie invatata <strong>impreuna</strong>, ca o singura \"felie\" de vocabular.</p>\n<p>Asemanator cu romana: zicem \"ma gandesc <em>la</em>\" (nu \"ma gandesc pe\"). In germana exista aceeasi logica, doar ca prepozitiile sunt diferite: <em>denken AN</em>, <em>warten AUF</em>, <em>sich freuen ÜBER</em>.</p>\n\n<div class=\"gram-tip\">\n<strong>Sfat de aur:</strong> NU traduce verbul si prepozitia separat. Inveti perechea ca o singura unitate. Cand auzi \"ma astept la\" -> \"rechnen <em>mit</em>\", \"ma plang de\" -> \"sich beschweren <em>über</em>\".\n</div>\n\n<h3>Cazul (Akkusativ vs Dativ)</h3>\n<p>Fiecare verb + prepozitie cere un anumit caz. Vestea buna: la A2, prioritatea e sa stii <strong>care prepozitie</strong> merge cu care verb. Cazul vine cu practica.</p>\n<p>Pattern util: prepozitiile <strong>aus, bei, mit, nach, von, zu</strong> cer mereu <strong>Dativ</strong>. Prepozitiile <strong>für, um, gegen</strong> cer mereu <strong>Akkusativ</strong>. Prepozitiile <strong>an, auf, in, über</strong> sunt Wechselpräpositionen (depinde de verb).</p>\n\n<h3>Cele mai importante perechi de retinut</h3>\n\n<h4>1. sich freuen AUF vs sich freuen ÜBER (a se bucura)</h4>\n<ul>\n  <li><strong>auf + Akk.</strong> = bucurie pentru ceva DIN VIITOR (abia astept). <em>\"Ich freue mich AUF den Urlaub.\"</em> (Abia astept vacanta.)</li>\n  <li><strong>über + Akk.</strong> = bucurie pentru ceva DEJA INTAMPLAT. <em>\"Ich freue mich ÜBER das Geschenk.\"</em> (Ma bucur de cadou.)</li>\n</ul>\n\n<h4>2. sprechen MIT vs sprechen ÜBER (a vorbi)</h4>\n<ul>\n  <li><strong>mit + Dat.</strong> = vorbesti CU CINEVA (persoana). <em>\"Ich spreche mit meinem Bruder.\"</em></li>\n  <li><strong>über + Akk.</strong> = vorbesti DESPRE CEVA (subiect). <em>\"Wir sprechen über das Wetter.\"</em></li>\n</ul>\n\n<h4>3. erzählen VON vs erzählen ÜBER (a povesti)</h4>\n<ul>\n  <li><strong>von + Dat.</strong> = ceva personal, amintiri. <em>\"Oma erzählt von früher.\"</em></li>\n  <li><strong>über + Akk.</strong> = subiect general, obiectiv. <em>\"Sie erzählt über ihre Arbeit.\"</em></li>\n</ul>\n\n<h4>4. danken FÜR vs sich bedanken BEI (a multumi)</h4>\n<ul>\n  <li><strong>danken FÜR + Akk.</strong> = multumesti PENTRU ceva (lucrul). <em>\"Ich danke dir für das Geschenk.\"</em></li>\n  <li><strong>sich bedanken BEI + Dat.</strong> = multumesti FATA DE cineva (persoana). <em>\"Ich bedanke mich bei dir.\"</em></li>\n</ul>\n\n<h4>5. kämpfen FÜR / UM / GEGEN (a lupta)</h4>\n<ul>\n  <li><strong>für + Akk.</strong> = pentru o cauza/idee. <em>\"kämpfen für die Freiheit\"</em></li>\n  <li><strong>um + Akk.</strong> = pentru a obtine ceva concret. <em>\"kämpfen um den ersten Platz\"</em></li>\n  <li><strong>gegen + Akk.</strong> = impotriva cuiva. <em>\"kämpfen gegen die Ungerechtigkeit\"</em></li>\n</ul>\n\n<h4>6. sich interessieren FÜR vs sich interessieren AN</h4>\n<ul>\n  <li><strong>für + Akk.</strong> = interes general (sport, muzica). Mai frecvent. <em>\"Ich interessiere mich für Musik.\"</em></li>\n  <li><strong>an + Dat.</strong> = interes specific. <em>\"Ich bin an diesem Auto interessiert.\"</em></li>\n</ul>\n\n<h4>7. bestehen AUS vs bestehen AUF (a fi compus / a insista)</h4>\n<ul>\n  <li><strong>aus + Dat.</strong> = a fi compus DIN. <em>\"Das Team besteht aus zehn Personen.\"</em></li>\n  <li><strong>auf + Dat.</strong> = a insista PE. <em>\"Er besteht auf seinem Recht.\"</em></li>\n</ul>\n\n<h4>8. sorgen FÜR vs sich sorgen UM (a avea grija / a fi ingrijorat)</h4>\n<ul>\n  <li><strong>für + Akk.</strong> = a se ingriji activ. <em>\"Ich sorge für meine Familie.\"</em></li>\n  <li><strong>sich sorgen + um + Akk.</strong> = a fi ingrijorat (anxios). <em>\"Ich sorge mich um dich.\"</em></li>\n</ul>\n\n<h3>Tabel de referinta - cele mai importante 30 verbe A2</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Verb</th><th>Prep.</th><th>Caz</th><th>Sens romana</th></tr></thead>\n  <tbody>\n    <tr><td>denken</td><td>an</td><td>Akk.</td><td>a se gandi la</td></tr>\n    <tr><td>sich erinnern</td><td>an</td><td>Akk.</td><td>a-si aminti de</td></tr>\n    <tr><td>sich gewöhnen</td><td>an</td><td>Akk.</td><td>a se obisnui cu</td></tr>\n    <tr><td>arbeiten</td><td>an</td><td>Dat.</td><td>a lucra la</td></tr>\n    <tr><td>teilnehmen</td><td>an</td><td>Dat.</td><td>a participa la</td></tr>\n    <tr><td>warten</td><td>auf</td><td>Akk.</td><td>a astepta</td></tr>\n    <tr><td>sich freuen</td><td>auf</td><td>Akk.</td><td>a abia astepta (viitor)</td></tr>\n    <tr><td>hoffen</td><td>auf</td><td>Akk.</td><td>a spera la</td></tr>\n    <tr><td>achten</td><td>auf</td><td>Akk.</td><td>a fi atent la</td></tr>\n    <tr><td>sich vorbereiten</td><td>auf</td><td>Akk.</td><td>a se pregati pentru</td></tr>\n    <tr><td>verzichten</td><td>auf</td><td>Akk.</td><td>a renunta la</td></tr>\n    <tr><td>bestehen</td><td>aus</td><td>Dat.</td><td>a fi compus din</td></tr>\n    <tr><td>helfen</td><td>bei</td><td>Dat.</td><td>a ajuta la</td></tr>\n    <tr><td>sich bedanken</td><td>bei</td><td>Dat.</td><td>a multumi (persoanei)</td></tr>\n    <tr><td>sich entschuldigen</td><td>bei</td><td>Dat.</td><td>a-si cere scuze fata de</td></tr>\n    <tr><td>danken</td><td>für</td><td>Akk.</td><td>a multumi pentru</td></tr>\n    <tr><td>sich interessieren</td><td>für</td><td>Akk.</td><td>a fi interesat de</td></tr>\n    <tr><td>sorgen</td><td>für</td><td>Akk.</td><td>a se ingriji de</td></tr>\n    <tr><td>sich entscheiden</td><td>für/gegen</td><td>Akk.</td><td>a se decide pt./impotriva</td></tr>\n    <tr><td>anfangen / aufhören</td><td>mit</td><td>Dat.</td><td>a incepe / termina cu</td></tr>\n    <tr><td>sprechen</td><td>mit / über</td><td>Dat./Akk.</td><td>a vorbi cu / despre</td></tr>\n    <tr><td>sich treffen</td><td>mit</td><td>Dat.</td><td>a se intalni cu</td></tr>\n    <tr><td>fragen</td><td>nach</td><td>Dat.</td><td>a intreba de</td></tr>\n    <tr><td>sich ärgern</td><td>über</td><td>Akk.</td><td>a se enerva din cauza</td></tr>\n    <tr><td>sich freuen</td><td>über</td><td>Akk.</td><td>a se bucura de (trecut)</td></tr>\n    <tr><td>bitten</td><td>um</td><td>Akk.</td><td>a ruga/cere</td></tr>\n    <tr><td>sich kümmern</td><td>um</td><td>Akk.</td><td>a se ocupa de</td></tr>\n    <tr><td>träumen</td><td>von</td><td>Dat.</td><td>a visa la</td></tr>\n    <tr><td>abhängen</td><td>von</td><td>Dat.</td><td>a depinde de</td></tr>\n    <tr><td>gratulieren</td><td>zu</td><td>Dat.</td><td>a felicita pentru</td></tr>\n  </tbody>\n</table>\n\n<h3>Strategii de invatare</h3>\n<ol>\n  <li><strong>Inveti pe perechi:</strong> nu memora \"denken\" si separat \"an\". Memoreaza \"denken AN\" ca o unitate.</li>\n  <li><strong>Concentreaza-te pe pereche-trucuri</strong> (cele 8 de mai sus) - acestea apar des in examene si conversatie.</li>\n  <li><strong>Foloseste in propozitii proprii:</strong> dupa ce inveti un verb, scrie 2-3 propozitii personale cu el.</li>\n  <li><strong>Repetare zilnica scurta:</strong> 5-10 verbe pe zi, repetate dupa 1, 3, 7 zile.</li>\n</ol>\n","exercises":[{"id":"vp-1","type":"Lückentext","difficulty":"Usor","question":"Ich warte ___ den Bus.","options":null,"correctAnswer":"auf","explanationRomanian":"Verbul 'warten' merge cu prepozitia 'auf' + Akkusativ. Astepti orientat SPRE ceva care urmeaza. Capcana frecventa: in romana zicem 'astept autobuzul', dar in germana e 'astept AUF autobuzul'."},{"id":"vp-2","type":"Lückentext","difficulty":"Usor","question":"Ich danke dir ___ das schöne Geschenk.","options":null,"correctAnswer":"für","explanationRomanian":"'danken FÜR' + Akkusativ = a multumi PENTRU ceva. La fel ca in romana ('multumesc pentru') si engleza ('thank you for')."},{"id":"vp-3","type":"Lückentext","difficulty":"Usor","question":"Ich denke oft ___ meine Familie.","options":null,"correctAnswer":"an","explanationRomanian":"'denken AN' + Akkusativ = a se gandi la. In germana NU se foloseste 'auf' aici. Truc: gandul tau este orientat 'AN' (catre) cineva."},{"id":"vp-4","type":"Lückentext","difficulty":"Mediu","question":"Sie freut sich ___ den Urlaub im August. (eveniment viitor)","options":null,"correctAnswer":"auf","explanationRomanian":"Cand bucuria e pentru ceva DIN VIITOR (vacanta care urmeaza) -> 'sich freuen AUF' + Akkusativ. Acesta e una din cele mai importante perechi A2!"},{"id":"vp-5","type":"Lückentext","difficulty":"Mediu","question":"Ich freue mich ___ das schöne Geschenk, das ich gestern bekommen habe.","options":null,"correctAnswer":"über","explanationRomanian":"Cand bucuria e pentru ceva CARE DEJA S-A INTAMPLAT (cadoul primit ieri) -> 'sich freuen ÜBER' + Akkusativ. Cuvantul 'gestern' iti spune ca e in trecut."},{"id":"vp-6","type":"Lückentext","difficulty":"Mediu","question":"Das Team besteht ___ zehn Spielern.","options":null,"correctAnswer":"aus","explanationRomanian":"'bestehen AUS' + Dativ = a fi compus DIN. Atentie: NU confunda cu 'bestehen AUF' + Dativ care inseamna 'a insista PE ceva'."},{"id":"vp-7","type":"Lückentext","difficulty":"Greu","question":"Ich beschwere mich ___ den schlechten Service. (despre ce ma plang)","options":null,"correctAnswer":"über","explanationRomanian":"'sich beschweren ÜBER' + Akk. = a se plange DE (subiectul plangerii). NOTA: 'sich beschweren BEI' + Dativ = a te plange LA cineva (persoana). Doua prepozitii diferite, doua roluri diferite."},{"id":"vp-8","type":"Lückentext","difficulty":"Greu","question":"Es geht ___ ein wichtiges Problem in unserer Firma.","options":null,"correctAnswer":"um","explanationRomanian":"'es geht UM' + Akk. = este vorba DESPRE. Expresie idiomatica fixa, foarte frecventa in conversatie. Truc: 'um' = in jurul, deci subiectul 'se invarte in jurul' acelei probleme."},{"id":"vp-9","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Hilfe","dich","um","bitte","Ich"],"correctAnswer":"Ich bitte dich um Hilfe","explanationRomanian":"Topica: Subiect (Ich) + Verb conjugat pe pozitia 2 (bitte) + obiect direct (dich) + prepozitie (um) + obiect (Hilfe). 'bitten UM' = a cere/ruga pentru ceva."},{"id":"vp-10","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele:","options":["Bus","Ich","den","warte","auf"],"correctAnswer":"Ich warte auf den Bus","explanationRomanian":"Verbul mereu pe pozitia 2: Ich (S) + warte (V) + auf (prep.) + den Bus (Akk., m.). 'warten auf' + Akkusativ."},{"id":"vp-11","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["einem","Er","arbeitet","Projekt","an","neuen"],"correctAnswer":"Er arbeitet an einem neuen Projekt","explanationRomanian":"'arbeiten AN' + Dativ. Topica: Er (S) + arbeitet (V poz.2) + an (prep.) + einem neuen Projekt (Dat. neutru cu adjectiv 'neu' declinat -en)."},{"id":"vp-12","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["zum","dir","Geburtstag","Ich","gratuliere"],"correctAnswer":"Ich gratuliere dir zum Geburtstag","explanationRomanian":"'gratulieren ZU' + Dativ. 'zum' = zu+dem (contractie). Topica: S + V + obiect Dat. (dir) + prepozitie + obiect Dat. (zum Geburtstag)."},{"id":"vp-13","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele:","options":["mich","dir","bei","Ich","für","bedanke","Hilfe","die"],"correctAnswer":"Ich bedanke mich bei dir für die Hilfe","explanationRomanian":"Doua perechi cu 'bedanken': BEI dir (la cine = persoana, Dativ) + FÜR die Hilfe (pentru ce = Akk.). Reflexiv 'mich' vine imediat dupa verbul conjugat."},{"id":"vp-14","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza cuvintele (atentie la Perfekt):","options":["gewartet","lange","Wir","Spiel","haben","auf","das"],"correctAnswer":"Wir haben lange auf das Spiel gewartet","explanationRomanian":"Perfekt: haben + ... + Partizip (gewartet) la sfarsit. 'warten auf' + Akkusativ (das Spiel). Adverbul 'lange' (mult timp) intre auxiliar si complement."},{"id":"vp-15","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza (Perfekt + verb reflexiv):","options":["sich","verliebt","Bruder","in","Mein","hat","sie"],"correctAnswer":"Mein Bruder hat sich in sie verliebt","explanationRomanian":"'sich verlieben IN' + Akkusativ. La Perfekt: hat + sich (reflexiv) + in sie (Akk.) + verliebt (Partizip la sfarsit). Pronumele 'sie' (in ea) e Akkusativ feminin singular."},{"id":"vp-16","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza (subordonata cu weil):","options":["weil","Ich","ich","müde","schlafen","gehe","bin"],"correctAnswer":"Ich gehe schlafen weil ich müde bin","explanationRomanian":"Propozitie principala (Ich gehe schlafen) + subordonata cu 'weil' unde verbul 'bin' merge la sfarsit. 'müde sein' nu are prepozitie (e adjectiv predicativ)."},{"id":"vp-17","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Ich warte für den Bus.\"","options":null,"correctAnswer":"Ich warte auf den Bus","explanationRomanian":"Greseala: 'für' in loc de 'auf'. Verbul 'warten' merge cu 'auf', NU 'für'. 'warten auf' + Akkusativ. Capcana clasica pentru romani."},{"id":"vp-18","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Scrie corect:\n\"Ich denke auf dich.\"","options":null,"correctAnswer":"Ich denke an dich","explanationRomanian":"Greseala: 'auf' in loc de 'an'. 'denken AN' + Akkusativ. Truc: gandul e orientat 'AN' (catre), nu 'AUF' (deasupra)."},{"id":"vp-19","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Wir sprechen mit das Wetter.\"","options":null,"correctAnswer":"Wir sprechen über das Wetter","explanationRomanian":"Greseala: 'mit' in loc de 'über'. Vremea e SUBIECT, nu interlocutor. 'sprechen MIT' = vorbesti CU CINEVA (persoana). 'sprechen ÜBER' = vorbesti DESPRE CEVA (subiect)."},{"id":"vp-20","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich freue mich auf das Geschenk, das ich gestern bekommen habe.\"","options":null,"correctAnswer":"Ich freue mich über das Geschenk, das ich gestern bekommen habe","explanationRomanian":"Greseala: 'auf' in loc de 'über'. Cuvantul 'gestern' arata ca e TRECUT -> 'sich freuen ÜBER' (nu 'auf' care e pentru viitor)."},{"id":"vp-21","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Scrie corect:\n\"Ich erinnere mich an meiner Schule.\"","options":null,"correctAnswer":"Ich erinnere mich an meine Schule","explanationRomanian":"Greseala in caz: 'meiner' (Dativ) in loc de 'meine' (Akkusativ). 'sich erinnern AN' cere ACUZATIV, nu Dativ. Femininul ramane neschimbat la Akk: meine Schule."},{"id":"vp-22","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Scrie corect:\n\"Sie hat mich gegen die Idee entschieden.\"","options":null,"correctAnswer":"Sie hat sich gegen die Idee entschieden","explanationRomanian":"Greseala in pronume reflexiv: 'mich' (eu) in loc de 'sich' (ea). 'sich entscheiden' e reflexiv: pers. 3 -> 'sich'. La Perfekt: sie hat sich + ... + entschieden (Partizip la sfarsit)."},{"id":"vp-23","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Scrie corect:\n\"Es handelt sich für ein wichtiges Problem.\"","options":null,"correctAnswer":"Es handelt sich um ein wichtiges Problem","explanationRomanian":"Greseala: 'für' in loc de 'um'. 'es handelt sich UM' = este vorba DESPRE. Expresie fixa, capcana frecventa pentru ca in romana zicem 'pentru'/'despre'."},{"id":"vp-24","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Scrie corect:\n\"Sie kämpft auf ihre Rechte.\"","options":null,"correctAnswer":"Sie kämpft für ihre Rechte","explanationRomanian":"Greseala: 'auf' in loc de 'für'. 'kämpfen FÜR' + Akk. = a lupta PENTRU o cauza/idee. Atentie la trio: kämpfen FÜR (cauza) / UM (a obtine) / GEGEN (impotriva)."},{"id":"vp-25","type":"Umformung","difficulty":"Usor","question":"Inlocuieste numele cu pronume:\n\"Ich denke an Maria.\"","options":null,"correctAnswer":"Ich denke an sie","explanationRomanian":"Maria (femeie singular) -> 'sie' (ea). Prepozitia 'an' ramane. Pentru OAMENI se foloseste pronumele normal dupa prepozitie (an sie/ihn/uns/euch)."},{"id":"vp-26","type":"Umformung","difficulty":"Mediu","question":"Inlocuieste obiectul cu da-cuvant (pentru lucruri):\n\"Ich erinnere mich an die Schule.\"","options":null,"correctAnswer":"Ich erinnere mich daran","explanationRomanian":"Pentru LUCRURI (nu persoane), 'an + lucru' devine 'daran' (da+r+an, cu 'r' de legatura caci 'an' incepe cu vocala). Pattern: da+(r)+prepozitie."},{"id":"vp-27","type":"Umformung","difficulty":"Mediu","question":"Adauga negatie 'nicht':\n\"Ich rechne mit Problemen.\"","options":null,"correctAnswer":"Ich rechne nicht mit Problemen","explanationRomanian":"Pentru a nega o constructie cu prepozitie, 'nicht' se pune INAINTE de prepozitie (nu inainte de obiect). 'rechnen MIT' + Dat. = a se astepta la."},{"id":"vp-28","type":"Umformung","difficulty":"Mediu","question":"Pune la trecut (Perfekt):\n\"Ich freue mich über das Geschenk.\"","options":null,"correctAnswer":"Ich habe mich über das Geschenk gefreut","explanationRomanian":"Verbele reflexive iau auxiliar 'haben'. Schema Perfekt: ich habe + reflexiv (mich) + ... + Partizip (gefreut) la sfarsit. 'sich freuen' e regulat -> gefreut."},{"id":"vp-29","type":"Umformung","difficulty":"Mediu","question":"Conjuga la pers. 3 sg.:\n\"sich freuen auf / das Wochenende / sie (ea)\"","options":null,"correctAnswer":"Sie freut sich auf das Wochenende","explanationRomanian":"'sich freuen auf' + Akk. La pers. 3 sg.: sie freut sich auf + Akk. 'das Wochenende' (n.) ramane neschimbat la Akk."},{"id":"vp-30","type":"Umformung","difficulty":"Greu","question":"Formuleaza intrebarea (cu 'wo+prep'):\n\"Ich warte auf den Bus.\"","options":null,"correctAnswer":"Worauf wartest du","explanationRomanian":"Pentru intrebari despre LUCRURI cu prepozitie, folosesti 'wo + prepozitie'. wo+auf = worauf (cu 'r' de legatura). Pattern: wo+(r)+prep + verb + subiect."},{"id":"vp-31","type":"Umformung","difficulty":"Greu","question":"Pune la trecut (Perfekt) - atentie verb neregulat:\n\"Wir sprechen mit dem Lehrer.\"","options":null,"correctAnswer":"Wir haben mit dem Lehrer gesprochen","explanationRomanian":"'sprechen' e neregulat -> Partizip 'gesprochen'. Auxiliar 'haben'. Topica: Wir haben + complement (mit dem Lehrer) + Partizip (gesprochen) la sfarsit."},{"id":"vp-32","type":"Umformung","difficulty":"Greu","question":"Inlocuieste numele cu da-cuvant:\n\"Ich denke oft an die Sommerferien.\"","options":null,"correctAnswer":"Ich denke oft daran","explanationRomanian":"'die Sommerferien' = lucru/eveniment, NU persoana -> da-cuvant 'daran' (da+r+an). Daca era persoana ('an Maria') am fi pus 'an sie'."},{"id":"vp-33","type":"Multiple Choice","difficulty":"Usor","question":"Ich freue mich ___ die Sommerferien (vacanta de vara, in viitor).","options":["auf","über","für","an"],"correctAnswer":"auf","explanationRomanian":"Pentru evenimente VIITOARE -> 'sich freuen AUF'. Capcana: 'für' (in romana zicem 'pentru') NU merge in germana - regula e clara: auf=viitor, über=trecut. 'an' si 'über' nu se folosesc pentru 'sich freuen' la viitor."},{"id":"vp-34","type":"Multiple Choice","difficulty":"Usor","question":"Wir sprechen ___ unserer Mutter. (CU mama)","options":["über","mit","von","an"],"correctAnswer":"mit","explanationRomanian":"Cand vorbim CU O PERSOANA (interlocutorul) folosim 'sprechen MIT' + Dat. Capcane: 'über' = despre subiect; 'von' = mai indirect (a mentiona); 'an' nu se foloseste niciodata cu 'sprechen'."},{"id":"vp-35","type":"Multiple Choice","difficulty":"Mediu","question":"Sie kümmert sich ___ ihre kleinen Kinder.","options":["um","für","mit","an"],"correctAnswer":"um","explanationRomanian":"'sich kümmern UM' + Akk. = a se ocupa de cineva (cu grija activa). Capcana: 'für' suna apropiat (in romana 'pentru copii') si exista 'sorgen für', dar verbul 'kümmern' cere strict 'um'."},{"id":"vp-36","type":"Multiple Choice","difficulty":"Mediu","question":"Worauf wartest du? Ich warte ___","options":["über das Wetter","auf den Bus","mit dem Wetter","an die Wahl"],"correctAnswer":"auf den Bus","explanationRomanian":"Intrebarea 'worauf' contine deja prepozitia 'auf', deci raspunsul incepe cu 'auf' + Akk. 'auf den Bus' (m. Akk: der Bus -> den Bus). Celelalte folosesc prepozitii gresite."},{"id":"vp-37","type":"Multiple Choice","difficulty":"Mediu","question":"Ich interessiere mich ___ Sport. (sport in general, ca domeniu)","options":["für","an","auf","über"],"correctAnswer":"für","explanationRomanian":"Pentru un domeniu GENERAL (sport, muzica) -> 'sich interessieren FÜR' + Akk. 'AN' se foloseste rar, doar pentru un lucru SPECIFIC ('an diesem Auto'). La A2, FÜR e mereu raspunsul corect."},{"id":"vp-38","type":"Multiple Choice","difficulty":"Greu","question":"___ wem hast du das gehört? (de la cine ai auzit asta?)","options":["Von","Mit","Um","An"],"correctAnswer":"Von","explanationRomanian":"'hören VON' + Dativ = a auzi DE LA cineva (sursa informatiei). 'wem' = forma Dativ a lui 'wer'. Combinatia: Von wem? = de la cine? (Dat.). 'mit' inseamna 'cu', 'um' = despre/in jur, 'an' nu merge cu 'hören'."},{"id":"vp-39","type":"Multiple Choice","difficulty":"Greu","question":"Welche Form ist richtig? Er ___ für seine Verspätung.","options":["entschuldigt mich","entschuldigt","entschuldigt sich","sich entschuldigt"],"correctAnswer":"entschuldigt sich","explanationRomanian":"'sich entschuldigen' este reflexiv. Pers. 3 sg: er entschuldigt sich (reflexivul 'sich'). Verbul conjugat sta pe pozitia 2, pronumele reflexiv imediat dupa verbul conjugat. 'mich' ar fi gresit pentru 'er' (mich = eu)."},{"id":"vp-40","type":"Multiple Choice","difficulty":"Greu","question":"Was bedeutet 'Es hängt von dir ab'?","options":["Atarna pe tine","Depinde de tine","Vine de la tine","Iese din tine"],"correctAnswer":"Depinde de tine","explanationRomanian":"'abhängen VON' + Dat. = a depinde de. Verb separabil: 'ab' merge la sfarsit la prezent. Sensul vine din imaginea unui tablou care 'atarna DE' un cui - daca dispare cuiul, cade tabloul."},{"id":"vp-41","type":"Lückentext","difficulty":"Usor","question":"Ich warte ___ den Bus.","options":null,"correctAnswer":"auf","explanationRomanian":"'warten auf' = a astepta. Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-42","type":"Lückentext","difficulty":"Mediu","question":"Ich freue mich ___ den Urlaub.","options":null,"correctAnswer":"auf","explanationRomanian":"'sich freuen auf' = a abia astepta (viitor). Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-43","type":"Lückentext","difficulty":"Mediu","question":"Ich hoffe ___ gutes Wetter.","options":null,"correctAnswer":"auf","explanationRomanian":"'hoffen auf' = a spera la. Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-44","type":"Lückentext","difficulty":"Usor","question":"Ich achte ___ die Autos.","options":null,"correctAnswer":"auf","explanationRomanian":"'achten auf' = a fi atent la. Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-45","type":"Lückentext","difficulty":"Mediu","question":"Ich passe ___ den Hund auf.","options":null,"correctAnswer":"auf","explanationRomanian":"'aufpassen auf' = a supraveghea. Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-46","type":"Lückentext","difficulty":"Usor","question":"Ich antworte ___ die Frage.","options":null,"correctAnswer":"auf","explanationRomanian":"'antworten auf' = a raspunde la. Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-47","type":"Lückentext","difficulty":"Mediu","question":"Ich bereite mich ___ die Pruefung vor.","options":null,"correctAnswer":"auf","explanationRomanian":"'sich vorbereiten auf' = a se pregati pentru. Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-48","type":"Lückentext","difficulty":"Mediu","question":"Ich verlasse mich ___ meinen Freund.","options":null,"correctAnswer":"auf","explanationRomanian":"'sich verlassen auf' = a se baza pe. Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-49","type":"Lückentext","difficulty":"Mediu","question":"Ich reagiere ___ die Nachricht.","options":null,"correctAnswer":"auf","explanationRomanian":"'reagieren auf' = a reactiona la. Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-50","type":"Lückentext","difficulty":"Mediu","question":"Ich verzichte ___ den Zucker.","options":null,"correctAnswer":"auf","explanationRomanian":"'verzichten auf' = a renunta la. Combinatie fixa, prepozitia 'auf' nu se schimba (auf + Akk)."},{"id":"vp-51","type":"Lückentext","difficulty":"Mediu","question":"Ich bestehe ___ drei Teilen.","options":null,"correctAnswer":"aus","explanationRomanian":"'bestehen aus' = a fi compus din. Combinatie fixa, prepozitia 'aus' nu se schimba (aus + Dat)."},{"id":"vp-52","type":"Lückentext","difficulty":"Mediu","question":"Ich stamme ___ Rumaenien.","options":null,"correctAnswer":"aus","explanationRomanian":"'stammen aus' = a proveni din. Combinatie fixa, prepozitia 'aus' nu se schimba (aus + Dat)."},{"id":"vp-53","type":"Lückentext","difficulty":"Mediu","question":"Ich helfe ___ den Hausaufgaben.","options":null,"correctAnswer":"bei","explanationRomanian":"'helfen bei' = a ajuta la. Combinatie fixa, prepozitia 'bei' nu se schimba (bei + Dat)."},{"id":"vp-54","type":"Lückentext","difficulty":"Mediu","question":"Ich bedanke mich ___ dem Lehrer.","options":null,"correctAnswer":"bei","explanationRomanian":"'sich bedanken bei' = a multumi cuiva (persoanei). Combinatie fixa, prepozitia 'bei' nu se schimba (bei + Dat)."},{"id":"vp-55","type":"Lückentext","difficulty":"Mediu","question":"Ich beschwere mich ___ dem Chef.","options":null,"correctAnswer":"bei","explanationRomanian":"'sich beschweren bei' = a se plange la (cineva). Combinatie fixa, prepozitia 'bei' nu se schimba (bei + Dat)."},{"id":"vp-56","type":"Lückentext","difficulty":"Mediu","question":"Ich entschuldige mich ___ der Mutter.","options":null,"correctAnswer":"bei","explanationRomanian":"'sich entschuldigen bei' = a-si cere scuze fata de. Combinatie fixa, prepozitia 'bei' nu se schimba (bei + Dat)."},{"id":"vp-57","type":"Multiple Choice","difficulty":"Mediu","question":"Ich freue mich ___ den Urlaub naechste Woche.","options":["auf","über","für","an"],"correctAnswer":"auf","explanationRomanian":"Eveniment VIITOR (vacanta urmatoare) -> 'sich freuen AUF'. 'über' e pentru trecut."},{"id":"vp-58","type":"Multiple Choice","difficulty":"Mediu","question":"Ich freue mich ___ deinen Brief von gestern.","options":["auf","über","für","an"],"correctAnswer":"über","explanationRomanian":"Eveniment TRECUT (scrisoare deja primita) -> 'sich freuen ÜBER'."},{"id":"vp-59","type":"Multiple Choice","difficulty":"Usor","question":"Wir sprechen ___ unserem Lehrer.","options":["mit","über","von","an"],"correctAnswer":"mit","explanationRomanian":"'sprechen MIT' = vorbim CU O PERSOANA (interlocutor) + Dativ."},{"id":"vp-60","type":"Multiple Choice","difficulty":"Usor","question":"Wir sprechen ___ die Pruefung.","options":["mit","über","von","an"],"correctAnswer":"über","explanationRomanian":"'sprechen ÜBER' = vorbim DESPRE UN SUBIECT + Akkusativ."},{"id":"vp-61","type":"Multiple Choice","difficulty":"Mediu","question":"Oma erzaehlt ___ ihrer Jugend. (amintiri personale)","options":["von","über","mit","an"],"correctAnswer":"von","explanationRomanian":"'erzaehlen VON' + Dat. = ceva personal, amintiri trăite. 'über' e pentru subiect general."},{"id":"vp-62","type":"Multiple Choice","difficulty":"Mediu","question":"Der Reporter berichtet ___ den Krieg. (subiect general)","options":["über","von","mit","an"],"correctAnswer":"über","explanationRomanian":"'berichten ÜBER' + Akk. = a raporta despre un subiect (analitic, general)."},{"id":"vp-63","type":"Multiple Choice","difficulty":"Usor","question":"Ich danke dir ___ deine Hilfe.","options":["für","bei","mit","an"],"correctAnswer":"für","explanationRomanian":"'danken FÜR' + Akk. = multumesti PENTRU lucrul primit."},{"id":"vp-64","type":"Multiple Choice","difficulty":"Mediu","question":"Ich bedanke mich ___ dir.","options":["für","bei","mit","an"],"correctAnswer":"bei","explanationRomanian":"'bedanken BEI' + Dat. = multumesti FATA DE persoana."},{"id":"vp-65","type":"Multiple Choice","difficulty":"Mediu","question":"Er kaempft ___ die Ungerechtigkeit (impotriva).","options":["für","gegen","um","mit"],"correctAnswer":"gegen","explanationRomanian":"'kaempfen GEGEN' + Akk. = a lupta impotriva."},{"id":"vp-66","type":"Multiple Choice","difficulty":"Mediu","question":"Sie kaempft ___ den ersten Platz (a obtine).","options":["für","gegen","um","mit"],"correctAnswer":"um","explanationRomanian":"'kaempfen UM' + Akk. = a lupta pentru a obtine ceva concret."},{"id":"vp-67","type":"Multiple Choice","difficulty":"Mediu","question":"Er kaempft ___ die Freiheit (cauza).","options":["für","gegen","um","mit"],"correctAnswer":"für","explanationRomanian":"'kaempfen FÜR' + Akk. = a lupta pentru o cauza/idee."},{"id":"vp-68","type":"Multiple Choice","difficulty":"Mediu","question":"Das Team besteht ___ zehn Spielern.","options":["aus","auf","mit","von"],"correctAnswer":"aus","explanationRomanian":"'bestehen AUS' + Dat. = compus DIN. Diferit de 'bestehen AUF' (a insista)."},{"id":"vp-69","type":"Multiple Choice","difficulty":"Greu","question":"Er besteht ___ seinem Recht.","options":["aus","auf","mit","von"],"correctAnswer":"auf","explanationRomanian":"'bestehen AUF' + Dat. = a insista pe ceva. Diferit de 'bestehen AUS' (compus din)."},{"id":"vp-70","type":"Multiple Choice","difficulty":"Mediu","question":"Ich sorge ___ meine Familie (am grija).","options":["für","um","mit","an"],"correctAnswer":"für","explanationRomanian":"'sorgen FÜR' + Akk. = a se ingriji activ. Diferit de 'sich sorgen UM' (a fi ingrijorat)."},{"id":"vp-71","type":"Multiple Choice","difficulty":"Greu","question":"Ich sorge mich ___ dich (sunt ingrijorat).","options":["für","um","mit","an"],"correctAnswer":"um","explanationRomanian":"'sich sorgen UM' + Akk. = a fi ingrijorat. Diferit de 'sorgen FÜR' (a se ingriji)."},{"id":"vp-72","type":"Multiple Choice","difficulty":"Mediu","question":"Sie interessiert sich ___ Sport (general).","options":["für","an","auf","über"],"correctAnswer":"für","explanationRomanian":"'sich interessieren FÜR' + Akk. = interes general (sport, muzica). 'AN' = interes specific."},{"id":"vp-73","type":"Multiple Choice","difficulty":"Mediu","question":"Wovon traeumst du? - Ich traeume ___ einem Haus.","options":["von","an","über","mit"],"correctAnswer":"von","explanationRomanian":"'traeumen VON' + Dat. Intrebarea 'wovon' contine deja 'von'."},{"id":"vp-74","type":"Multiple Choice","difficulty":"Mediu","question":"Es geht ___ ein wichtiges Problem.","options":["um","auf","über","an"],"correctAnswer":"um","explanationRomanian":"'es geht UM' = este vorba DESPRE. Expresie idiomatica fixa."},{"id":"vp-75","type":"Multiple Choice","difficulty":"Mediu","question":"Ich rechne ___ Problemen.","options":["mit","auf","an","für"],"correctAnswer":"mit","explanationRomanian":"'rechnen MIT' + Dat. = a se astepta la (literalmente 'a calcula cu')."},{"id":"vp-76","type":"Multiple Choice","difficulty":"Mediu","question":"Es haengt ___ dir ab.","options":["von","auf","an","über"],"correctAnswer":"von","explanationRomanian":"'abhaengen VON' + Dat. = a depinde de. Verb separabil ('haengt ... ab')."},{"id":"vp-77","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Bus","den","warte","Ich","auf"],"correctAnswer":"Ich warte auf den Bus","explanationRomanian":"S + V poz.2 + prep + Akk. 'warten auf' + Akk."},{"id":"vp-78","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Geschenk","danke","das","Ich","fuer","dir"],"correctAnswer":"Ich danke dir fuer das Geschenk","explanationRomanian":"S + V + Dat. (dir) + fuer + Akk. (das Geschenk)."},{"id":"vp-79","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["mich","Mutter","freue","auf","ich","meine"],"correctAnswer":"Ich freue mich auf meine Mutter","explanationRomanian":"Reflexiv 'mich' dupa verbul conjugat. 'freuen auf' + Akk."},{"id":"vp-80","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Geschichte","die","lacht","ueber","Er"],"correctAnswer":"Er lacht ueber die Geschichte","explanationRomanian":"'lachen ÜBER' + Akk. S + V + prep + Akk."},{"id":"vp-81","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["mit","Bruder","spreche","Ich","meinem"],"correctAnswer":"Ich spreche mit meinem Bruder","explanationRomanian":"'sprechen MIT' + Dat. (mit meinem Bruder)."},{"id":"vp-82","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Hilfe","bittet","Sie","um","uns"],"correctAnswer":"Sie bittet uns um Hilfe","explanationRomanian":"'bitten UM' + Akk. (Hilfe). Plus obiect direct (uns)."},{"id":"vp-83","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["aus","besteht","drei","Teilen","Buch","das"],"correctAnswer":"Das Buch besteht aus drei Teilen","explanationRomanian":"'bestehen AUS' + Dat. plural (Teilen)."},{"id":"vp-84","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Pruefung","die","auf","vor","bereiten","Wir","uns"],"correctAnswer":"Wir bereiten uns auf die Pruefung vor","explanationRomanian":"Verb separabil 'sich vorbereiten auf'. Reflexiv 'uns' + 'auf die Pruefung' (Akk.) + 'vor' la sfarsit."},{"id":"vp-85","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["Geschenk","haben","uns","wir","ueber","gefreut","das"],"correctAnswer":"Wir haben uns ueber das Geschenk gefreut","explanationRomanian":"Perfekt: haben + reflexiv + ÜBER + Akk + Partizip la sfarsit."},{"id":"vp-86","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza cuvintele intr-o propozitie corecta:","options":["sich","verliebt","Bruder","in","hat","sie","Mein"],"correctAnswer":"Mein Bruder hat sich in sie verliebt","explanationRomanian":"Perfekt: hat + sich + IN + Akk (sie) + Partizip 'verliebt' la sfarsit."},{"id":"vp-87","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Ich denke an dir.\"","options":null,"correctAnswer":"Ich denke an dich","explanationRomanian":"'denken AN' cere ACUZATIV, nu Dativ. 'dir' (Dat.) -> 'dich' (Akk.)."},{"id":"vp-88","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Ich warte fuer den Zug.\"","options":null,"correctAnswer":"Ich warte auf den Zug","explanationRomanian":"'warten AUF' (nu 'fuer'). Capcana din traducere RO 'astept pentru'."},{"id":"vp-89","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Ich freue mich auf den Brief, den ich gestern bekommen habe.\"","options":null,"correctAnswer":"Ich freue mich ueber den Brief, den ich gestern bekommen habe","explanationRomanian":"'gestern' = trecut, deci 'sich freuen ÜBER' (nu 'auf' care e pentru viitor)."},{"id":"vp-90","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Wir sprechen mit das Wetter.\"","options":null,"correctAnswer":"Wir sprechen ueber das Wetter","explanationRomanian":"Vremea = subiect, nu interlocutor. 'sprechen MIT' = cu cineva; 'sprechen ÜBER' = despre ceva."},{"id":"vp-91","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Sie bedankt sich fuer dem Lehrer.\"","options":null,"correctAnswer":"Sie bedankt sich beim Lehrer","explanationRomanian":"'bedanken BEI' + Dat. (la persoana). 'fuer' merge cu 'danken' nu 'bedanken'."},{"id":"vp-92","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Er kaempft auf seine Rechte.\"","options":null,"correctAnswer":"Er kaempft fuer seine Rechte","explanationRomanian":"'kaempfen FÜR' + Akk. = pentru o cauza. 'auf' nu merge."},{"id":"vp-93","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Ich gewoehne mich auf das Wetter.\"","options":null,"correctAnswer":"Ich gewoehne mich an das Wetter","explanationRomanian":"'sich gewoehnen AN' + Akk. (nu 'auf'). Te 'lipesti AN' noul obicei."},{"id":"vp-94","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Es geht auf Geld.\"","options":null,"correctAnswer":"Es geht um Geld","explanationRomanian":"Expresie fixa: 'es geht UM' = este vorba despre. Niciodata 'auf'."},{"id":"vp-95","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Ich erinnere mich an meiner Schule.\"","options":null,"correctAnswer":"Ich erinnere mich an meine Schule","explanationRomanian":"'sich erinnern AN' + ACUZATIV (nu Dativ). 'meiner' (Dat.) -> 'meine' (Akk.)."},{"id":"vp-96","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Sie hat sich fuer ihn verliebt.\"","options":null,"correctAnswer":"Sie hat sich in ihn verliebt","explanationRomanian":"'sich verlieben IN' + Akk. (nu 'fuer'). Intri IN starea/persoana."},{"id":"vp-97","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Das Team besteht aus zehn Spieler.\"","options":null,"correctAnswer":"Das Team besteht aus zehn Spielern","explanationRomanian":"'aus' + Dat. La plural Dat. substantivul ia '-n': Spieler -> Spielern."},{"id":"vp-98","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala in propozitie. Scrie versiunea corecta:\n\"Ich entschuldige mich an dir.\"","options":null,"correctAnswer":"Ich entschuldige mich bei dir","explanationRomanian":"'sich entschuldigen BEI' + Dat. (la persoana). Niciodata 'an'."},{"id":"vp-99","type":"Umformung","difficulty":"Usor","question":"Inlocuieste cu pronume personal:\n\"Ich denke an Maria.\"","options":null,"correctAnswer":"Ich denke an sie","explanationRomanian":"Maria = singular feminin -> 'sie'. Pentru oameni se foloseste pronumele direct dupa prepozitie."},{"id":"vp-100","type":"Umformung","difficulty":"Mediu","question":"Inlocuieste cu da-cuvant (lucru):\n\"Ich erinnere mich an die Reise.\"","options":null,"correctAnswer":"Ich erinnere mich daran","explanationRomanian":"'an + lucru' -> 'daran' (cu r de legatura caci 'an' incepe cu vocala)."},{"id":"vp-101","type":"Umformung","difficulty":"Mediu","question":"Inlocuieste cu da-cuvant:\n\"Wir warten auf den Bus.\"","options":null,"correctAnswer":"Wir warten darauf","explanationRomanian":"'auf + lucru' -> 'darauf'. Pentru lucruri se foloseste 'da+(r)+prepozitie'."},{"id":"vp-102","type":"Umformung","difficulty":"Mediu","question":"Inlocuieste cu da-cuvant:\n\"Sie spricht ueber das Wetter.\"","options":null,"correctAnswer":"Sie spricht darueber","explanationRomanian":"'ueber + lucru' -> 'darueber'. r de legatura."},{"id":"vp-103","type":"Umformung","difficulty":"Mediu","question":"Pune la trecut (Perfekt):\n\"Ich freue mich ueber den Brief.\"","options":null,"correctAnswer":"Ich habe mich ueber den Brief gefreut","explanationRomanian":"Reflexive iau 'haben'. Schema: ich habe + mich + complement + Partizip la sfarsit."},{"id":"vp-104","type":"Umformung","difficulty":"Mediu","question":"Pune la trecut (Perfekt):\n\"Wir sprechen mit dem Lehrer.\"","options":null,"correctAnswer":"Wir haben mit dem Lehrer gesprochen","explanationRomanian":"'sprechen' neregulat -> Partizip 'gesprochen'. haben + complement + Partizip la sfarsit."},{"id":"vp-105","type":"Umformung","difficulty":"Mediu","question":"Pune la trecut (Perfekt):\n\"Sie wartet auf den Bus.\"","options":null,"correctAnswer":"Sie hat auf den Bus gewartet","explanationRomanian":"'warten' regulat -> 'gewartet'. haben + ... + Partizip la sfarsit."},{"id":"vp-106","type":"Umformung","difficulty":"Mediu","question":"Pune la trecut (Perfekt):\n\"Er denkt an seine Familie.\"","options":null,"correctAnswer":"Er hat an seine Familie gedacht","explanationRomanian":"'denken' neregulat -> Partizip 'gedacht'. haben + ... + Partizip la sfarsit."},{"id":"vp-107","type":"Umformung","difficulty":"Greu","question":"Formuleaza intrebarea cu 'wo+prep':\n\"Ich warte auf den Bus.\"","options":null,"correctAnswer":"Worauf wartest du","explanationRomanian":"Pentru lucruri: wo + prep -> wo+r+auf = worauf."},{"id":"vp-108","type":"Umformung","difficulty":"Greu","question":"Formuleaza intrebarea cu 'wo+prep':\n\"Sie traeumt von Italien.\"","options":null,"correctAnswer":"Wovon traeumst du","explanationRomanian":"wo+von = wovon (fara r caci 'von' incepe cu consoana)."},{"id":"vp-109","type":"Umformung","difficulty":"Mediu","question":"Conjuga la pers. 3 sg.:\n\"sich kuemmern um / der Hund / sie (ea)\"","options":null,"correctAnswer":"Sie kuemmert sich um den Hund","explanationRomanian":"Pers. 3 sg.: sie kuemmert sich. 'um den Hund' (m. Akk.: der Hund -> den Hund)."},{"id":"vp-110","type":"Umformung","difficulty":"Usor","question":"Schimba subiectul la pers. 1 plural (wir):\n\"Er traeumt von einem Haus.\"","options":null,"correctAnswer":"Wir traeumen von einem Haus","explanationRomanian":"Wir + traeumen (terminatie -en). 'von einem Haus' (Dat. neutru) ramane neschimbat."}]},{"id":"relativsaetze","level":"B1","category":"Propozitii","title_de":"Relativsätze (der/die/das)","title_ro":"Propozitii relative","summary":"Subordonate care descriu un substantiv. Pronumele relativ se acorda cu genul (din substantiv) si cazul (din rol).","theory":"\n<h3>Ce este o propozitie relativa?</h3>\n<p>O propozitie care descrie sau aduce mai multe informatii despre un substantiv din propozitia principala. In romana = \"care\".</p>\n<p class=\"gram-example\">Der Mann, <strong>der</strong> dort steht, ist mein Bruder.<br>\n(Barbatul care sta acolo este fratele meu.)</p>\n\n<h3>Pronumele relativ</h3>\n<p>In germana, pronumele relativ se acorda dupa 2 reguli:</p>\n<ul>\n  <li><strong>GENUL si numarul</strong> = de la substantivul din propozitia principala</li>\n  <li><strong>CAZUL</strong> = depinde de rolul lui in propozitia secundara</li>\n</ul>\n\n<h3>Tabel complet (echivalent cu der/die/das)</h3>\n<table class=\"gram-table\">\n  <thead><tr><th>Caz</th><th>m.</th><th>f.</th><th>n.</th><th>pl.</th></tr></thead>\n  <tbody>\n    <tr><td>Nominativ</td><td><strong>der</strong></td><td><strong>die</strong></td><td><strong>das</strong></td><td><strong>die</strong></td></tr>\n    <tr><td>Akkusativ</td><td><strong>den</strong></td><td><strong>die</strong></td><td><strong>das</strong></td><td><strong>die</strong></td></tr>\n    <tr><td>Dativ</td><td><strong>dem</strong></td><td><strong>der</strong></td><td><strong>dem</strong></td><td><strong>denen</strong></td></tr>\n    <tr><td>Genitiv</td><td><strong>dessen</strong></td><td><strong>deren</strong></td><td><strong>dessen</strong></td><td><strong>deren</strong></td></tr>\n  </tbody>\n</table>\n<p>Aproape totul e identic cu articolul definit, cu 2 exceptii: <strong>denen</strong> (Dat. pl.) si <strong>dessen/deren</strong> (Genitiv).</p>\n\n<h3>Exemple pe cazuri</h3>\n\n<h4>Nominativ -- pronumele este SUBIECTUL secundarei</h4>\n<p class=\"gram-example\">Der Mann, <strong>der</strong> Klavier spielt, ist mein Bruder.<br>\n(Cine canta? = der Mann, deci pronumele e subiect = Nominativ.)</p>\n\n<h4>Akkusativ -- pronumele este OBIECTUL DIRECT al secundarei</h4>\n<p class=\"gram-example\">Der Mann, <strong>den</strong> ich sehe, ist mein Bruder.<br>\n(Pe cine vad? = den Mann, deci Akkusativ.)</p>\n\n<h4>Dativ -- pronumele este OBIECTUL INDIRECT</h4>\n<p class=\"gram-example\">Der Mann, <strong>dem</strong> ich helfe, ist mein Bruder.<br>\n(Cui ajut? = dem Mann, deci Dativ.)</p>\n\n<h4>Cu prepozitie</h4>\n<p>Prepozitia merge IMPREUNA cu pronumele relativ la inceputul subordonatei:</p>\n<p class=\"gram-example\">Das ist die Frau, <strong>mit der</strong> ich gestern gesprochen habe.<br>\n(Cu cine am vorbit? = mit der Frau. mit + Dativ.)</p>\n\n<h3>Verbul mereu la sfarsit</h3>\n<p>Ca in toate subordonatele, verbul conjugat al subordonatei merge la SFARSIT:</p>\n<p class=\"gram-example\">Das Buch, das ich lese, <strong>ist</strong> super. (Cartea pe care o citesc e super.)<br>\nDas Auto, <strong>das</strong> du gestern <strong>gekauft hast</strong>, ist neu.</p>\n\n<div class=\"gram-tip\">\n<strong>Strategia in 3 pasi pentru a alege pronumele:</strong><br>\n1. Care e <strong>genul si numarul</strong> substantivului in principala? (m./f./n./pl.)<br>\n2. Ce <strong>rol</strong> joaca pronumele in subordonata? (subiect / obiect direct / indirect)<br>\n3. Combina: gen + caz = pronume.\n</div>\n","exercises":[{"type":"fill","prompt":"Der Mann, ___ dort wohnt, ist Lehrer.","answer":"der","hint":"Mann = m. + e SUBIECTUL subordonatei = Nom.","explanation":"der Mann (m.) + subiect in subordonata (cine locuieste? -> der) = der."},{"type":"fill","prompt":"Die Frau, ___ ich kenne, ist Italienerin.","answer":"die","hint":"Frau = f. + obiect direct (cine?) = Akk","explanation":"die Frau (f.) + Akkusativ (pe cine cunosc?) = die."},{"type":"choice","prompt":"Das Kind, ___ ich helfe, ist krank.","options":["das","den","dem","der"],"answer":"dem","explanation":"das Kind (n.) + Dativ (cui ajut? helfen + Dat.) -> dem."},{"type":"choice","prompt":"Die Bücher, ___ auf dem Tisch liegen, sind alt.","options":["der","die","das","dem"],"answer":"die","explanation":"die Bücher (pl.) + subiect (care stau? -> die) = die (Nom. pl.)."},{"type":"fill","prompt":"Das ist der Freund, mit ___ ich gespielt habe.","answer":"dem","hint":"Freund (m.) + mit cere Dativ","explanation":"der Freund (m.) + prepozitia 'mit' (Dat.) -> mit dem."},{"type":"transform","prompt":"Combina cu propozitie relativa: Ich kenne den Mann. Der Mann arbeitet hier.","answer":"Ich kenne den Mann, der hier arbeitet.","hint":"der = m. Nom.","explanation":"der Mann + subiect in subordonata -> der. Verbul 'arbeitet' la sfarsit."},{"id":"rs-1000","type":"Lückentext","difficulty":"Mediu","question":"Der Mann, ___ dort wohnt, ist Lehrer.","options":null,"correctAnswer":"der","explanationRomanian":"Mann m. + subiect in subordonata (Nom.) -> der."},{"id":"rs-1001","type":"Lückentext","difficulty":"Mediu","question":"Die Frau, ___ ich kenne, ist Italienerin.","options":null,"correctAnswer":"die","explanationRomanian":"Frau f. + obiect direct (Akk.) -> die."},{"id":"rs-1002","type":"Lückentext","difficulty":"Greu","question":"Das Kind, ___ ich helfe, ist krank.","options":null,"correctAnswer":"dem","explanationRomanian":"Kind n. + helfen + Dativ -> dem."},{"id":"rs-1003","type":"Lückentext","difficulty":"Mediu","question":"Die Buecher, ___ auf dem Tisch liegen, sind alt.","options":null,"correctAnswer":"die","explanationRomanian":"Buecher pl. + subiect (Nom.) -> die."},{"id":"rs-1004","type":"Lückentext","difficulty":"Greu","question":"Das ist der Freund, mit ___ ich gespielt habe.","options":null,"correctAnswer":"dem","explanationRomanian":"Freund m. + mit (Dat.) -> dem."},{"id":"rs-1005","type":"Lückentext","difficulty":"Greu","question":"Die Stadt, ___ ich wohne, ist schön.","options":null,"correctAnswer":"in der","explanationRomanian":"wohnen IN + Stadt (f. Dat.) -> in der. (Sau cu 'wo': Stadt, wo ich wohne.)"},{"id":"rs-1006","type":"Lückentext","difficulty":"Greu","question":"Ich kenne den Mann, ___ Auto rot ist. (al carui)","options":null,"correctAnswer":"dessen","explanationRomanian":"Genitiv masculin/neutru: dessen (al carui)."},{"id":"rs-1007","type":"Lückentext","difficulty":"Greu","question":"Die Frau, ___ Hund weggelaufen ist, weint.","options":null,"correctAnswer":"deren","explanationRomanian":"Genitiv feminin/plural: deren (al/a carei)."},{"id":"rs-1008","type":"Multiple Choice","difficulty":"Mediu","question":"Pronumele relativ se acorda dupa:","options":["genul din subordonata","genul si numarul din PRINCIPALA, cazul din SUBORDONATA","primul cuvant","ultimul verb"],"correctAnswer":"genul si numarul din PRINCIPALA, cazul din SUBORDONATA","explanationRomanian":"Genul/numarul vine de la substantivul din principala. Cazul depinde de rolul lui in subordonata."},{"id":"rs-1009","type":"Multiple Choice","difficulty":"Mediu","question":"'Cartea pe care o citesc' =","options":["Das Buch, das ich lese","Das Buch, der ich lese","Das Buch, dem ich lese","Das Buch, die ich lese"],"correctAnswer":"Das Buch, das ich lese","explanationRomanian":"das Buch (n.) + Akk in subordonata (lesen + Akk) -> das."},{"id":"rs-1010","type":"Multiple Choice","difficulty":"Greu","question":"'Femeia cu care vorbesc' =","options":["Die Frau, mit die ich spreche","Die Frau, mit der ich spreche","Die Frau, mit den ich spreche","Die Frau, die ich spreche mit"],"correctAnswer":"Die Frau, mit der ich spreche","explanationRomanian":"die Frau (f.) + mit (Dat.) -> mit der."},{"id":"rs-1011","type":"Multiple Choice","difficulty":"Usor","question":"In subordonata relativa, verbul:","options":["pe poz. 1","pe poz. 2","la sfarsit","imediat dupa pronumele relativ"],"correctAnswer":"la sfarsit","explanationRomanian":"Ca in toate subordonatele, verbul conjugat la SFARSIT."},{"id":"rs-1012","type":"Multiple Choice","difficulty":"Greu","question":"Forma relativa de Dativ plural:","options":["der","die","den","denen"],"correctAnswer":"denen","explanationRomanian":"Dativ plural: denen (forma speciala, diferita de articol 'den')."},{"id":"rs-1013","type":"Multiple Choice","difficulty":"Greu","question":"Genitiv (al carui/carei) m./n.:","options":["der","des","dessen","dem"],"correctAnswer":"dessen","explanationRomanian":"dessen pentru m./n. la Genitiv."},{"id":"rs-1014","type":"Multiple Choice","difficulty":"Mediu","question":"Care e CORECT?","options":["Der Mann, der arbeitet hier","Der Mann, der hier arbeitet","Der Mann hier, der arbeitet","Der Mann der hier arbeitet"],"correctAnswer":"Der Mann, der hier arbeitet","explanationRomanian":"Subordonata cu virgula. V (arbeitet) la sfarsit."},{"id":"rs-1015","type":"Multiple Choice","difficulty":"Mediu","question":"'Tara unde locuiesc' (folosind 'wo') =","options":["Das Land, wo ich wohne","Das Land, das ich wohne","Das Land, in das ich wohne","Das Land, in dem wohne ich"],"correctAnswer":"Das Land, wo ich wohne","explanationRomanian":"Pentru locuri se poate folosi 'wo' in loc de 'in dem' / 'in der'."},{"id":"rs-1016","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["der","Mann,","Der","ist","wohnt,","Lehrer","dort"],"correctAnswer":"Der Mann, der dort wohnt, ist Lehrer","explanationRomanian":"Subordonata: der + S + V (wohnt) la sfarsit. Apoi principala continua."},{"id":"rs-1017","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["kenne,","die","Italienerin","Die","Frau,","ist","ich"],"correctAnswer":"Die Frau, die ich kenne, ist Italienerin","explanationRomanian":"die (Akk f.) + S + V (kenne) la sfarsit."},{"id":"rs-1018","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["das","Das","Buch,","ich","lese,","ist","interessant"],"correctAnswer":"Das Buch, das ich lese, ist interessant","explanationRomanian":"lesen + Akk -> das (n. Akk)."},{"id":"rs-1019","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["mit","der","Mann,","Der","spreche,","ich","ist","alt"],"correctAnswer":"Der Mann, mit dem ich spreche, ist alt","explanationRomanian":"mit + Dat. -> dem (m. Dat)."},{"id":"rs-1020","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["in","wohne,","der","Die","Stadt,","ich","ist","schön"],"correctAnswer":"Die Stadt, in der ich wohne, ist schön","explanationRomanian":"wohnen IN + Dat. f. -> in der."},{"id":"rs-1021","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["liegen,","die","Bücher,","Tisch","auf","dem","Die","alt","sind"],"correctAnswer":"Die Bücher, die auf dem Tisch liegen, sind alt","explanationRomanian":"die (pl. Nom.) + complement + V (liegen) la sfarsit."},{"id":"rs-1022","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Der Mann, der arbeitet hier, ist Lehrer.\"","options":null,"correctAnswer":"Der Mann, der hier arbeitet, ist Lehrer","explanationRomanian":"V (arbeitet) la SFARSITUL subordonatei."},{"id":"rs-1023","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Die Frau, der ich kenne, ist nett.\"","options":null,"correctAnswer":"Die Frau, die ich kenne, ist nett","explanationRomanian":"die Frau (f.) + Akk -> die (nu der, care e f. Dat. sau m. Nom)."},{"id":"rs-1024","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Das Kind, das ich helfe, ist krank.\"","options":null,"correctAnswer":"Das Kind, dem ich helfe, ist krank","explanationRomanian":"helfen + Dat -> dem (n. Dat.). 'das' ar fi Nom./Akk."},{"id":"rs-1025","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Die Bücher, der auf dem Tisch liegen, sind alt.\"","options":null,"correctAnswer":"Die Bücher, die auf dem Tisch liegen, sind alt","explanationRomanian":"Plural Nom -> die (nu der)."},{"id":"rs-1026","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Der Mann, mit den ich spreche, ist alt.\"","options":null,"correctAnswer":"Der Mann, mit dem ich spreche, ist alt","explanationRomanian":"mit + Dat. -> dem (nu den, care e Akk pl.)."},{"id":"rs-1027","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Das ist der Mann, dessen seinem Auto rot ist.\"","options":null,"correctAnswer":"Das ist der Mann, dessen Auto rot ist","explanationRomanian":"Cu 'dessen' nu mai e nevoie de articol/posesiv ('seinem'). dessen Auto = al carui auto."},{"id":"rs-1028","type":"Umformung","difficulty":"Mediu","question":"Combina cu prop. relativa:\n\"Ich kenne den Mann. Der Mann arbeitet hier.\"","options":null,"correctAnswer":"Ich kenne den Mann, der hier arbeitet","explanationRomanian":"der (m. Nom in subordonata) + V (arbeitet) la sfarsit."},{"id":"rs-1029","type":"Umformung","difficulty":"Mediu","question":"Combina:\n\"Das ist die Frau. Ich kenne die Frau.\"","options":null,"correctAnswer":"Das ist die Frau, die ich kenne","explanationRomanian":"die (f. Akk) + S + V la sfarsit."},{"id":"rs-1030","type":"Umformung","difficulty":"Greu","question":"Combina:\n\"Das ist das Kind. Ich helfe dem Kind.\"","options":null,"correctAnswer":"Das ist das Kind, dem ich helfe","explanationRomanian":"helfen + Dat -> dem (n. Dat)."},{"id":"rs-1031","type":"Umformung","difficulty":"Mediu","question":"Combina:\n\"Das sind die Bücher. Die Bücher liegen auf dem Tisch.\"","options":null,"correctAnswer":"Das sind die Bücher, die auf dem Tisch liegen","explanationRomanian":"die (pl. Nom in subordonata) + complement + V."},{"id":"rs-1032","type":"Umformung","difficulty":"Greu","question":"Combina:\n\"Das ist der Mann. Ich spreche mit dem Mann.\"","options":null,"correctAnswer":"Das ist der Mann, mit dem ich spreche","explanationRomanian":"mit + Dat -> mit dem. Prepozitia merge cu pronumele la inceputul subordonatei."},{"id":"rs-1033","type":"Umformung","difficulty":"Mediu","question":"Combina cu 'wo':\n\"Das ist die Stadt. Ich wohne in der Stadt.\"","options":null,"correctAnswer":"Das ist die Stadt, wo ich wohne","explanationRomanian":"wo = adverb relativ pentru loc (alternativa la 'in der')."}]},{"id":"konjunktiv-2","level":"B1","category":"Verbe","title_de":"Konjunktiv 2 (Conditional)","title_ro":"Conditional / Optativ","summary":"Pentru situatii ireale, dorinte si politete: 'as merge', 'mi-as dori', 'ai putea'.","theory":"\n<h3>Cand folosim Konjunktiv 2?</h3>\n<ol>\n  <li><strong>Dorinte ireale:</strong> \"Wenn ich reich <strong>wäre</strong>, ...\" (Daca as fi bogat...)</li>\n  <li><strong>Politete:</strong> \"<strong>Könnten</strong> Sie mir helfen?\" (Ati putea sa ma ajutati?)</li>\n  <li><strong>Sfaturi:</strong> \"Du <strong>solltest</strong> mehr schlafen.\" (Ar trebui sa dormi mai mult.)</li>\n  <li><strong>Conditii ireale:</strong> \"Wenn ich Zeit <strong>hätte</strong>, würde ich ...\" (Daca as avea timp, as...)</li>\n</ol>\n\n<h3>Cele 2 forme: würde + Infinitiv vs forma proprie</h3>\n<p>In germana moderna sunt 2 cai de a forma Konjunktiv 2:</p>\n\n<h4>Forma 1: würde + infinitiv (cea mai folosita)</h4>\n<p>Functioneaza pentru aproape orice verb. Ca \"would\" in engleza:</p>\n<table class=\"gram-table\">\n  <tbody>\n    <tr><td>ich würde gehen</td><td>as merge</td></tr>\n    <tr><td>du würdest gehen</td><td>ai merge</td></tr>\n    <tr><td>er würde gehen</td><td>el ar merge</td></tr>\n    <tr><td>wir würden gehen</td><td>am merge</td></tr>\n    <tr><td>ihr würdet gehen</td><td>ati merge</td></tr>\n    <tr><td>sie würden gehen</td><td>ei ar merge</td></tr>\n  </tbody>\n</table>\n<p>Pattern: <strong>würd-</strong> + terminatii ca la prezent + infinitiv la sfarsit.</p>\n\n<h4>Forma 2: forma proprie (pentru cateva verbe importante)</h4>\n<p>Pentru sein, haben, modale si cateva alte verbe se folosesc forme proprii:</p>\n<table class=\"gram-table\">\n  <thead><tr><th>Infinitiv</th><th>Konjunktiv 2 (ich)</th><th>Sens</th></tr></thead>\n  <tbody>\n    <tr><td>sein</td><td><strong>wäre</strong></td><td>as fi</td></tr>\n    <tr><td>haben</td><td><strong>hätte</strong></td><td>as avea</td></tr>\n    <tr><td>können</td><td><strong>könnte</strong></td><td>as putea</td></tr>\n    <tr><td>müssen</td><td><strong>müsste</strong></td><td>ar trebui</td></tr>\n    <tr><td>sollen</td><td><strong>sollte</strong></td><td>ar trebui (sfat)</td></tr>\n    <tr><td>dürfen</td><td><strong>dürfte</strong></td><td>as avea voie</td></tr>\n    <tr><td>wollen</td><td><strong>wollte</strong></td><td>as vrea</td></tr>\n    <tr><td>mögen</td><td><strong>möchte</strong></td><td>as dori</td></tr>\n  </tbody>\n</table>\n\n<h3>Conjugare wäre si hätte</h3>\n<table class=\"gram-table\">\n  <thead><tr><th></th><th>sein -> wäre</th><th>haben -> hätte</th></tr></thead>\n  <tbody>\n    <tr><td>ich</td><td>wäre</td><td>hätte</td></tr>\n    <tr><td>du</td><td>wärst</td><td>hättest</td></tr>\n    <tr><td>er/sie/es</td><td>wäre</td><td>hätte</td></tr>\n    <tr><td>wir</td><td>wären</td><td>hätten</td></tr>\n    <tr><td>ihr</td><td>wärt</td><td>hättet</td></tr>\n    <tr><td>sie</td><td>wären</td><td>hätten</td></tr>\n  </tbody>\n</table>\n\n<h3>Constructia ireala 'wenn ... wäre/hätte, würde ...'</h3>\n<p class=\"gram-example\"><strong>Wenn</strong> ich Zeit <strong>hätte</strong>, <strong>würde</strong> ich nach Rom <strong>fahren</strong>.<br>\n(Daca as avea timp, as merge la Roma.)</p>\n\n<p class=\"gram-example\"><strong>Wenn</strong> ich reicher <strong>wäre</strong>, <strong>würde</strong> ich ein Haus <strong>kaufen</strong>.<br>\n(Daca as fi mai bogat, as cumpara o casa.)</p>\n\n<div class=\"gram-tip\">\n<strong>Sfat:</strong> in propozitia \"wenn\", folosesti hätte/wäre/könnte... In propozitia principala folosesti würde + infinitiv (mai usor). Asa eviti formele ciudate ca \"ginge\" sau \"läse\".\n</div>\n","exercises":[{"type":"fill","prompt":"Wenn ich Zeit ___, würde ich kommen. (a avea, ich - Konj. 2)","answer":"hätte","hint":"haben -> ?","explanation":"haben -> hätte (as avea)."},{"type":"fill","prompt":"Ich ___ gerne ein Glas Wasser. (a-mi dori - politicos)","answer":"möchte","hint":"Konj. 2 de la mögen","explanation":"möchte = as dori (forma standard pentru politete)."},{"type":"choice","prompt":"___ Sie mir bitte helfen?","options":["Können","Konnten","Könnten","Konnten"],"answer":"Könnten","explanation":"Politete -> Konjunktiv 2: Könnten (ati putea)."},{"type":"transform","prompt":"Konjunktiv 2: Ich gehe ins Kino.","answer":"Ich würde ins Kino gehen.","hint":"würde + infinitiv","explanation":"Konj. 2 cu würde: ich würde + infinitiv la sfarsit."},{"type":"fill","prompt":"Wenn ich reich ___, würde ich nicht arbeiten. (a fi)","answer":"wäre","hint":"sein -> ?","explanation":"sein -> wäre. (Daca as fi bogat...)"},{"type":"transform","prompt":"Sfat politicos: Du musst mehr schlafen.","answer":"Du solltest mehr schlafen.","hint":"Konj. 2 al lui sollen","explanation":"Pentru sfat -> sollte. Du solltest = ar trebui sa."},{"id":"k2-800","type":"Lückentext","difficulty":"Mediu","question":"Wenn ich Zeit ___, würde ich kommen. (haben, ich Konj 2)","options":null,"correctAnswer":"hätte","explanationRomanian":"haben Konj 2: ich hätte."},{"id":"k2-801","type":"Lückentext","difficulty":"Usor","question":"Ich ___ gerne ein Glas Wasser, bitte. (politicos: as dori)","options":null,"correctAnswer":"möchte","explanationRomanian":"möchte = forma politicoasa (Konj 2 de la mögen)."},{"id":"k2-802","type":"Lückentext","difficulty":"Mediu","question":"Wenn ich reich ___, würde ich nicht arbeiten. (sein, ich Konj 2)","options":null,"correctAnswer":"wäre","explanationRomanian":"sein Konj 2: ich wäre."},{"id":"k2-803","type":"Lückentext","difficulty":"Mediu","question":"___ Sie mir bitte helfen? (politicos)","options":null,"correctAnswer":"Könnten","explanationRomanian":"können Konj 2: könnten = ati putea (politete formala)."},{"id":"k2-804","type":"Lückentext","difficulty":"Mediu","question":"Du ___ mehr Sport machen. (sfat: ar trebui)","options":null,"correctAnswer":"solltest","explanationRomanian":"sollen Konj 2: ich/er sollte, du solltest."},{"id":"k2-805","type":"Lückentext","difficulty":"Mediu","question":"Wir ___ nach Italien fahren, wenn wir Zeit hätten.","options":null,"correctAnswer":"würden","explanationRomanian":"Konj 2 cu 'würde': wir würden + infinitiv."},{"id":"k2-806","type":"Lückentext","difficulty":"Mediu","question":"Ich ___ gerne mit dir sprechen.","options":null,"correctAnswer":"würde","explanationRomanian":"Politete: würde + infinitiv. ich würde = as."},{"id":"k2-807","type":"Lückentext","difficulty":"Greu","question":"Wenn er hier ___, würde er uns helfen. (sein, er Konj 2)","options":null,"correctAnswer":"wäre","explanationRomanian":"sein Konj 2: er wäre. Wenn + Konj 2 + ..., würde + inf."},{"id":"k2-808","type":"Multiple Choice","difficulty":"Usor","question":"Care e Konj 2 de la 'haben' (ich)?","options":["habe","hatte","hätte","hätten"],"correctAnswer":"hätte","explanationRomanian":"haben -> hätte (cu umlaut)."},{"id":"k2-809","type":"Multiple Choice","difficulty":"Usor","question":"Care e Konj 2 de la 'sein' (ich)?","options":["bin","war","wäre","sei"],"correctAnswer":"wäre","explanationRomanian":"sein -> wäre (cu umlaut)."},{"id":"k2-810","type":"Multiple Choice","difficulty":"Mediu","question":"'as merge' (gehen) =","options":["ich gehe","ich ging","ich würde gehen","ich gehte"],"correctAnswer":"ich würde gehen","explanationRomanian":"Konj 2 cu 'würde + infinitiv'. Forma proprie 'ginge' rar folosita."},{"id":"k2-811","type":"Multiple Choice","difficulty":"Mediu","question":"'ar trebui sa dormi mai mult' =","options":["Du musst mehr schlafen","Du sollst mehr schlafen","Du solltest mehr schlafen","Du würdest mehr schlafen"],"correctAnswer":"Du solltest mehr schlafen","explanationRomanian":"Sfat = sollten (Konj 2 de la sollen)."},{"id":"k2-812","type":"Multiple Choice","difficulty":"Mediu","question":"Care e cea mai politicoasa cerere?","options":["Gib mir Wasser!","Geben Sie mir Wasser.","Könnten Sie mir Wasser geben?","Sie geben mir Wasser?"],"correctAnswer":"Könnten Sie mir Wasser geben?","explanationRomanian":"Konj 2 (könnten) = cea mai politicoasa forma."},{"id":"k2-813","type":"Multiple Choice","difficulty":"Mediu","question":"In propozitia 'wenn', folosim:","options":["würde","Konj 2 forma proprie (hätte/wäre/könnte)","indicativ","Praeteritum"],"correctAnswer":"Konj 2 forma proprie (hätte/wäre/könnte)","explanationRomanian":"wenn + hätte/wäre/könnte. Würde se foloseste in principala."},{"id":"k2-814","type":"Multiple Choice","difficulty":"Usor","question":"Forma 'möchte' inseamna:","options":["place","as dori","vreau","trebuie"],"correctAnswer":"as dori","explanationRomanian":"möchte = Konj 2 de la mögen, folosit pentru 'as dori' politicos."},{"id":"k2-815","type":"Multiple Choice","difficulty":"Greu","question":"'Daca as fi bogat, as cumpara o casa' =","options":["Wenn ich reich war, kaufte ich ein Haus","Wenn ich reich wäre, würde ich ein Haus kaufen","Ich bin reich und kaufe ein Haus","Wenn ich reich bin, ich kaufe ein Haus"],"correctAnswer":"Wenn ich reich wäre, würde ich ein Haus kaufen","explanationRomanian":"Conditie ireala: wenn + wäre, würde + inf in principala."},{"id":"k2-816","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["hätte","Wenn","ich","Zeit",","],"correctAnswer":"Wenn ich Zeit hätte ,","explanationRomanian":"Subordonata cu wenn: V (hätte) la sfarsit."},{"id":"k2-817","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["würde","ich","kommen","gerne"],"correctAnswer":"Ich würde gerne kommen","explanationRomanian":"S + würde + adv + INFINITIV la sfarsit."},{"id":"k2-818","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["möchte","Glas","ein","Ich","Wasser"],"correctAnswer":"Ich möchte ein Glas Wasser","explanationRomanian":"möchte ca verb principal."},{"id":"k2-819","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["könnten","Sie","mir","helfen","?"],"correctAnswer":"Könnten Sie mir helfen","explanationRomanian":"Politete: könnten + S + Dat + INFINITIV."},{"id":"k2-820","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["solltest","mehr","Du","schlafen"],"correctAnswer":"Du solltest mehr schlafen","explanationRomanian":"Sfat: sollten Konj 2 + INFINITIV la sfarsit."},{"id":"k2-821","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["wären","Wenn","wir","reicher",",","würden","wir","ein","Haus","kaufen"],"correctAnswer":"Wenn wir reicher wären, würden wir ein Haus kaufen","explanationRomanian":"Plural: wären (sein Konj 2 pl.). Subordonata + principala cu inversiune."},{"id":"k2-822","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Wenn ich reich bin, würde ich nicht arbeiten.\"","options":null,"correctAnswer":"Wenn ich reich wäre, würde ich nicht arbeiten","explanationRomanian":"Conditie ireala: wenn + Konj 2 (wäre), nu indicativ (bin)."},{"id":"k2-823","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Ich würde gerne sprechen mit dir.\"","options":null,"correctAnswer":"Ich würde gerne mit dir sprechen","explanationRomanian":"INFINITIV (sprechen) la SFARSITUL absolut. Complement (mit dir) inainte."},{"id":"k2-824","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Corect:\n\"Ich will einen Kaffee, bitte.\"","options":null,"correctAnswer":"Ich möchte einen Kaffee, bitte","explanationRomanian":"Politete: möchte (nu will, care suna brutal)."},{"id":"k2-825","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Wenn ich Zeit habe, würde ich kommen.\"","options":null,"correctAnswer":"Wenn ich Zeit hätte, würde ich kommen","explanationRomanian":"Conditie ireala: wenn + hätte (nu habe = indicativ)."},{"id":"k2-826","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Du musstest mehr schlafen.\"","options":null,"correctAnswer":"Du solltest mehr schlafen","explanationRomanian":"Sfat = solltest (Konj 2). 'musstest' (Praet. de la muessen) = trebuia (afirmatie despre trecut)."},{"id":"k2-827","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Könnten Sie mir bitte zu helfen?\"","options":null,"correctAnswer":"Könnten Sie mir bitte helfen","explanationRomanian":"Cu modal: INFINITIV intreg (helfen), nu 'zu helfen' (asta e cu alte verbe)."},{"id":"k2-828","type":"Umformung","difficulty":"Usor","question":"Pune la Konj 2 (politicos):\n\"Ich will Wasser.\"","options":null,"correctAnswer":"Ich möchte Wasser","explanationRomanian":"wollen -> möchte pentru politete."},{"id":"k2-829","type":"Umformung","difficulty":"Mediu","question":"Pune la Konj 2:\n\"Können Sie mir helfen?\"","options":null,"correctAnswer":"Könnten Sie mir helfen","explanationRomanian":"können -> könnten (politete maxima)."},{"id":"k2-830","type":"Umformung","difficulty":"Mediu","question":"Pune la Konj 2 (a as):\n\"Ich gehe ins Kino.\"","options":null,"correctAnswer":"Ich würde ins Kino gehen","explanationRomanian":"Konj 2 cu würde + infinitiv."},{"id":"k2-831","type":"Umformung","difficulty":"Mediu","question":"Pune la Konj 2:\n\"Ich habe ein Auto.\"","options":null,"correctAnswer":"Ich hätte ein Auto","explanationRomanian":"haben -> hätte (forma proprie)."},{"id":"k2-832","type":"Umformung","difficulty":"Mediu","question":"Pune la sfat (Konj 2 sollen):\n\"Du musst weniger essen.\"","options":null,"correctAnswer":"Du solltest weniger essen","explanationRomanian":"muessen (obligatie) -> sollten (sfat blând)."},{"id":"k2-833","type":"Umformung","difficulty":"Greu","question":"Construieste o conditie ireala:\n\"Ich habe Zeit. Ich komme zu dir.\"","options":null,"correctAnswer":"Wenn ich Zeit hätte, würde ich zu dir kommen","explanationRomanian":"wenn + hätte + virgula + würde + complement + INFINITIV (kommen)."}]},{"id":"passiv","level":"B1","category":"Verbe","title_de":"Passiv (werden + Partizip II)","title_ro":"Diateza pasiva","summary":"Pentru a sublinia ACTIUNEA, nu cine o face. werden conjugat + Partizip II la sfarsit.","theory":"\n<h3>Activ vs Pasiv -- ce schimba</h3>\n<p>La <strong>activ</strong> -- subiectul face actiunea: \"Der Mann <strong>kauft</strong> das Auto.\"<br>\nLa <strong>pasiv</strong> -- subiectul primeste actiunea: \"Das Auto <strong>wird</strong> (vom Mann) <strong>gekauft</strong>.\"</p>\n\n<p>Pasivul focalizeaza pe rezultat sau actiune, nu pe persoana. Foarte comun in stiri, instructiuni, proceduri.</p>\n\n<h3>Formula la prezent</h3>\n<p class=\"gram-example\"><strong>Subiect + werden (poz. 2) + ... + Partizip II (la sfarsit)</strong></p>\n\n<table class=\"gram-table\">\n  <thead><tr><th>Persoana</th><th>werden</th></tr></thead>\n  <tbody>\n    <tr><td>ich</td><td>werde</td></tr>\n    <tr><td>du</td><td>wirst</td></tr>\n    <tr><td>er/sie/es</td><td>wird</td></tr>\n    <tr><td>wir</td><td>werden</td></tr>\n    <tr><td>ihr</td><td>werdet</td></tr>\n    <tr><td>sie</td><td>werden</td></tr>\n  </tbody>\n</table>\n\n<h3>Exemple</h3>\n<ul>\n  <li>\"Das Buch <strong>wird</strong> heute <strong>gelesen</strong>.\" (Cartea e citita azi.)</li>\n  <li>\"Hier <strong>werden</strong> Brötchen <strong>gebacken</strong>.\" (Aici se coc cornuri.)</li>\n  <li>\"Das Haus <strong>wurde</strong> 2020 <strong>gebaut</strong>.\" (Casa a fost construita in 2020. -- Präteritum)</li>\n</ul>\n\n<h3>Pasiv la Präteritum (cu wurde)</h3>\n<p>wurde + Partizip II</p>\n<ul>\n  <li>\"Das Telefon <strong>wurde</strong> <strong>erfunden</strong>.\" (Telefonul a fost inventat.)</li>\n</ul>\n\n<h3>Pasiv la Perfekt (cu sein + Partizip II + worden)</h3>\n<p>worden = Partizip de la werden, fara 'ge-' in fata. Atentie: NU 'geworden' (acela e altceva).</p>\n<ul>\n  <li>\"Das Buch <strong>ist</strong> gestern <strong>geschrieben worden</strong>.\" (Cartea a fost scrisa ieri.)</li>\n</ul>\n\n<h3>Cum transform Activ -> Pasiv</h3>\n<ol>\n  <li>Obiectul direct (Akk.) la activ devine subiect (Nom.) la pasiv.</li>\n  <li>Verbul activ devine \"werden + Partizip II\".</li>\n  <li>Subiectul activ devine optional, cu \"von + Dativ\" sau dispare.</li>\n</ol>\n\n<p class=\"gram-example\">Activ: <em>Der Lehrer (Subj.) korrigiert <strong>den Test</strong> (Akk.).</em><br>\nPasiv: <em><strong>Der Test</strong> (Subj.) wird (vom Lehrer) korrigiert.</em></p>\n\n<h3>Pasiv cu modal</h3>\n<p>Modal + Infinitiv pasiv (Partizip + werden)</p>\n<ul>\n  <li>\"Das Auto <strong>muss</strong> <strong>repariert werden</strong>.\" (Masina trebuie reparata.)</li>\n  <li>\"Das Buch <strong>kann</strong> hier <strong>gekauft werden</strong>.\" (Cartea poate fi cumparata aici.)</li>\n</ul>\n\n<div class=\"gram-tip\">\n<strong>Atentie:</strong> doar verbele tranzitive (cu obiect direct/Akk) pot forma pasiv. Verbe ca \"schlafen\", \"gehen\" nu au pasiv personal.\n</div>\n","exercises":[{"type":"transform","prompt":"Activ -> Pasiv: Der Mann kauft das Auto.","answer":"Das Auto wird (vom Mann) gekauft.","hint":"Akk -> Nom + werden + Partizip","explanation":"das Auto trece la subiect, verbul devine 'wird gekauft'."},{"type":"fill","prompt":"Hier ___ Pizza gemacht. (a se face - prezent)","answer":"wird","hint":"es/das + werden","explanation":"Pizza (singular) -> wird gemacht."},{"type":"choice","prompt":"Das Haus ___ 1990 gebaut. (a fi construit - trecut)","options":["wird","wurde","wurden","ist"],"answer":"wurde","explanation":"Pasiv la Präteritum: wurde + Partizip. das Haus -> wurde gebaut."},{"type":"transform","prompt":"Activ -> Pasiv (prezent): Sie schreibt einen Brief.","answer":"Ein Brief wird (von ihr) geschrieben.","hint":"obiect Akk -> subiect","explanation":"einen Brief -> ein Brief la Nominativ. wird + geschrieben."},{"type":"fill","prompt":"Das Auto muss ___ ___. (sa fie reparat - reparieren)","answer":"repariert werden","hint":"Partizip + werden","explanation":"Pasiv cu modal: muss + repariert werden (Partizip + werden infinitiv)."},{"type":"choice","prompt":"Die Briefe ___ heute geschickt. (sunt trimise)","options":["wird","werden","wurden","ist"],"answer":"werden","explanation":"die Briefe (plural) -> werden geschickt."},{"id":"pa-900","type":"Lückentext","difficulty":"Usor","question":"Hier ___ Pizza gemacht. (prezent pasiv)","options":null,"correctAnswer":"wird","explanationRomanian":"Pasiv prezent: wird + Partizip."},{"id":"pa-901","type":"Lückentext","difficulty":"Mediu","question":"Das Haus ___ 1990 gebaut. (Praet pasiv)","options":null,"correctAnswer":"wurde","explanationRomanian":"Pasiv Praet: wurde + Partizip."},{"id":"pa-902","type":"Lückentext","difficulty":"Mediu","question":"Die Briefe ___ heute geschickt. (prezent pasiv pl.)","options":null,"correctAnswer":"werden","explanationRomanian":"Pasiv prezent pl: werden + Partizip."},{"id":"pa-903","type":"Lückentext","difficulty":"Greu","question":"Das Auto muss ___ ___ . (a fi reparat = repariert)","options":null,"correctAnswer":"repariert werden","explanationRomanian":"Pasiv cu modal: muss + Partizip + werden infinitiv."},{"id":"pa-904","type":"Lückentext","difficulty":"Greu","question":"Das Buch ___ gestern ___ ___ . (a fi citit, Perfekt)","options":null,"correctAnswer":"ist gelesen worden","explanationRomanian":"Pasiv Perfekt: sein + Partizip + worden (NU geworden)."},{"id":"pa-905","type":"Lückentext","difficulty":"Mediu","question":"Die Tür ___ jeden Morgen geöffnet.","options":null,"correctAnswer":"wird","explanationRomanian":"Pasiv prezent sg.: wird (die Tür e singular f.)."},{"id":"pa-906","type":"Lückentext","difficulty":"Mediu","question":"Wo ___ die Kinder unterrichtet?","options":null,"correctAnswer":"werden","explanationRomanian":"Pasiv plural: werden (die Kinder pl.)."},{"id":"pa-907","type":"Lückentext","difficulty":"Mediu","question":"Der Kuchen ___ gestern gebacken.","options":null,"correctAnswer":"wurde","explanationRomanian":"Pasiv Praet: wurde (der Kuchen sg.)."},{"id":"pa-908","type":"Multiple Choice","difficulty":"Usor","question":"Pasivul se formeaza cu:","options":["sein + Partizip","haben + Partizip","werden + Partizip","wurden + Partizip"],"correctAnswer":"werden + Partizip","explanationRomanian":"Diateza pasiva: werden conjugat + Partizip II."},{"id":"pa-909","type":"Multiple Choice","difficulty":"Mediu","question":"Pasiv prezent: 'Cartea este citita' =","options":["Das Buch ist gelesen","Das Buch wird gelesen","Das Buch hat gelesen","Das Buch wurde gelesen"],"correctAnswer":"Das Buch wird gelesen","explanationRomanian":"Pasiv prezent: wird + Partizip."},{"id":"pa-910","type":"Multiple Choice","difficulty":"Greu","question":"Cum se zice 'Casa a fost construita' (Perfekt pasiv)?","options":["Das Haus ist gebaut","Das Haus wurde gebaut","Das Haus ist gebaut worden","Das Haus hat gebaut"],"correctAnswer":"Das Haus ist gebaut worden","explanationRomanian":"Pasiv Perfekt: sein + Partizip + WORDEN (nu geworden)."},{"id":"pa-911","type":"Multiple Choice","difficulty":"Greu","question":"Cum se zice 'Masina trebuie reparata' (modal pasiv)?","options":["Das Auto muss reparieren","Das Auto wird reparieren","Das Auto muss repariert werden","Das Auto muss werden repariert"],"correctAnswer":"Das Auto muss repariert werden","explanationRomanian":"Modal + Partizip + werden infinitiv."},{"id":"pa-912","type":"Multiple Choice","difficulty":"Mediu","question":"Persoana care face actiunea, in pasiv, se exprima cu:","options":["nichts","von + Dativ","fuer + Akk","mit + Dat"],"correctAnswer":"von + Dativ","explanationRomanian":"Agentul pasiv: 'vom Mann gekauft' (von + Dativ)."},{"id":"pa-913","type":"Multiple Choice","difficulty":"Usor","question":"Care propozitie e in DIATEZA PASIVA?","options":["Ich kaufe ein Auto","Das Auto wird gekauft","Das Auto ist neu","Ich habe gekauft"],"correctAnswer":"Das Auto wird gekauft","explanationRomanian":"Pasiv = werden + Partizip."},{"id":"pa-914","type":"Multiple Choice","difficulty":"Mediu","question":"Doar verbele ___ formeaza pasiv:","options":["regulate","tranzitive (cu obiect direct)","reflexive","neregulate"],"correctAnswer":"tranzitive (cu obiect direct)","explanationRomanian":"Verbe ca 'gehen', 'schlafen' nu au pasiv personal (sunt intranzitive)."},{"id":"pa-915","type":"Multiple Choice","difficulty":"Usor","question":"Forma corecta a 'werden' la pers. 3 sg.:","options":["wirde","wirdt","wird","werden"],"correctAnswer":"wird","explanationRomanian":"wird pentru pers. 3 sg."},{"id":"pa-916","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["wird","Brot","gebacken","Hier"],"correctAnswer":"Hier wird Brot gebacken","explanationRomanian":"Inversiune: adv + V + S + Partizip."},{"id":"pa-917","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["wurde","Haus","1990","Das","gebaut"],"correctAnswer":"Das Haus wurde 1990 gebaut","explanationRomanian":"S + V + adv + Partizip."},{"id":"pa-918","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["werden","geschickt","Die","Briefe"],"correctAnswer":"Die Briefe werden geschickt","explanationRomanian":"Plural: werden + Partizip."},{"id":"pa-919","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["muss","repariert","werden","Das","Auto"],"correctAnswer":"Das Auto muss repariert werden","explanationRomanian":"Modal pasiv: S + Modal + Partizip + werden inf."},{"id":"pa-920","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["worden","ist","Das","gelesen","Buch"],"correctAnswer":"Das Buch ist gelesen worden","explanationRomanian":"Perfekt pasiv: ist + Partizip + worden."},{"id":"pa-921","type":"Satzbau","difficulty":"Greu","question":"Ordoneaza:","options":["wird","Pizza","gemacht","vom","Italiener"],"correctAnswer":"Pizza wird vom Italiener gemacht","explanationRomanian":"Cu agent: von + Dat. (vom = von dem)."},{"id":"pa-922","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Das Buch ist gelesen.\"","options":null,"correctAnswer":"Das Buch wird gelesen","explanationRomanian":"Pasiv prezent = wird + Partizip, NU sein + Partizip (asta e Zustandspassiv = stare)."},{"id":"pa-923","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Das Auto muss reparieren.\"","options":null,"correctAnswer":"Das Auto muss repariert werden","explanationRomanian":"Pasiv cu modal: Partizip + werden infinitiv. 'reparieren' e activ."},{"id":"pa-924","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Das Haus ist 1990 gebaut.\"","options":null,"correctAnswer":"Das Haus wurde 1990 gebaut","explanationRomanian":"Trecut pasiv: wurde (Praet pasiv) sau 'ist gebaut worden' (Perfekt pasiv)."},{"id":"pa-925","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Das Buch ist gestern geschrieben geworden.\"","options":null,"correctAnswer":"Das Buch ist gestern geschrieben worden","explanationRomanian":"Perfekt pasiv: WORDEN (nu geworden, care e altceva)."},{"id":"pa-926","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Die Briefe wird geschickt.\"","options":null,"correctAnswer":"Die Briefe werden geschickt","explanationRomanian":"Pluralul Briefe -> werden (nu wird)."},{"id":"pa-927","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Das Auto wird vom Mann gekauft worden.\"","options":null,"correctAnswer":"Das Auto ist vom Mann gekauft worden","explanationRomanian":"Pasiv Perfekt: SEIN auxiliar (ist), nu 'wird' (asta e prezent + worden = forma incorecta)."},{"id":"pa-928","type":"Umformung","difficulty":"Mediu","question":"Activ -> Pasiv:\n\"Der Mann kauft das Auto.\"","options":null,"correctAnswer":"Das Auto wird vom Mann gekauft","explanationRomanian":"Akk -> Nom (das Auto). werden + Partizip. Agent: vom Mann."},{"id":"pa-929","type":"Umformung","difficulty":"Mediu","question":"Activ -> Pasiv:\n\"Sie schreibt einen Brief.\"","options":null,"correctAnswer":"Ein Brief wird von ihr geschrieben","explanationRomanian":"einen Brief (Akk) -> ein Brief (Nom). wird + geschrieben."},{"id":"pa-930","type":"Umformung","difficulty":"Mediu","question":"Pune la Praet pasiv:\n\"Das Brot wird gebacken.\"","options":null,"correctAnswer":"Das Brot wurde gebacken","explanationRomanian":"wird -> wurde la Praet."},{"id":"pa-931","type":"Umformung","difficulty":"Greu","question":"Adauga modal 'muessen':\n\"Das Auto wird repariert.\"","options":null,"correctAnswer":"Das Auto muss repariert werden","explanationRomanian":"Modal + Partizip + werden inf."},{"id":"pa-932","type":"Umformung","difficulty":"Greu","question":"Pune la Perfekt pasiv:\n\"Das Buch wird geschrieben.\"","options":null,"correctAnswer":"Das Buch ist geschrieben worden","explanationRomanian":"wird -> ist (sein + worden = Perfekt pasiv). Partizip 'geschrieben' inainte."},{"id":"pa-933","type":"Umformung","difficulty":"Mediu","question":"Pasiv -> Activ:\n\"Das Auto wird vom Mann repariert.\"","options":null,"correctAnswer":"Der Mann repariert das Auto","explanationRomanian":"Subiect = agentul (vom Mann -> der Mann). Akk = das Auto."}]},{"id":"praeteritum","level":"B1","category":"Verbe","title_de":"Präteritum (Imperfekt)","title_ro":"Imperfectul (timpul trecut scris)","summary":"Trecut folosit in scris (carti, presa). In vorbire se foloseste mai ales pentru sein, haben, modale.","theory":"\n<h3>Cand folosim Präteritum?</h3>\n<p>In contrast cu Perfekt (folosit in vorbire), Präteritum apare:</p>\n<ul>\n  <li>In <strong>scris</strong>: carti, articole, povesti, cv-uri.</li>\n  <li>In <strong>vorbire</strong>: pentru <em>sein, haben, es gab, modalele</em> (acolo unde Perfekt suna ciudat).</li>\n</ul>\n<p>\"Ich war in Berlin\" e mai natural decat \"Ich bin in Berlin gewesen\".</p>\n\n<h3>Verbe regulate -- adauga -te</h3>\n<p>Pattern: radacina + <strong>-te</strong> + terminatie</p>\n<table class=\"gram-table\">\n  <thead><tr><th></th><th>spielen</th><th>arbeiten</th></tr></thead>\n  <tbody>\n    <tr><td>ich</td><td>spiel<strong>te</strong></td><td>arbeit<strong>ete</strong></td></tr>\n    <tr><td>du</td><td>spiel<strong>test</strong></td><td>arbeit<strong>etest</strong></td></tr>\n    <tr><td>er/sie/es</td><td>spiel<strong>te</strong></td><td>arbeit<strong>ete</strong></td></tr>\n    <tr><td>wir</td><td>spiel<strong>ten</strong></td><td>arbeit<strong>eten</strong></td></tr>\n    <tr><td>ihr</td><td>spiel<strong>tet</strong></td><td>arbeit<strong>etet</strong></td></tr>\n    <tr><td>sie</td><td>spiel<strong>ten</strong></td><td>arbeit<strong>eten</strong></td></tr>\n  </tbody>\n</table>\n<p>Atentie: dupa -t, -d, -m, -n se baga \"e\" in plus (arbeit-e-te).</p>\n\n<h3>Verbe neregulate -- schimba radacina</h3>\n<p>Tre' invatat tabelul. Cele mai uzuale:</p>\n<table class=\"gram-table\">\n  <thead><tr><th>Infinitiv</th><th>Pratium (ich/er)</th><th>Sens</th></tr></thead>\n  <tbody>\n    <tr><td>sein</td><td><strong>war</strong></td><td>am fost</td></tr>\n    <tr><td>haben</td><td><strong>hatte</strong></td><td>aveam</td></tr>\n    <tr><td>gehen</td><td><strong>ging</strong></td><td>am mers</td></tr>\n    <tr><td>kommen</td><td><strong>kam</strong></td><td>am venit</td></tr>\n    <tr><td>fahren</td><td><strong>fuhr</strong></td><td>am calatorit</td></tr>\n    <tr><td>sehen</td><td><strong>sah</strong></td><td>am vazut</td></tr>\n    <tr><td>essen</td><td><strong>ass</strong></td><td>am mancat</td></tr>\n    <tr><td>trinken</td><td><strong>trank</strong></td><td>am baut</td></tr>\n    <tr><td>lesen</td><td><strong>las</strong></td><td>am citit</td></tr>\n    <tr><td>sprechen</td><td><strong>sprach</strong></td><td>am vorbit</td></tr>\n    <tr><td>schreiben</td><td><strong>schrieb</strong></td><td>am scris</td></tr>\n    <tr><td>finden</td><td><strong>fand</strong></td><td>am gasit</td></tr>\n    <tr><td>geben</td><td><strong>gab</strong></td><td>am dat</td></tr>\n    <tr><td>nehmen</td><td><strong>nahm</strong></td><td>am luat</td></tr>\n  </tbody>\n</table>\n\n<h3>Conjugare neregulat: sein</h3>\n<table class=\"gram-table\">\n  <tbody>\n    <tr><td>ich war</td><td>du warst</td><td>er war</td></tr>\n    <tr><td>wir waren</td><td>ihr wart</td><td>sie waren</td></tr>\n  </tbody>\n</table>\n\n<h3>Modal verbs la Präteritum</h3>\n<p>Pierd umlautul si adauga -te:</p>\n<ul>\n  <li>können -> <strong>konnte</strong> (puteam)</li>\n  <li>müssen -> <strong>musste</strong> (trebuia)</li>\n  <li>wollen -> <strong>wollte</strong> (voiam)</li>\n  <li>sollen -> <strong>sollte</strong> (ar fi trebuit)</li>\n  <li>dürfen -> <strong>durfte</strong> (aveam voie)</li>\n  <li>mögen -> <strong>mochte</strong> (imi placea)</li>\n</ul>\n\n<div class=\"gram-tip\">\n<strong>Sfat:</strong> persoana 1 si 3 singular sunt mereu identice la Präteritum (ich war = er war, ich ging = er ging). Asta e o trasatura unica a acestui timp.\n</div>\n","exercises":[{"type":"transform","prompt":"Präteritum: Ich bin in Berlin.","answer":"Ich war in Berlin.","hint":"sein -> war","explanation":"ich bin -> ich war (eu eram/am fost)."},{"type":"transform","prompt":"Präteritum: Wir gehen ins Kino.","answer":"Wir gingen ins Kino.","hint":"gehen -> ging","explanation":"gehen e neregulat -> ging. wir gingen."},{"type":"fill","prompt":"Als Kind ___ ich oft Fussball. (spielen, ich)","answer":"spielte","hint":"regulat: -te","explanation":"spielen e regulat. ich spielte = jucam."},{"type":"fill","prompt":"Er ___ gestern krank. (sein, er)","answer":"war","hint":"sein -> ?","explanation":"sein e neregulat. ich/er war."},{"type":"choice","prompt":"Ich ___ nicht kommen. (nu puteam)","options":["kann","konnte","kannte","können"],"answer":"konnte","explanation":"können la Präteritum -> konnte (pierde umlaut, adauga -te)."},{"type":"transform","prompt":"Präteritum: Sie hat ein Auto.","answer":"Sie hatte ein Auto.","hint":"haben -> hatte","explanation":"haben -> hatte (avea)."},{"id":"pr-700","type":"Lückentext","difficulty":"Usor","question":"Als Kind ___ ich oft Fussball. (spielen, ich)","options":null,"correctAnswer":"spielte","explanationRomanian":"spielen regulat -> spielte."},{"id":"pr-701","type":"Lückentext","difficulty":"Usor","question":"Er ___ gestern krank. (sein, er)","options":null,"correctAnswer":"war","explanationRomanian":"sein neregulat: war."},{"id":"pr-702","type":"Lückentext","difficulty":"Mediu","question":"Wir ___ ins Kino. (gehen, wir)","options":null,"correctAnswer":"gingen","explanationRomanian":"gehen neregulat: ging. Plural: gingen."},{"id":"pr-703","type":"Lückentext","difficulty":"Mediu","question":"Sie ___ ein Buch. (lesen, sie ea)","options":null,"correctAnswer":"las","explanationRomanian":"lesen neregulat: las."},{"id":"pr-704","type":"Lückentext","difficulty":"Mediu","question":"Du ___ in Italien. (sein, du)","options":null,"correctAnswer":"warst","explanationRomanian":"sein: du warst."},{"id":"pr-705","type":"Lückentext","difficulty":"Usor","question":"Wir ___ keine Zeit. (haben, wir)","options":null,"correctAnswer":"hatten","explanationRomanian":"haben: hatten."},{"id":"pr-706","type":"Lückentext","difficulty":"Mediu","question":"Sie ___ einen Brief. (schreiben, sie ea)","options":null,"correctAnswer":"schrieb","explanationRomanian":"schreiben neregulat: schrieb."},{"id":"pr-707","type":"Lückentext","difficulty":"Mediu","question":"Ich ___ gestern arbeiten. (muessen, ich)","options":null,"correctAnswer":"musste","explanationRomanian":"muessen pierde umlaut + te: musste."},{"id":"pr-708","type":"Multiple Choice","difficulty":"Mediu","question":"Cand folosesti Praeteritum vs Perfekt?","options":["Praeteritum doar in scris, Perfekt in vorbire","Sunt identice","Praeteritum doar pentru sein/haben","Perfekt doar in scris"],"correctAnswer":"Praeteritum doar in scris, Perfekt in vorbire","explanationRomanian":"Praeteritum: scris (carti, articole). Vorbire: Perfekt (mai ales). Exceptii vorbire: sein, haben, modale."},{"id":"pr-709","type":"Multiple Choice","difficulty":"Usor","question":"Forma de Praeteritum a 'sein' la pers. 1 sg.:","options":["bin","war","ware","wäre"],"correctAnswer":"war","explanationRomanian":"ich war = eu eram/am fost."},{"id":"pr-710","type":"Multiple Choice","difficulty":"Usor","question":"Forma de Praeteritum a 'haben' la pers. 1 sg.:","options":["habe","hat","hatte","hätte"],"correctAnswer":"hatte","explanationRomanian":"ich hatte = aveam/avusesem."},{"id":"pr-711","type":"Multiple Choice","difficulty":"Mediu","question":"La Praeteritum, pers. 1 si pers. 3 sg. sunt:","options":["diferite","identice","in opozitie","rar identice"],"correctAnswer":"identice","explanationRomanian":"Trasatura unica: 'ich war = er war', 'ich ging = er ging'."},{"id":"pr-712","type":"Multiple Choice","difficulty":"Mediu","question":"Verb regulat 'arbeiten' la Praet. (ich):","options":["arbeite","arbeitete","arbete","gearbeitet"],"correctAnswer":"arbeitete","explanationRomanian":"Dupa -t/-d se baga 'e' suplimentar: arbeit-ete."},{"id":"pr-713","type":"Multiple Choice","difficulty":"Mediu","question":"Verb modal 'koennen' la Praet. (ich):","options":["kann","konnte","konnt","konntte"],"correctAnswer":"konnte","explanationRomanian":"Modal pierde umlaut + adauga -te: konnte (puteam)."},{"id":"pr-714","type":"Multiple Choice","difficulty":"Mediu","question":"Praet. de la 'fahren':","options":["fahrte","fuhr","gefahren","fahrt"],"correctAnswer":"fuhr","explanationRomanian":"fahren neregulat: fuhr (vocala schimbata)."},{"id":"pr-715","type":"Multiple Choice","difficulty":"Mediu","question":"'A baut' la Praet. (ich):","options":["trinkte","trink","trank","getrunken"],"correctAnswer":"trank","explanationRomanian":"trinken: trank (a baut)."},{"id":"pr-716","type":"Satzbau","difficulty":"Usor","question":"Ordoneaza:","options":["war","in","Ich","Berlin"],"correctAnswer":"Ich war in Berlin","explanationRomanian":"S + Praet. + complement."},{"id":"pr-717","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["wir","ins","gingen","Kino"],"correctAnswer":"Wir gingen ins Kino","explanationRomanian":"wir gingen = mergeam."},{"id":"pr-718","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["hatte","kein","Sie","Geld"],"correctAnswer":"Sie hatte kein Geld","explanationRomanian":"haben: hatte (avea)."},{"id":"pr-719","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["las","ein","Sie","Buch"],"correctAnswer":"Sie las ein Buch","explanationRomanian":"lesen: las."},{"id":"pr-720","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["spielte","ich","Als","Kind","Fussball"],"correctAnswer":"Als Kind spielte ich Fussball","explanationRomanian":"Inversiune cu adverb 'als Kind' la inceput."},{"id":"pr-721","type":"Satzbau","difficulty":"Mediu","question":"Ordoneaza:","options":["er","Damals","in","wohnte","Berlin"],"correctAnswer":"Damals wohnte er in Berlin","explanationRomanian":"Inversiune dupa adverb temporal: adv + V + S + complement."},{"id":"pr-722","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Ich war 25 Jahre alt, als ich studierte in Berlin.\"","options":null,"correctAnswer":"Ich war 25 Jahre alt, als ich in Berlin studierte","explanationRomanian":"In subordonata cu 'als' verbul (studierte) merge la sfarsit."},{"id":"pr-723","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Er konnt nicht kommen.\"","options":null,"correctAnswer":"Er konnte nicht kommen","explanationRomanian":"können Praet pers. 3: konnte (cu -te)."},{"id":"pr-724","type":"Fehlerkorrektur","difficulty":"Mediu","question":"Greseala. Corect:\n\"Wir gingten ins Kino.\"","options":null,"correctAnswer":"Wir gingen ins Kino","explanationRomanian":"gehen neregulat: ging. Plural: gingen (nu 'gingten')."},{"id":"pr-725","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Ich gefahren nach Italien.\"","options":null,"correctAnswer":"Ich fuhr nach Italien","explanationRomanian":"Asta amesteca Perfekt cu Praet. Praeteritum: ich fuhr."},{"id":"pr-726","type":"Fehlerkorrektur","difficulty":"Usor","question":"Greseala. Corect:\n\"Sie hate ein Buch.\"","options":null,"correctAnswer":"Sie hatte ein Buch","explanationRomanian":"haben Praet: hatte (cu doi 't')."},{"id":"pr-727","type":"Fehlerkorrektur","difficulty":"Greu","question":"Greseala. Corect:\n\"Ich war Lehrerin, als ich war jung.\"","options":null,"correctAnswer":"Ich war Lehrerin, als ich jung war","explanationRomanian":"als + V (war) la sfarsit, nu repetat de doua ori (a doua ori la sfarsit)."},{"id":"pr-728","type":"Umformung","difficulty":"Usor","question":"Pune la Praeteritum:\n\"Ich bin in Berlin.\"","options":null,"correctAnswer":"Ich war in Berlin","explanationRomanian":"bin -> war."},{"id":"pr-729","type":"Umformung","difficulty":"Usor","question":"Pune la Praeteritum:\n\"Wir haben Hunger.\"","options":null,"correctAnswer":"Wir hatten Hunger","explanationRomanian":"haben -> hatten."},{"id":"pr-730","type":"Umformung","difficulty":"Mediu","question":"Pune la Praeteritum:\n\"Sie geht ins Kino.\"","options":null,"correctAnswer":"Sie ging ins Kino","explanationRomanian":"gehen -> ging."},{"id":"pr-731","type":"Umformung","difficulty":"Mediu","question":"Pune la Praeteritum:\n\"Ich kann nicht kommen.\"","options":null,"correctAnswer":"Ich konnte nicht kommen","explanationRomanian":"können -> konnte. Modal pe poz. 2 + infinitiv la sfarsit."},{"id":"pr-732","type":"Umformung","difficulty":"Mediu","question":"Pune la Praeteritum:\n\"Er liest ein Buch.\"","options":null,"correctAnswer":"Er las ein Buch","explanationRomanian":"lesen -> las."},{"id":"pr-733","type":"Umformung","difficulty":"Mediu","question":"Pune la Praeteritum:\n\"Maria fährt nach Italien.\"","options":null,"correctAnswer":"Maria fuhr nach Italien","explanationRomanian":"fahren -> fuhr."}]}];
